        const x = dist.sample(rng);
        try testing.expect(x >= 0.0);
        sum += x;
    }

    const sample_mean = sum / @as(f64, @floatFromInt(n));
    // Mean = α/β = 0.5/2.0 = 0.25
    try expectApproxEqAbs(0.25, sample_mean, 0.03);
}

