    try expectApproxEqRel(0.3, cat.pmf(1), 1e-10);
    try expectApproxEqRel(0.2, cat.pmf(2), 1e-10);
}

test "Categorical: pmf out-of-bounds returns 0.0" {
    const allocator = testing.allocator;
    const weights = [_]f64{ 0.5, 0.3, 0.2 };
