        defer dist.deinit();

        const counts = [_]u64{ 5, 5 };
        _ = dist.pmf(&counts);
        _ = dist.logpmf(&counts);
        _ = dist.mean(0);
        _ = dist.variance(0);
        _ = dist.covariance(0, 1);

