}

test "DiscreteUniform: entropy increases with range" {
    const dist1 = try DiscreteUniform(f64).init(0, 5); // n = 6
    const dist2 = try DiscreteUniform(f64).init(0, 10); // n = 11
    try testing.expect(dist1.entropy() < dist2.entropy());
