}

test "DiscreteUniform: large range" {
    const dist = try DiscreteUniform(f64).init(0, 1_000_000);
    const expected: f64 = 1.0 / 1_000_001.0;

    try expectApproxEqRel(expected, dist.pmf(0), 1e-12);
