    const dist1 = try HalfNormal(f64).init(0.5);
    try expectEqual(@as(f64, 0.5), dist1.sigma);

    const dist2 = try HalfNormal(f64).init(2.0);
    try expectEqual(@as(f64, 2.0), dist2.sigma);

