}

test "MaxwellBoltzmann: validate fails for NaN a" {
    const dist = MaxwellBoltzmann(f64){ .a = math.nan(f64) };
    try testing.expectError(error.InvalidParameter, dist.validate());
}

test "MaxwellBoltzmann: validate fails for Inf a" {
