test "LogLogistic: sample empirical mean ≈ theoretical mean" {
    var prng = std.Random.DefaultPrng.init(12345);
    const rng = prng.random();
    const dist = try LogLogistic(f64).init(1.0, 3.0);
    const n: usize = 50000;
