    var i: usize = 0;
    while (i < n) : (i += 1) {
        sum += dist.sample(rng);
    }
    const empirical_mean = sum / @as(f64, @floatFromInt(n));
    try testing.expectApproxEqRel(dist.mean(), empirical_mean, 0.02);
}

