    const result = Levy(f64).init(math.inf(f64), 1.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Levy: init with infinite c returns error" {
    const result = Levy(f64).init(0.0, math.inf(f64));
    try testing.expectError(error.InvalidParameter, result);
}

