test "Lomax: init succeeds with valid params" {
    const dist = try Lomax(f64).init(1.0, 1.0);
    try testing.expectEqual(@as(f64, 1.0), dist.lambda);
    try testing.expectEqual(@as(f64, 1.0), dist.kappa);
}

