test "GeneralizedLogistic: quantile-cdf parity" {
    const dist = try GeneralizedLogistic(f64).init(0.0, 1.0, 2.0);
    const ps = [_]f64{ 0.1, 0.3, 0.7, 0.9 };
    for (ps) |p| {
