// --- sample tests ---

test "GeneralizedLogistic: sample is finite" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try GeneralizedLogistic(f64).init(0.0, 1.0, 1.0);
    for (0..100) |_| {
        const sample = dist.sample(rng.random());
        try testing.expect(math.isFinite(sample));
    }
}

test "GeneralizedLogistic: sample mean approaches theoretical" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try GeneralizedLogistic(f64).init(0.0, 1.0, 1.0);
    var sum: f64 = 0.0;
    const n = 10000;
    for (0..n) |_| {
        sum += dist.sample(rng.random());
    }
    const sample_mean = sum / @as(f64, @floatFromInt(n));
    const theoretical_mean = dist.mean();
    try testing.expectApproxEqAbs(theoretical_mean, sample_mean, 0.05);
}

test "GeneralizedLogistic: sample is non-deterministic" {
    var rng1 = std.Random.DefaultPrng.init(42);
    var rng2 = std.Random.DefaultPrng.init(43);
    const dist = try GeneralizedLogistic(f64).init(0.0, 1.0, 1.0);
    const s1 = dist.sample(rng1.random());
    const s2 = dist.sample(rng2.random());
    try testing.expect(s1 != s2);
}

// --- f32 variant tests ---

test "GeneralizedLogistic: f32 init succeeds" {
    const dist = try GeneralizedLogistic(f32).init(0.0, 1.0, 1.0);
    try testing.expectEqual(@as(f32, 0.0), dist.mu);
}

test "GeneralizedLogistic: f32 pdf is positive" {
    const dist = try GeneralizedLogistic(f32).init(0.0, 1.0, 1.0);
    try testing.expect(dist.pdf(0.0) > 0.0);
}

test "GeneralizedLogistic: f32 cdf in [0,1]" {
    const dist = try GeneralizedLogistic(f32).init(0.0, 1.0, 1.0);
    const cdf_val = dist.cdf(0.0);
    try testing.expect(cdf_val >= 0.0 and cdf_val <= 1.0);
}

test "GeneralizedLogistic: f32 mean is finite" {
    const dist = try GeneralizedLogistic(f32).init(0.0, 1.0, 2.0);
    try testing.expect(math.isFinite(dist.mean()));
}

// ============================================================================
// Slash Distribution
// ============================================================================
pub fn Slash(comptime T: type) type {
    return struct {
        mu: T,
        sigma: T,

        const Self = @This();

        // Standard normal PDF: φ(z) = exp(-z²/2) / √(2π)
        fn phi(z: T) T {
            return @exp(-z * z / 2.0) / @sqrt(2.0 * math.pi);
        }

        // Standard normal CDF: Φ(z) = 0.5*(1 + erf(z/√2))
        fn Phi(z: T) T {
            return 0.5 * (1.0 + erf(z / @sqrt(@as(T, 2.0))));
        }

        // phi(0) constant: 1/√(2π)
        fn phi0val() T {
            return 1.0 / @sqrt(@as(T, 2.0) * math.pi);
        }

        // --- Lifecycle ---

        /// Initialize Slash distribution with location mu and scale sigma > 0.
        /// Time: O(1) | Space: O(1)
        pub fn init(mu: T, sigma: T) DistributionError!Self {
            if (!math.isFinite(mu)) return error.InvalidParameter;
            if (sigma <= 0.0 or !math.isFinite(sigma)) return error.InvalidParameter;
            return Self{ .mu = mu, .sigma = sigma };
        }

        /// Assert all parameters are valid.
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (!math.isFinite(self.mu)) return error.InvalidParameter;
            if (self.sigma <= 0.0 or !math.isFinite(self.sigma)) return error.InvalidParameter;
        }

        // --- PDF / LogPDF ---

        /// Log-probability density function.
        /// For z=(x-μ)/σ ≠ 0: log φ₀ + log(-expm1(-z²/2)) - log σ - 2 log|z|
        /// For z=0: log φ₀ - log 2 - log σ
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            const z = (x - self.mu) / self.sigma;
            const p0 = phi0val();
            if (z == 0.0) {
                return @log(p0) - @log(@as(T, 2.0)) - @log(self.sigma);
            }
            // (1 - exp(-z²/2)) = -expm1(-z²/2), numerically stable for small z
            const one_minus_exp = -math.expm1(-z * z / 2.0);
            if (one_minus_exp <= 0.0) return -math.inf(T);
            return @log(p0) + @log(one_minus_exp) - @log(self.sigma) - 2.0 * @log(@abs(z));
        }

        /// Probability density function.
        /// f(x) = φ₀·(1−exp(−z²/2))/(σ·z²) for z≠0; φ₀/(2σ) for z=0
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            return @exp(self.logpdf(x));
        }

        // --- CDF / SF ---

        /// Cumulative distribution function.
        /// F(x) = Φ(z) + φ₀·expm1(−z²/2)/z for z≠0; 0.5 for z=0
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            const z = (x - self.mu) / self.sigma;
            const p0 = phi0val();
            if (z == 0.0) return 0.5;
            return Phi(z) + p0 * math.expm1(-z * z / 2.0) / z;
        }

        /// Survival function: 1 - CDF(x).
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            return 1.0 - self.cdf(x);
        }

        // --- Quantile ---

        /// Quantile (inverse CDF) via bisection search.
        /// Returns NaN for p outside [0,1]; -∞ for p=0; +∞ for p=1.
        /// Time: O(100) | Space: O(1)
        pub fn quantile(self: Self, p: T) T {
            if (math.isNan(p) or p < 0.0 or p > 1.0) return math.nan(T);
            if (p == 0.0) return -math.inf(T);
            if (p == 1.0) return math.inf(T);
            var lo: T = self.mu - 100.0 * self.sigma;
            var hi: T = self.mu + 100.0 * self.sigma;
            var iter: usize = 0;
            while (iter < 100) : (iter += 1) {
                const mid = (lo + hi) / 2.0;
                if (hi - lo < 1e-12 * (1.0 + @abs(mid))) break;
                if (self.cdf(mid) < p) {
                    lo = mid;
                } else {
                    hi = mid;
                }
            }
            return (lo + hi) / 2.0;
        }

        // --- Moments ---

        /// Mean: undefined (NaN) — no finite moments exist.
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            _ = self;
            return math.nan(T);
        }

        /// Variance: undefined (NaN) — no finite moments exist.
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            _ = self;
            return math.nan(T);
        }

        /// Mode: μ (PDF maximum is at x = μ).
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            return self.mu;
        }

        // --- Entropy ---

        /// Entropy via 2000-panel composite Simpson's rule over [−40σ, 40σ].
        /// H(Slash(μ,σ)) = H_std + log(σ)
        /// Time: O(2000) | Space: O(1)
        pub fn entropy(self: Self) T {
            const n_panels: usize = 2000;
            const x_lo: T = -40.0;
            const x_hi: T = 40.0;
            const h_val: T = (x_hi - x_lo) / @as(T, @floatFromInt(n_panels));
            const p0 = phi0val();
            // Compute standard slash entropy (sigma=1, mu=0)
            var sum: T = 0.0;
            var i: usize = 0;
            while (i <= n_panels) : (i += 1) {
                const z = x_lo + @as(T, @floatFromInt(i)) * h_val;
                // f_std(z) and -log(f_std(z))
                const lp: T = blk: {
                    if (z == 0.0) break :blk @log(p0) - @log(@as(T, 2.0));
                    const one_minus_exp = -math.expm1(-z * z / 2.0);
                    if (one_minus_exp <= 0.0) break :blk -math.inf(T);
                    break :blk @log(p0) + @log(one_minus_exp) - 2.0 * @log(@abs(z));
                };
                const f_std: T = @exp(lp);
                // -f * log(f) contribution (0 when f=0)
                const contrib: T = if (f_std <= 0.0 or !math.isFinite(lp)) 0.0 else -f_std * lp;
                const w: T = if (i == 0 or i == n_panels) 1.0 else if (i % 2 == 1) 4.0 else 2.0;
                sum += w * contrib;
            }
            const h_std = sum * h_val / 3.0;
            return h_std + @log(self.sigma);
        }

        // --- Sampling ---

        /// Sample via Z/U where Z~N(0,1) (Box-Muller) and U~Uniform(0,1).
        /// Time: O(1) | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            // Box-Muller for Z ~ N(0,1)
            const rand1 = @max(rng.float(T), math.floatEps(T));
            const rand2 = rng.float(T);
            const z_normal = @sqrt(-2.0 * @log(rand1)) * @cos(2.0 * math.pi * rand2);
            // U ~ Uniform(0,1), avoid 0
            const u = @max(rng.float(T), math.floatEps(T));
            return self.mu + self.sigma * z_normal / u;
        }
    };
}

// ============================================================================
// Slash(μ, σ) Distribution Tests
// ============================================================================
//
// Slash(μ, σ): μ (location, real), σ > 0 (scale)
// Support: (-∞, +∞); defined as μ + σ·Z/U, Z~N(0,1), U~Uniform(0,1)
// Heavy-tailed (heavier than Cauchy); NO finite moments
//

// --- init tests ---

test "Slash: init with mu=0, sigma=1" {
    const dist = try Slash(f64).init(0.0, 1.0);
    try testing.expectEqual(@as(f64, 0.0), dist.mu);
    try testing.expectEqual(@as(f64, 1.0), dist.sigma);
}

test "Slash: init with mu=2, sigma=3" {
    const dist = try Slash(f64).init(2.0, 3.0);
    try testing.expectEqual(@as(f64, 2.0), dist.mu);
    try testing.expectEqual(@as(f64, 3.0), dist.sigma);
}

test "Slash: init with mu=-1, sigma=0.5" {
    const dist = try Slash(f64).init(-1.0, 0.5);
    try testing.expectEqual(@as(f64, -1.0), dist.mu);
    try testing.expectEqual(@as(f64, 0.5), dist.sigma);
}

test "Slash: init fails when sigma=0" {
    const result = Slash(f64).init(0.0, 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Slash: init fails when sigma is negative" {
    const result = Slash(f64).init(0.0, -1.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Slash: init fails when sigma is infinite" {
    const result = Slash(f64).init(0.0, math.inf(f64));
    try testing.expectError(error.InvalidParameter, result);
}

test "Slash: init fails when mu is NaN" {
    const result = Slash(f64).init(math.nan(f64), 1.0);
    try testing.expectError(error.InvalidParameter, result);
}

// --- pdf tests ---

test "Slash: pdf at mode (x=mu) for Slash(0,1)" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const phi0 = 1.0 / math.sqrt(2.0 * math.pi);
    const expected = phi0 / 2.0; // ≈ 0.19947114
    const pdf_val = dist.pdf(0.0);
    try testing.expectApproxEqAbs(expected, pdf_val, 1e-6);
}

test "Slash: pdf at x=1 for Slash(0,1)" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const expected = 0.15697155; // hardcoded
    const pdf_val = dist.pdf(1.0);
    try testing.expectApproxEqAbs(expected, pdf_val, 1e-6);
}

test "Slash: pdf at x=-1 for Slash(0,1) is symmetric" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const pdf_pos = dist.pdf(1.0);
    const pdf_neg = dist.pdf(-1.0);
    try testing.expectApproxEqAbs(pdf_pos, pdf_neg, 1e-10);
}

test "Slash: pdf is positive for all finite x" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const test_points = [_]f64{ -5.0, -2.0, -1.0, -0.5, 0.0, 0.5, 1.0, 2.0, 5.0 };
    for (test_points) |x| {
        try testing.expect(dist.pdf(x) > 0.0);
    }
}

test "Slash: pdf(mu) for Slash(2,3) equals phi0/(2*3)" {
    const dist = try Slash(f64).init(2.0, 3.0);
    const phi0 = 1.0 / math.sqrt(2.0 * math.pi);
    const expected = phi0 / (2.0 * 3.0); // ≈ 0.06649038
    const pdf_val = dist.pdf(2.0);
    try testing.expectApproxEqAbs(expected, pdf_val, 1e-6);
}

test "Slash: pdf decays away from mode" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const pdf_at_mu = dist.pdf(0.0);
    const pdf_at_1 = dist.pdf(1.0);
    const pdf_at_2 = dist.pdf(2.0);
    try testing.expect(pdf_at_mu > pdf_at_1);
    try testing.expect(pdf_at_1 > pdf_at_2);
}

test "Slash: logpdf at x=mu returns log(phi0/(2*sigma))" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const phi0 = 1.0 / math.sqrt(2.0 * math.pi);
    const expected = @log(phi0 / 2.0);
    const logpdf_val = dist.logpdf(0.0);
    try testing.expectApproxEqAbs(expected, logpdf_val, 1e-10);
}

test "Slash: logpdf(x=1, Slash(0,1)) equals log(pdf(1))" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const pdf_val = dist.pdf(1.0);
    const expected_logpdf = @log(pdf_val);
    const logpdf_val = dist.logpdf(1.0);
    try testing.expectApproxEqAbs(expected_logpdf, logpdf_val, 1e-10);
}

// --- cdf tests ---

test "Slash: cdf at mode (x=mu) is exactly 0.5" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const cdf_val = dist.cdf(0.0);
    try testing.expectApproxEqAbs(0.5, cdf_val, 1e-10);
}

test "Slash: cdf at mode for Slash(2,3) is exactly 0.5" {
    const dist = try Slash(f64).init(2.0, 3.0);
    const cdf_val = dist.cdf(2.0);
    try testing.expectApproxEqAbs(0.5, cdf_val, 1e-10);
}

test "Slash: cdf(1) for Slash(0,1)" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const expected = 0.68437320; // hardcoded
    const cdf_val = dist.cdf(1.0);
    try testing.expectApproxEqAbs(expected, cdf_val, 1e-6);
}

test "Slash: cdf(-1) for Slash(0,1)" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const expected = 0.31562680; // hardcoded
    const cdf_val = dist.cdf(-1.0);
    try testing.expectApproxEqAbs(expected, cdf_val, 1e-6);
}

test "Slash: cdf symmetry for Slash(0,1): cdf(-x) + cdf(x) ≈ 1" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const cdf_neg_1 = dist.cdf(-1.0);
    const cdf_pos_1 = dist.cdf(1.0);
    try testing.expectApproxEqAbs(1.0, cdf_neg_1 + cdf_pos_1, 1e-10);
}

test "Slash: cdf is monotone increasing" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const cdf_minus_1 = dist.cdf(-1.0);
    const cdf_0 = dist.cdf(0.0);
    const cdf_plus_1 = dist.cdf(1.0);
    try testing.expect(cdf_minus_1 < cdf_0);
    try testing.expect(cdf_0 < cdf_plus_1);
}

test "Slash: cdf approaches 1 for large positive x" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const cdf_large = dist.cdf(100.0);
    try testing.expect(cdf_large > 0.99);
}

test "Slash: cdf approaches 0 for large negative x" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const cdf_small = dist.cdf(-100.0);
    try testing.expect(cdf_small < 0.01);
}

test "Slash: cdf + sf = 1" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const cdf_val = dist.cdf(0.7);
    const sf_val = dist.sf(0.7);
    try testing.expectApproxEqAbs(1.0, cdf_val + sf_val, 1e-10);
}

// --- quantile tests ---

test "Slash: quantile(0.5) = 0 for Slash(0,1)" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const q = dist.quantile(0.5);
    try testing.expectApproxEqAbs(0.0, q, 1e-8);
}

test "Slash: quantile(0.5) = mu for Slash(mu, sigma)" {
    const dist = try Slash(f64).init(3.0, 2.0);
    const q = dist.quantile(0.5);
    try testing.expectApproxEqAbs(3.0, q, 1e-8);
}

test "Slash: quantile(NaN) returns NaN" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const q = dist.quantile(math.nan(f64));
    try testing.expect(math.isNan(q));
}

test "Slash: quantile(-0.1) returns NaN" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const q = dist.quantile(-0.1);
    try testing.expect(math.isNan(q));
}

test "Slash: quantile(1.1) returns NaN" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const q = dist.quantile(1.1);
    try testing.expect(math.isNan(q));
}

test "Slash: quantile(0) returns -inf" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const q = dist.quantile(0.0);
    try testing.expect(math.isNegativeInf(q));
}

test "Slash: quantile(1) returns +inf" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const q = dist.quantile(1.0);
    try testing.expect(math.isPositiveInf(q));
}

test "Slash: quantile is inverse of cdf at p=0.7" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const q = dist.quantile(0.7);
    const cdf_q = dist.cdf(q);
    try testing.expectApproxEqAbs(0.7, cdf_q, 1e-6);
}

// --- mean/variance tests ---

test "Slash: mean() returns NaN" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const mean_val = dist.mean();
    try testing.expect(math.isNan(mean_val));
}

test "Slash: variance() returns NaN" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const var_val = dist.variance();
    try testing.expect(math.isNan(var_val));
}

test "Slash: mode() returns mu for Slash(0,1)" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const mode_val = dist.mode();
    try testing.expectApproxEqAbs(0.0, mode_val, 1e-10);
}

test "Slash: mode() returns mu for Slash(2,3)" {
    const dist = try Slash(f64).init(2.0, 3.0);
    const mode_val = dist.mode();
    try testing.expectApproxEqAbs(2.0, mode_val, 1e-10);
}

// --- entropy tests ---

test "Slash: entropy is finite and positive" {
    const dist = try Slash(f64).init(0.0, 1.0);
    const entropy_val = dist.entropy();
    try testing.expect(entropy_val > 0.0);
    try testing.expect(math.isFinite(entropy_val));
}

test "Slash: entropy scales with sigma: entropy(0,2) > entropy(0,1)" {
    const dist1 = try Slash(f64).init(0.0, 1.0);
    const dist2 = try Slash(f64).init(0.0, 2.0);
    const ent1 = dist1.entropy();
    const ent2 = dist2.entropy();
    try testing.expect(ent2 > ent1);
}

test "Slash: entropy difference is approximately log(2) when sigma doubles" {
    const dist1 = try Slash(f64).init(0.0, 1.0);
    const dist2 = try Slash(f64).init(0.0, 2.0);
    const ent1 = dist1.entropy();
    const ent2 = dist2.entropy();
    const log_2 = @log(2.0);
    const diff = ent2 - ent1;
    try testing.expectApproxEqAbs(log_2, diff, 1e-4);
}

test "Slash: entropy is location-invariant" {
    const dist1 = try Slash(f64).init(3.0, 1.0);
    const dist2 = try Slash(f64).init(-3.0, 1.0);
    const ent1 = dist1.entropy();
    const ent2 = dist2.entropy();
    try testing.expectApproxEqAbs(ent1, ent2, 1e-10);
}

// --- sample tests ---

test "Slash: sample returns a finite value" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try Slash(f64).init(0.0, 1.0);
    const sample_val = dist.sample(rng.random());
    try testing.expect(math.isFinite(sample_val));
}

test "Slash: sample(Slash(mu, sigma)) has mode near mu over 1000 samples" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try Slash(f64).init(5.0, 1.0);
    var sum: f64 = 0.0;
    var count: i32 = 0;
    for (0..1000) |_| {
        const s = dist.sample(rng.random());
        if (math.isFinite(s)) {
            sum += s;
            count += 1;
        }
    }
    const mean_sample = sum / @as(f64, @floatFromInt(count));
    try testing.expect(count >= 900); // at least 900 finite samples
    try testing.expect(math.isFinite(mean_sample));
}

test "Slash: two consecutive samples differ" {
    var rng1 = std.Random.DefaultPrng.init(42);
    var rng2 = std.Random.DefaultPrng.init(43);
    const dist = try Slash(f64).init(0.0, 1.0);
    const s1 = dist.sample(rng1.random());
    const s2 = dist.sample(rng2.random());
    try testing.expect(s1 != s2);
}

// --- validate tests ---

test "Slash: validate() succeeds for valid parameters" {
    var dist = try Slash(f64).init(0.0, 1.0);
    try dist.validate();
}

test "Slash: validate() fails after manually setting sigma to 0" {
    var dist = try Slash(f64).init(0.0, 1.0);
    dist.sigma = 0.0;
    const result = dist.validate();
    try testing.expectError(error.InvalidParameter, result);
}

test "Slash: validate() fails after manually setting sigma to negative" {
    var dist = try Slash(f64).init(0.0, 1.0);
    dist.sigma = -1.0;
    const result = dist.validate();
    try testing.expectError(error.InvalidParameter, result);
}

// ============================================================================
// Fréchet Distribution
// ============================================================================
//
// Fréchet(α, s, m): α > 0 (shape), s > 0 (scale), m (location)
// Support: x > m; defined as the Type II extreme value distribution
// Named after Maurice Fréchet; used in extreme value theory, actuarial science
//

pub fn Frechet(comptime T: type) type {
    return struct {
        alpha: T,
        s: T,
        m: T,

        const Self = @This();

        // --- Lifecycle ---

        /// Initialize Fréchet distribution with shape alpha > 0, scale s > 0, and location m.
        /// Time: O(1) | Space: O(1)
        pub fn init(alpha: T, s: T, m: T) DistributionError!Self {
            if (alpha <= 0.0 or !math.isFinite(alpha)) return error.InvalidParameter;
            if (s <= 0.0 or !math.isFinite(s)) return error.InvalidParameter;
            if (!math.isFinite(m)) return error.InvalidParameter;
            return Self{ .alpha = alpha, .s = s, .m = m };
        }

        /// Assert all parameters are valid.
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (self.alpha <= 0.0 or !math.isFinite(self.alpha)) return error.InvalidParameter;
            if (self.s <= 0.0 or !math.isFinite(self.s)) return error.InvalidParameter;
            if (!math.isFinite(self.m)) return error.InvalidParameter;
        }

        // --- PDF / LogPDF ---

        /// Log-probability density function.
        /// For x ≤ m: returns -∞
        /// For x > m: log(α) - log(s) - (α+1)·log(z) - z^(-α), where z=(x-m)/s
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= self.m) return -math.inf(T);
            const z = (x - self.m) / self.s;
            const z_neg_alpha = math.pow(T, z, -self.alpha);
            return @log(self.alpha) - @log(self.s) - (self.alpha + 1.0) * @log(z) - z_neg_alpha;
        }

        /// Probability density function.
        /// f(x) = (α/s)·((x-m)/s)^(-α-1)·exp(-((x-m)/s)^(-α)) for x > m; 0 for x ≤ m
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            return @exp(self.logpdf(x));
        }

        // --- CDF / SF ---

        /// Cumulative distribution function.
        /// F(x) = exp(-((x-m)/s)^(-α)) for x > m; 0 for x ≤ m
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= self.m) return 0.0;
            const z = (x - self.m) / self.s;
            const z_neg_alpha = math.pow(T, z, -self.alpha);
            return @exp(-z_neg_alpha);
        }

        /// Survival function: 1 - CDF(x).
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            return 1.0 - self.cdf(x);
        }

        // --- Quantile ---

        /// Quantile (inverse CDF).
        /// Q(p) = m + s·(-log(p))^(-1/α)
        /// Returns NaN for p outside [0,1]; m for p=0; +∞ for p=1.
        /// Time: O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) T {
            if (math.isNan(p) or p < 0.0 or p > 1.0) return math.nan(T);
            if (p == 0.0) return self.m;
            if (p == 1.0) return math.inf(T);
            const neg_log_p = -@log(p);
            const neg_one_over_alpha = -1.0 / self.alpha;
            return self.m + self.s * math.pow(T, neg_log_p, neg_one_over_alpha);
        }

        // --- Moments ---

        /// Mean: m + s·Γ(1-1/α) for α > 1; NaN otherwise.
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            if (self.alpha <= 1.0) return math.nan(T);
            const gamma_arg = 1.0 - 1.0 / self.alpha;
            const gamma_val = @exp(logGamma(gamma_arg));
            return self.m + self.s * gamma_val;
        }

        /// Variance: s²·(Γ(1-2/α) - Γ(1-1/α)²) for α > 2; NaN otherwise.
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            if (self.alpha <= 2.0) return math.nan(T);
            const g1_arg = 1.0 - 1.0 / self.alpha;
            const g2_arg = 1.0 - 2.0 / self.alpha;
            const g1 = @exp(logGamma(g1_arg));
            const g2 = @exp(logGamma(g2_arg));
            return self.s * self.s * (g2 - g1 * g1);
        }

        /// Mode: m + s·(α/(α+1))^(1/α)
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            const ratio = self.alpha / (self.alpha + 1.0);
            const one_over_alpha = 1.0 / self.alpha;
            return self.m + self.s * math.pow(T, ratio, one_over_alpha);
        }

        // --- Entropy ---

        /// Entropy: 1 + γ·(1+1/α) + log(s/α), γ≈0.5772156649
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            const euler_gamma: T = 0.5772156649015329;
            return 1.0 + euler_gamma * (1.0 + 1.0 / self.alpha) + @log(self.s / self.alpha);
        }

        // --- Sampling ---

        /// Sample via X = m + s·(-log(U))^(-1/α), U ~ Uniform(0,1).
        /// Time: O(1) | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const u = @max(rng.float(T), math.floatEps(T));
            const neg_log_u = -@log(u);
            const neg_one_over_alpha = -1.0 / self.alpha;
            return self.m + self.s * math.pow(T, neg_log_u, neg_one_over_alpha);
        }
    };
}

// ============================================================================
// Fréchet(α, s, m) Distribution Tests
// ============================================================================
//
// Fréchet(α, s, m): Type II extreme value distribution
// Parameters: α > 0 (shape), s > 0 (scale), m (location, any real)
// Support: x > m; CDF=0 and PDF=0 for x ≤ m
// CDF: F(x) = exp(-((x-m)/s)^(-α)) for x > m
// PDF: f(x) = (α/s)·((x-m)/s)^(-α-1)·exp(-((x-m)/s)^(-α))
// LogPDF: log(α) - log(s) - (α+1)·log(z) - z^(-α), z=(x-m)/s
// Quantile: Q(p) = m + s·(-log(p))^(-1/α)
// Mean: m + s·Γ(1-1/α) for α > 1; NaN for α ≤ 1
// Variance: s²·(Γ(1-2/α) - Γ(1-1/α)²) for α > 2; NaN for α ≤ 2
// Mode: m + s·(α/(α+1))^(1/α)
// Entropy: 1 + γ·(1+1/α) + log(s/α), γ≈0.5772156649
// Sample: X = m + s·(-log(U))^(-1/α), U ~ Uniform(0,1)
//

// --- init tests ---

test "Frechet: init with alpha=2, s=1, m=0" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    try testing.expectEqual(@as(f64, 2.0), dist.alpha);
    try testing.expectEqual(@as(f64, 1.0), dist.s);
    try testing.expectEqual(@as(f64, 0.0), dist.m);
}

test "Frechet: init with alpha=3, s=2, m=1" {
    const dist = try Frechet(f64).init(3.0, 2.0, 1.0);
    try testing.expectEqual(@as(f64, 3.0), dist.alpha);
    try testing.expectEqual(@as(f64, 2.0), dist.s);
    try testing.expectEqual(@as(f64, 1.0), dist.m);
}

test "Frechet: init with negative m" {
    const dist = try Frechet(f64).init(2.0, 1.0, -5.5);
    try testing.expectEqual(@as(f64, -5.5), dist.m);
}

test "Frechet: init fails when alpha=0" {
    const result = Frechet(f64).init(0.0, 1.0, 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when alpha is negative" {
    const result = Frechet(f64).init(-1.0, 1.0, 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when s=0" {
    const result = Frechet(f64).init(2.0, 0.0, 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when s is negative" {
    const result = Frechet(f64).init(2.0, -1.0, 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when alpha is NaN" {
    const result = Frechet(f64).init(math.nan(f64), 1.0, 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when s is NaN" {
    const result = Frechet(f64).init(2.0, math.nan(f64), 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when m is NaN" {
    const result = Frechet(f64).init(2.0, 1.0, math.nan(f64));
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when alpha is infinite" {
    const result = Frechet(f64).init(math.inf(f64), 1.0, 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when s is infinite" {
    const result = Frechet(f64).init(2.0, math.inf(f64), 0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: init fails when m is infinite" {
    const result = Frechet(f64).init(2.0, 1.0, math.inf(f64));
    try testing.expectError(error.InvalidParameter, result);
}

// --- validate tests ---

test "Frechet: validate() succeeds for valid parameters" {
    var dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    try dist.validate();
}

test "Frechet: validate() fails after manually setting alpha to 0" {
    var dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    dist.alpha = 0.0;
    const result = dist.validate();
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: validate() fails after manually setting s to negative" {
    var dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    dist.s = -1.0;
    const result = dist.validate();
    try testing.expectError(error.InvalidParameter, result);
}

test "Frechet: validate() fails after manually setting m to NaN" {
    var dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    dist.m = math.nan(f64);
    const result = dist.validate();
    try testing.expectError(error.InvalidParameter, result);
}

// --- pdf tests ---

test "Frechet: pdf returns 0 for x=m (boundary)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const pdf_val = dist.pdf(0.0);
    try testing.expectEqual(@as(f64, 0.0), pdf_val);
}

test "Frechet: pdf returns 0 for x < m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const pdf_val = dist.pdf(-1.0);
    try testing.expectEqual(@as(f64, 0.0), pdf_val);
}

test "Frechet: pdf at x=s for Frechet(2,1,0) is 2*exp(-1)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const expected = 2.0 * @exp(-1.0); // ≈ 0.73575888
    const pdf_val = dist.pdf(1.0);
    try testing.expectApproxEqAbs(expected, pdf_val, 1e-6);
}

test "Frechet: pdf at x=s for Frechet(3,1,0) is 3*exp(-1)" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    const expected = 3.0 * @exp(-1.0); // ≈ 1.10363832
    const pdf_val = dist.pdf(1.0);
    try testing.expectApproxEqAbs(expected, pdf_val, 1e-6);
}

test "Frechet: pdf is positive for x > m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const test_points = [_]f64{ 0.1, 0.5, 1.0, 2.0, 5.0 };
    for (test_points) |x| {
        try testing.expect(dist.pdf(x) > 0.0);
    }
}

test "Frechet: pdf has mode at m + s*(alpha/(alpha+1))^(1/alpha)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const mode_val = dist.mode();
    const pdf_at_mode = dist.pdf(mode_val);
    const pdf_left = dist.pdf(mode_val - 0.05);
    const pdf_right = dist.pdf(mode_val + 0.05);
    try testing.expect(pdf_at_mode > pdf_left);
    try testing.expect(pdf_at_mode > pdf_right);
}

test "Frechet: pdf is unimodal (mode is unique maximum)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const pdf_at_0_5 = dist.pdf(0.5);
    const pdf_at_2 = dist.pdf(2.0);
    try testing.expect(pdf_at_0_5 > pdf_at_2);
}

test "Frechet: pdf at x=s equals exp(-1)^2 * alpha" {
    // At z=1 (x=s), pdf = (alpha/s) * 1^(-alpha-1) * exp(-1) = (alpha/s)*exp(-1)
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const expected = 2.0 * @exp(-1.0);
    const pdf_val = dist.pdf(1.0);
    try testing.expectApproxEqAbs(expected, pdf_val, 1e-6);
}

test "Frechet: pdf for Frechet(2,1,0) at x=0.5 is computed correctly" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    // z = 0.5, z^(-alpha-1) = 0.5^(-3) = 8, exp(-0.5^(-2)) = exp(-4)
    const z = 0.5;
    const z_pow = math.pow(f64, z, -3.0); // 8
    const exp_term = @exp(-math.pow(f64, z, -2.0)); // exp(-4)
    const expected = 2.0 * z_pow * exp_term; // ≈ 0.00268
    const pdf_val = dist.pdf(0.5);
    try testing.expectApproxEqAbs(expected, pdf_val, 1e-4);
}

// --- logpdf tests ---

test "Frechet: logpdf returns -inf for x=m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const logpdf_val = dist.logpdf(0.0);
    try testing.expect(math.isNegativeInf(logpdf_val));
}

test "Frechet: logpdf returns -inf for x < m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const logpdf_val = dist.logpdf(-1.0);
    try testing.expect(math.isNegativeInf(logpdf_val));
}

test "Frechet: logpdf at x=s for Frechet(2,1,0) equals log(2*exp(-1))" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const expected = @log(2.0 * @exp(-1.0)); // ≈ -0.25318
    const logpdf_val = dist.logpdf(1.0);
    try testing.expectApproxEqAbs(expected, logpdf_val, 1e-6);
}

test "Frechet: logpdf(x > m) equals log(pdf(x))" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const x = 2.0;
    const pdf_val = dist.pdf(x);
    const logpdf_val = dist.logpdf(x);
    const expected = @log(pdf_val);
    try testing.expectApproxEqAbs(expected, logpdf_val, 1e-10);
}

// --- cdf tests ---

test "Frechet: cdf returns 0 for x=m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const cdf_val = dist.cdf(0.0);
    try testing.expectEqual(@as(f64, 0.0), cdf_val);
}

test "Frechet: cdf returns 0 for x < m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const cdf_val = dist.cdf(-1.0);
    try testing.expectEqual(@as(f64, 0.0), cdf_val);
}

test "Frechet: cdf at x=s equals exp(-1) for any alpha" {
    // CDF at x = m + s is exp(-(1)^(-alpha)) = exp(-1), independent of alpha
    const dist2 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist3 = try Frechet(f64).init(3.0, 1.0, 0.0);
    const cdf2 = dist2.cdf(1.0);
    const cdf3 = dist3.cdf(1.0);
    const expected = @exp(-1.0); // ≈ 0.36787944
    try testing.expectApproxEqAbs(expected, cdf2, 1e-10);
    try testing.expectApproxEqAbs(expected, cdf3, 1e-10);
}

test "Frechet: cdf(1) for Frechet(2,1,0)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const expected = @exp(-1.0); // ≈ 0.36787944
    const cdf_val = dist.cdf(1.0);
    try testing.expectApproxEqAbs(expected, cdf_val, 1e-10);
}

test "Frechet: cdf(1) for Frechet(3,1,0)" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    const expected = @exp(-1.0); // ≈ 0.36787944
    const cdf_val = dist.cdf(1.0);
    try testing.expectApproxEqAbs(expected, cdf_val, 1e-10);
}

test "Frechet: cdf is monotone increasing" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const cdf_0_5 = dist.cdf(0.5);
    const cdf_1 = dist.cdf(1.0);
    const cdf_2 = dist.cdf(2.0);
    try testing.expect(cdf_0_5 < cdf_1);
    try testing.expect(cdf_1 < cdf_2);
}

test "Frechet: cdf approaches 1 for large x" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const cdf_large = dist.cdf(100.0);
    try testing.expect(cdf_large > 0.9999);
}

test "Frechet: cdf at location m equals 0" {
    const dist = try Frechet(f64).init(2.0, 1.0, 5.0);
    const cdf_val = dist.cdf(5.0);
    try testing.expectEqual(@as(f64, 0.0), cdf_val);
}

test "Frechet: cdf + sf = 1 for x > m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const x = 1.5;
    const cdf_val = dist.cdf(x);
    const sf_val = dist.sf(x);
    try testing.expectApproxEqAbs(1.0, cdf_val + sf_val, 1e-10);
}

// --- sf (survival function) tests ---

test "Frechet: sf returns 1 for x=m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const sf_val = dist.sf(0.0);
    try testing.expectEqual(@as(f64, 1.0), sf_val);
}

test "Frechet: sf at x=s equals 1-exp(-1)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const expected = 1.0 - @exp(-1.0); // ≈ 0.63212056
    const sf_val = dist.sf(1.0);
    try testing.expectApproxEqAbs(expected, sf_val, 1e-10);
}

// --- quantile tests ---

test "Frechet: quantile(p) returns NaN for p=NaN" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const q = dist.quantile(math.nan(f64));
    try testing.expect(math.isNan(q));
}

test "Frechet: quantile(p) returns NaN for p < 0" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const q = dist.quantile(-0.1);
    try testing.expect(math.isNan(q));
}

test "Frechet: quantile(p) returns NaN for p > 1" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const q = dist.quantile(1.1);
    try testing.expect(math.isNan(q));
}

test "Frechet: quantile(0) returns m (location)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 5.0);
    const q = dist.quantile(0.0);
    try testing.expectApproxEqAbs(5.0, q, 1e-10);
}

test "Frechet: quantile(1) returns +infinity" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const q = dist.quantile(1.0);
    try testing.expect(math.isPositiveInf(q));
}

test "Frechet: quantile(exp(-1)) = s for Frechet(alpha,s,m)" {
    // Q(p) = m + s*(-log(p))^(-1/alpha)
    // Q(exp(-1)) = m + s*(1)^(-1/alpha) = m + s
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const p = @exp(-1.0);
    const q = dist.quantile(p);
    const expected = 1.0; // m + s = 0 + 1
    try testing.expectApproxEqAbs(expected, q, 1e-8);
}

test "Frechet: quantile(0.5) for Frechet(2,1,0)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    // Q(0.5) = s*(-log(0.5))^(-1/2) = log(2)^(-1/2) = 1/sqrt(log(2))
    const log_2 = @log(2.0);
    const expected = 1.0 / math.sqrt(log_2); // ≈ 1.20112240
    const q = dist.quantile(0.5);
    try testing.expectApproxEqAbs(expected, q, 1e-8);
}

test "Frechet: quantile(0.5) for Frechet(3,1,0)" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    // Q(0.5) = s*(-log(0.5))^(-1/3) = log(2)^(-1/3)
    const log_2 = @log(2.0);
    const expected = math.pow(f64, log_2, -1.0 / 3.0); // ≈ 0.79036...
    const q = dist.quantile(0.5);
    try testing.expectApproxEqAbs(expected, q, 1e-8);
}

test "Frechet: quantile is inverse of cdf" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const p = 0.7;
    const q = dist.quantile(p);
    const cdf_q = dist.cdf(q);
    try testing.expectApproxEqAbs(p, cdf_q, 1e-8);
}

test "Frechet: quantile with non-zero location m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 5.0);
    const p = 0.5;
    const q = dist.quantile(p);
    const log_2 = @log(2.0);
    const expected = 5.0 + 1.0 / math.sqrt(log_2); // m + s*(-log(p))^(-1/alpha)
    try testing.expectApproxEqAbs(expected, q, 1e-8);
}

// --- mean tests ---

test "Frechet: mean returns NaN for alpha <= 1" {
    const dist = try Frechet(f64).init(1.0, 1.0, 0.0);
    const mean_val = dist.mean();
    try testing.expect(math.isNan(mean_val));
}

test "Frechet: mean returns NaN for alpha=0.5" {
    const dist = try Frechet(f64).init(0.5, 1.0, 0.0);
    const mean_val = dist.mean();
    try testing.expect(math.isNan(mean_val));
}

test "Frechet: mean for alpha > 1 uses gamma function" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    // Mean = m + s*Gamma(1 - 1/alpha) = 0 + 1*Gamma(0.5) = sqrt(pi)
    const expected = math.sqrt(math.pi); // ≈ 1.77245385
    const mean_val = dist.mean();
    try testing.expectApproxEqAbs(expected, mean_val, 1e-6);
}

test "Frechet: mean for Frechet(3,1,0)" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    // Mean = Gamma(2/3) ≈ 1.35411794
    const mean_val = dist.mean();
    const expected = 1.35411794;
    try testing.expectApproxEqAbs(expected, mean_val, 1e-6);
}

test "Frechet: mean scales linearly with scale s" {
    const dist1 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(2.0, 2.0, 0.0);
    const mean1 = dist1.mean();
    const mean2 = dist2.mean();
    try testing.expectApproxEqAbs(2.0 * mean1, mean2, 1e-10);
}

test "Frechet: mean shifts with location m" {
    const dist1 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(2.0, 1.0, 5.0);
    const mean1 = dist1.mean();
    const mean2 = dist2.mean();
    try testing.expectApproxEqAbs(mean1 + 5.0, mean2, 1e-10);
}

// --- variance tests ---

test "Frechet: variance returns NaN for alpha <= 2" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const var_val = dist.variance();
    try testing.expect(math.isNan(var_val));
}

test "Frechet: variance returns NaN for alpha=1.5" {
    const dist = try Frechet(f64).init(1.5, 1.0, 0.0);
    const var_val = dist.variance();
    try testing.expect(math.isNan(var_val));
}

test "Frechet: variance for alpha > 2 is positive" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    const var_val = dist.variance();
    try testing.expect(var_val > 0.0);
}

test "Frechet: variance for Frechet(3,1,0)" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    // Variance ≈ 0.84530305
    const var_val = dist.variance();
    const expected = 0.84530305;
    try testing.expectApproxEqAbs(expected, var_val, 1e-6);
}

test "Frechet: variance scales with scale squared" {
    const dist1 = try Frechet(f64).init(3.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(3.0, 2.0, 0.0);
    const var1 = dist1.variance();
    const var2 = dist2.variance();
    try testing.expectApproxEqAbs(4.0 * var1, var2, 1e-10);
}

test "Frechet: variance is location-invariant" {
    const dist1 = try Frechet(f64).init(3.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(3.0, 1.0, 5.0);
    const var1 = dist1.variance();
    const var2 = dist2.variance();
    try testing.expectApproxEqAbs(var1, var2, 1e-10);
}

// --- mode tests ---

test "Frechet: mode for Frechet(2,1,0)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    // Mode = m + s*(alpha/(alpha+1))^(1/alpha) = (2/3)^(1/2) = sqrt(2/3)
    const expected = math.sqrt(2.0 / 3.0); // ≈ 0.81649658
    const mode_val = dist.mode();
    try testing.expectApproxEqAbs(expected, mode_val, 1e-6);
}

test "Frechet: mode for Frechet(3,1,0)" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    // Mode = (3/4)^(1/3) = cbrt(0.75) ≈ 0.90856029
    const expected = 0.90856029;
    const mode_val = dist.mode();
    try testing.expectApproxEqAbs(expected, mode_val, 1e-6);
}

test "Frechet: mode is always > m" {
    const dist = try Frechet(f64).init(2.0, 1.0, 5.0);
    const mode_val = dist.mode();
    try testing.expect(mode_val > 5.0);
}

test "Frechet: mode for Frechet(3,2,0)" {
    const dist = try Frechet(f64).init(3.0, 2.0, 0.0);
    // Mode = 2 * (3/4)^(1/3)
    const expected = 2.0 * math.pow(f64, 0.75, 1.0 / 3.0); // ≈ 1.81712058
    const mode_val = dist.mode();
    try testing.expectApproxEqAbs(expected, mode_val, 1e-6);
}

test "Frechet: mode is less than mean for alpha > 1 (right-skewed)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const mode_val = dist.mode();
    const mean_val = dist.mean();
    try testing.expect(mode_val < mean_val);
}

// --- entropy tests ---

test "Frechet: entropy is positive and finite" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const entropy_val = dist.entropy();
    try testing.expect(entropy_val > 0.0);
    try testing.expect(math.isFinite(entropy_val));
}

test "Frechet: entropy for Frechet(2,1,0)" {
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    // Entropy = 1 + gamma*(1+1/2) + log(1/2) = 1 + 0.5772*1.5 - log(2)
    const gamma = 0.5772156649015329;
    const expected = 1.0 + gamma * 1.5 - @log(2.0); // ≈ 1.17265
    const entropy_val = dist.entropy();
    try testing.expectApproxEqAbs(expected, entropy_val, 1e-5);
}

test "Frechet: entropy for Frechet(3,1,0)" {
    const dist = try Frechet(f64).init(3.0, 1.0, 0.0);
    // Entropy = 1 + gamma*(1+1/3) + log(1/3)
    const gamma = 0.5772156649015329;
    const expected = 1.0 + gamma * (4.0 / 3.0) + @log(1.0 / 3.0); // ≈ 0.67102
    const entropy_val = dist.entropy();
    try testing.expectApproxEqAbs(expected, entropy_val, 1e-5);
}

test "Frechet: entropy increases with scale s" {
    const dist1 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(2.0, 2.0, 0.0);
    const ent1 = dist1.entropy();
    const ent2 = dist2.entropy();
    try testing.expect(ent2 > ent1);
}

test "Frechet: entropy difference is log(scale_ratio)" {
    const dist1 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(2.0, 3.0, 0.0);
    const ent1 = dist1.entropy();
    const ent2 = dist2.entropy();
    const expected_diff = @log(3.0);
    const actual_diff = ent2 - ent1;
    try testing.expectApproxEqAbs(expected_diff, actual_diff, 1e-10);
}

test "Frechet: entropy is location-invariant" {
    const dist1 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(2.0, 1.0, 10.0);
    const ent1 = dist1.entropy();
    const ent2 = dist2.entropy();
    try testing.expectApproxEqAbs(ent1, ent2, 1e-10);
}

// --- sample tests ---

test "Frechet: sample returns finite value" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const sample_val = dist.sample(rng.random());
    try testing.expect(math.isFinite(sample_val));
}

test "Frechet: sample returns value > m" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try Frechet(f64).init(2.0, 1.0, 5.0);
    const sample_val = dist.sample(rng.random());
    try testing.expect(sample_val > 5.0);
}

test "Frechet: 100 samples all > m" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    for (0..100) |_| {
        const sample_val = dist.sample(rng.random());
        try testing.expect(sample_val > 0.0);
    }
}

test "Frechet: samples with different seeds differ" {
    var rng1 = std.Random.DefaultPrng.init(42);
    var rng2 = std.Random.DefaultPrng.init(43);
    const dist = try Frechet(f64).init(2.0, 1.0, 0.0);
    const s1 = dist.sample(rng1.random());
    const s2 = dist.sample(rng2.random());
    try testing.expect(s1 != s2);
}

test "Frechet: sample scales with s parameter" {
    var rng1 = std.Random.DefaultPrng.init(42);
    var rng2 = std.Random.DefaultPrng.init(42);
    const dist1 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(2.0, 2.0, 0.0);
    const s1 = dist1.sample(rng1.random());
    const s2 = dist2.sample(rng2.random());
    // Both samples use same RNG seed, so s2 should be approximately 2*s1
    try testing.expectApproxEqRel(2.0 * s1, s2, 1e-10);
}

test "Frechet: sample shifts with m parameter" {
    var rng1 = std.Random.DefaultPrng.init(42);
    var rng2 = std.Random.DefaultPrng.init(42);
    const dist1 = try Frechet(f64).init(2.0, 1.0, 0.0);
    const dist2 = try Frechet(f64).init(2.0, 1.0, 10.0);
    const s1 = dist1.sample(rng1.random());
    const s2 = dist2.sample(rng2.random());
    // Both samples use same RNG seed, so s2 should be approximately s1 + 10
    try testing.expectApproxEqRel(s1 + 10.0, s2, 1e-10);
}

// ============================================================================
// BetaPrime Distribution
// ============================================================================
//
// BetaPrime(α, β): also known as inverted Beta or Beta distribution of 2nd kind
// X ~ BetaPrime(α, β)  iff  X = Y/(1-Y) where Y ~ Beta(α, β)
// Support: x > 0
// Parameters: alpha (α > 0), beta_param (β > 0)
//
// PDF:     f(x) = x^(α-1)·(1+x)^(-α-β) / B(α,β)   for x > 0
// LogPDF:  (α-1)·ln(x) - (α+β)·ln(1+x) - ln B(α,β)
// CDF:     F(x) = I(x/(1+x); α, β) — regularized incomplete beta
// Mean:    α/(β-1)  for β > 1; NaN otherwise
// Variance: α(α+β-1)/((β-1)²(β-2))  for β > 2; NaN otherwise
// Mode:    (α-1)/(β+1)  for α > 1; 0 for α ≤ 1 (boundary mode)
// Entropy: ln B(α,β) − (α-1)·ψ(α) − (β+1)·ψ(β) + (α+β)·ψ(α+β)
// Sample:  G₁/G₂ where G₁~Gamma(α,1), G₂~Gamma(β,1)
//

pub fn BetaPrime(comptime T: type) type {
    return struct {
        alpha: T,
        beta_param: T,

        const Self = @This();

        // --- Lifecycle ---

        /// Initialize BetaPrime distribution with shape parameters alpha > 0, beta > 0.
        /// Time: O(1) | Space: O(1)
        pub fn init(alpha: T, beta_param: T) DistributionError!Self {
            if (alpha <= 0.0 or !math.isFinite(alpha)) return error.InvalidParameter;
            if (beta_param <= 0.0 or !math.isFinite(beta_param)) return error.InvalidParameter;
            return Self{ .alpha = alpha, .beta_param = beta_param };
        }

        /// Assert all parameters are valid.
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (self.alpha <= 0.0 or !math.isFinite(self.alpha)) return error.InvalidParameter;
            if (self.beta_param <= 0.0 or !math.isFinite(self.beta_param)) return error.InvalidParameter;
        }

        // --- PDF / LogPDF ---

        /// Log-probability density function.
        /// For x ≤ 0: returns -∞
        /// For x > 0: (α-1)·ln(x) - (α+β)·ln(1+x) - ln B(α,β)
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= 0.0) return -math.inf(T);
            return (self.alpha - 1.0) * @log(x) -
                (self.alpha + self.beta_param) * @log(1.0 + x) -
                logBeta(self.alpha, self.beta_param);
        }

        /// Probability density function.
        /// f(x) = x^(α-1)·(1+x)^(-α-β) / B(α,β) for x > 0; 0 for x ≤ 0
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            return @exp(self.logpdf(x));
        }

        // --- CDF / SF ---

        /// Cumulative distribution function.
        /// F(x) = I(x/(1+x); α, β) where I is the regularized incomplete beta.
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            const t = x / (1.0 + x);
            return regularizedBetaI(self.alpha, self.beta_param, t);
        }

        /// Survival function: 1 − CDF(x).
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            return 1.0 - self.cdf(x);
        }

        // --- Quantile ---

        /// Quantile (inverse CDF) via adaptive-bound bisection (100 iterations).
        /// Returns NaN for p outside [0,1]; 0 for p=0; +∞ for p=1.
        /// Time: O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) T {
            if (math.isNan(p) or p < 0.0 or p > 1.0) return math.nan(T);
            if (p == 0.0) return 0.0;
            if (p == 1.0) return math.inf(T);

            // Expand upper bound until CDF(hi) >= p
            var lo: T = 0.0;
            var hi: T = 1.0;
            while (self.cdf(hi) < p) hi *= 2.0;

            for (0..100) |_| {
                const mid = (lo + hi) / 2.0;
                if (self.cdf(mid) < p) {
                    lo = mid;
                } else {
                    hi = mid;
                }
            }
            return (lo + hi) / 2.0;
        }

        // --- Moments ---

        /// Mean: α/(β-1) for β > 1; NaN otherwise.
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            if (self.beta_param <= 1.0) return math.nan(T);
            return self.alpha / (self.beta_param - 1.0);
        }

        /// Variance: α(α+β-1)/((β-1)²(β-2)) for β > 2; NaN otherwise.
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            if (self.beta_param <= 2.0) return math.nan(T);
            const bm1 = self.beta_param - 1.0;
            return self.alpha * (self.alpha + self.beta_param - 1.0) /
                (bm1 * bm1 * (self.beta_param - 2.0));
        }

        /// Mode: (α-1)/(β+1) for α > 1; 0 for α ≤ 1 (PDF peaks at boundary x=0+).
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            if (self.alpha <= 1.0) return 0.0;
            return (self.alpha - 1.0) / (self.beta_param + 1.0);
        }

        // --- Entropy ---

        /// Entropy: ln B(α,β) − (α-1)·ψ(α) − (β+1)·ψ(β) + (α+β)·ψ(α+β)
        /// where ψ is the digamma function and B is the beta function.
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            const log_b = logBeta(self.alpha, self.beta_param);
            const psi_a = digamma(T, self.alpha);
            const psi_b = digamma(T, self.beta_param);
            const psi_ab = digamma(T, self.alpha + self.beta_param);
            return log_b -
                (self.alpha - 1.0) * psi_a -
                (self.beta_param + 1.0) * psi_b +
                (self.alpha + self.beta_param) * psi_ab;
        }

        // --- Sampling ---

        /// Sample via X = G₁/G₂ where G₁~Gamma(α,1), G₂~Gamma(β,1).
        /// Time: O(1) expected | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const g1 = Gamma(T){ .shape = self.alpha, .rate = 1.0 };
            const g2 = Gamma(T){ .shape = self.beta_param, .rate = 1.0 };
            return g1.sample(rng) / g2.sample(rng);
        }
    };
}

// ============================================================================
// BetaPrime(α, β) Tests
// ============================================================================
//
// BetaPrime(α, β): inverted Beta; X = Y/(1-Y) where Y ~ Beta(α, β)
// Support: x > 0; all PDF/CDF values 0 for x ≤ 0
//
// Key values (verified analytically):
//   BetaPrime(1,1): pdf(x) = 1/(1+x)², cdf(x) = x/(1+x), entropy = 2
//   BetaPrime(2,2): pdf(1) = 6/16 = 0.375, cdf(1) = 0.5, mean = 2, mode = 1/3
//   BetaPrime(2,3): pdf(1) = 0.375, cdf(1) = 0.6875, mean = 1, var = 2, mode = 0.25
//   BetaPrime(1,2): entropy = −ln(2) + 1.5 ≈ 0.80685
//   BetaPrime(3,4): mean = 1, var = 1, mode = 0.4
//

// --- init tests ---

test "BetaPrime: init with alpha=2, beta=2" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expectEqual(@as(f64, 2.0), dist.alpha);
    try testing.expectEqual(@as(f64, 2.0), dist.beta_param);
}

test "BetaPrime: init with alpha=1, beta=1 (standard inverted Pareto)" {
    const dist = try BetaPrime(f64).init(1.0, 1.0);
    try testing.expectEqual(@as(f64, 1.0), dist.alpha);
    try testing.expectEqual(@as(f64, 1.0), dist.beta_param);
}

test "BetaPrime: init with fractional params" {
    const dist = try BetaPrime(f64).init(0.5, 0.5);
    try testing.expectEqual(@as(f64, 0.5), dist.alpha);
    try testing.expectEqual(@as(f64, 0.5), dist.beta_param);
}

test "BetaPrime: init fails when alpha=0" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(0.0, 1.0));
}

test "BetaPrime: init fails when alpha is negative" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(-1.0, 1.0));
}

test "BetaPrime: init fails when beta=0" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(1.0, 0.0));
}

test "BetaPrime: init fails when beta is negative" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(1.0, -2.0));
}

test "BetaPrime: init fails when alpha is NaN" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(math.nan(f64), 1.0));
}

test "BetaPrime: init fails when beta is NaN" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(1.0, math.nan(f64)));
}

test "BetaPrime: init fails when alpha is infinite" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(math.inf(f64), 1.0));
}

test "BetaPrime: init fails when beta is infinite" {
    try testing.expectError(error.InvalidParameter, BetaPrime(f64).init(1.0, math.inf(f64)));
}

// --- validate tests ---

test "BetaPrime: validate passes for valid parameters" {
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    try dist.validate();
}

test "BetaPrime: validate fails after manually setting alpha to 0" {
    var dist = try BetaPrime(f64).init(2.0, 3.0);
    dist.alpha = 0.0;
    try testing.expectError(error.InvalidParameter, dist.validate());
}

test "BetaPrime: validate fails after manually setting beta to negative" {
    var dist = try BetaPrime(f64).init(2.0, 3.0);
    dist.beta_param = -1.0;
    try testing.expectError(error.InvalidParameter, dist.validate());
}

test "BetaPrime: validate fails after manually setting alpha to NaN" {
    var dist = try BetaPrime(f64).init(2.0, 3.0);
    dist.alpha = math.nan(f64);
    try testing.expectError(error.InvalidParameter, dist.validate());
}

// --- logpdf tests ---

test "BetaPrime: logpdf returns -inf for x=0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expect(math.isNegativeInf(dist.logpdf(0.0)));
}

test "BetaPrime: logpdf returns -inf for x < 0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expect(math.isNegativeInf(dist.logpdf(-1.0)));
}

test "BetaPrime: logpdf is finite for x > 0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expect(math.isFinite(dist.logpdf(1.0)));
}

test "BetaPrime: logpdf equals log(pdf) for x > 0" {
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    const x = 1.5;
    try testing.expectApproxEqAbs(@log(dist.pdf(x)), dist.logpdf(x), 1e-10);
}

// --- pdf tests ---

test "BetaPrime: pdf returns 0 for x=0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expectEqual(@as(f64, 0.0), dist.pdf(0.0));
}

test "BetaPrime: pdf returns 0 for x < 0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expectEqual(@as(f64, 0.0), dist.pdf(-0.5));
}

test "BetaPrime: pdf is positive for x > 0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    for ([_]f64{ 0.1, 0.5, 1.0, 2.0, 10.0 }) |x| {
        try testing.expect(dist.pdf(x) > 0.0);
    }
}

test "BetaPrime(1,1): pdf(x) = 1/(1+x)^2" {
    // BetaPrime(1,1): f(x) = x^0*(1+x)^(-2)/B(1,1) = 1/(1+x)^2 since B(1,1)=1
    const dist = try BetaPrime(f64).init(1.0, 1.0);
    const x = 2.0;
    const expected = 1.0 / ((1.0 + x) * (1.0 + x));
    try testing.expectApproxEqAbs(expected, dist.pdf(x), 1e-10);
}

test "BetaPrime(1,1): pdf(1) = 0.25" {
    const dist = try BetaPrime(f64).init(1.0, 1.0);
    try testing.expectApproxEqAbs(0.25, dist.pdf(1.0), 1e-10);
}

test "BetaPrime(2,2): pdf(1) = 0.375" {
    // B(2,2) = 1/6; f(1) = 1*(1+1)^(-4)/(1/6) = (1/16)*6 = 0.375
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expectApproxEqAbs(0.375, dist.pdf(1.0), 1e-10);
}

test "BetaPrime(2,3): pdf(1) = 0.375" {
    // B(2,3) = 1/12; f(1) = 1*(1+1)^(-5)/(1/12) = (1/32)*12 = 0.375
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    try testing.expectApproxEqAbs(0.375, dist.pdf(1.0), 1e-8);
}

test "BetaPrime: pdf integrates to approximately 1 (quadrature check)" {
    // Use trapezoidal rule over [0.001, 50] as a sanity check
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    var sum: f64 = 0.0;
    const n = 10000;
    const lo: f64 = 0.001;
    const hi: f64 = 50.0;
    const h = (hi - lo) / @as(f64, n);
    var i: usize = 0;
    while (i <= n) : (i += 1) {
        const x = lo + @as(f64, @floatFromInt(i)) * h;
        const w: f64 = if (i == 0 or i == n) 0.5 else 1.0;
        sum += w * dist.pdf(x) * h;
    }
    // Should be close to 1 (small error from tail truncation)
    try testing.expectApproxEqAbs(1.0, sum, 0.01);
}

test "BetaPrime: pdf unimodal — mode is a local maximum for alpha > 1" {
    const dist = try BetaPrime(f64).init(3.0, 4.0);
    const m = dist.mode(); // (3-1)/(4+1) = 0.4
    try testing.expect(dist.pdf(m) > dist.pdf(m - 0.1));
    try testing.expect(dist.pdf(m) > dist.pdf(m + 0.1));
}

// --- cdf tests ---

test "BetaPrime: cdf returns 0 for x=0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expectEqual(@as(f64, 0.0), dist.cdf(0.0));
}

test "BetaPrime: cdf returns 0 for x < 0" {
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expectEqual(@as(f64, 0.0), dist.cdf(-1.0));
}

test "BetaPrime(1,1): cdf(x) = x/(1+x)" {
    // I(t;1,1) = t (uniform), and t = x/(1+x), so CDF = x/(1+x)
    const dist = try BetaPrime(f64).init(1.0, 1.0);
    for ([_]f64{ 0.5, 1.0, 2.0, 4.0 }) |x| {
        const expected = x / (1.0 + x);
        try testing.expectApproxEqAbs(expected, dist.cdf(x), 1e-8);
    }
}

test "BetaPrime(1,1): cdf(1) = 0.5 (median at 1)" {
    const dist = try BetaPrime(f64).init(1.0, 1.0);
    try testing.expectApproxEqAbs(0.5, dist.cdf(1.0), 1e-8);
}

test "BetaPrime(2,2): cdf(1) = 0.5 (median at 1 by symmetry)" {
    // Beta(2,2) is symmetric around 0.5, so CDF(0.5) = 0.5
    // t = x/(1+x) = 1/2 when x=1, so CDF_BetaPrime(1) = I(0.5; 2,2) = 0.5
    const dist = try BetaPrime(f64).init(2.0, 2.0);
    try testing.expectApproxEqAbs(0.5, dist.cdf(1.0), 1e-8);
}

test "BetaPrime(2,3): cdf(1) = 0.6875" {
    // I(0.5; 2, 3) = 6*(0.5)^2*(0.5)^2 + 4*(0.5)^3*(0.5) + (0.5)^4 = 0.375+0.25+0.0625 = 0.6875
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    try testing.expectApproxEqAbs(0.6875, dist.cdf(1.0), 1e-6);
}

test "BetaPrime: cdf is monotone increasing" {
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    const xs = [_]f64{ 0.1, 0.5, 1.0, 2.0, 5.0 };
    for (0..xs.len - 1) |i| {
        try testing.expect(dist.cdf(xs[i]) < dist.cdf(xs[i + 1]));
    }
}

test "BetaPrime: cdf approaches 1 for large x" {
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    try testing.expect(dist.cdf(1000.0) > 0.9999);
}

test "BetaPrime: cdf + sf = 1 for x > 0" {
    const dist = try BetaPrime(f64).init(2.0, 3.0);
    const x = 1.5;
    try testing.expectApproxEqAbs(1.0, dist.cdf(x) + dist.sf(x), 1e-10);
}

