    try testing.expectEqual(@as(f64, 0.0), dist.mode());
}

test "BetaPrime: mode returns 0 for alpha = 1 (monotone decreasing PDF)" {
    const dist = try BetaPrime(f64).init(1.0, 2.0);
    try testing.expectEqual(@as(f64, 0.0), dist.mode());
}

test "BetaPrime(2,2): mode = 1/3" {
