    const dist = try BetaPrime(f64).init(3.0, 4.0);
    try testing.expectApproxEqAbs(0.4, dist.mode(), 1e-10);
}

test "BetaPrime: mode < mean for alpha > 1, beta > 1 (right-skewed)" {
