test "TruncatedNormal: quantile round-trip cdf(quantile(p)) ≈ p" {
    const dist = try TruncatedNormal(f64).init(0.0, 1.0, -1.0, 1.0);
    const p_vals = [_]f64{ 0.1, 0.25, 0.5, 0.75, 0.9 };
