test "Arcsine: pdf is U-shaped (minimum at center)" {
    const dist = try Arcsine(f64).init(0.0, 1.0);
    const p_quarter = dist.pdf(0.25);
    const p_center = dist.pdf(0.5);
    const p_three_quarter = dist.pdf(0.75);
