    // Entropy = ln(s) + 2, can be negative when s < exp(-2) ≈ 0.1353
    const dist_small = try Logistic(f64).init(0.0, 0.1);
    try testing.expectApproxEqAbs(@log(0.1) + 2.0, dist_small.entropy(), 1e-12);
