}

// ============================================================================
// InverseGamma Distribution
// ============================================================================
// InverseGamma(α, β): if X ~ InverseGamma(α, β), then 1/X ~ Gamma(α, rate=β).
// Conjugate prior for the variance of a Normal distribution in Bayesian analysis.
//
// Parameters: α > 0 (shape), β > 0 (scale)
// Support: x ∈ (0, ∞)
// PDF: (β^α / Γ(α)) · x^(-α-1) · exp(-β/x)
// CDF: 1 - P(α, β/x) where P is the regularized lower incomplete gamma
// Mean: β/(α-1) for α > 1, else undefined
// Variance: β²/((α-1)²(α-2)) for α > 2, else undefined
// Mode: β/(α+1)
// Entropy: α + ln(β) + logΓ(α) - (1+α)·ψ(α)

pub fn InverseGamma(comptime T: type) type {
    return struct {
        alpha: T, // shape α > 0
        beta: T, // scale β > 0

        const Self = @This();

        /// Create an InverseGamma distribution with shape α and scale β.
        ///
        /// Errors: α ≤ 0, β ≤ 0, or non-finite parameters.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(alpha: T, beta: T) DistributionError!Self {
            if (alpha <= 0.0 or !math.isFinite(alpha)) return error.InvalidParameter;
            if (beta <= 0.0 or !math.isFinite(beta)) return error.InvalidParameter;
            return Self{ .alpha = alpha, .beta = beta };
        }

        /// Probability density function (PDF) at x
        ///
        /// f(x; α, β) = (β^α / Γ(α)) · x^(-α-1) · exp(-β/x) for x > 0; 0 otherwise
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            return @exp(self.logpdf(x));
        }

        /// Log probability density function (log PDF) at x
        ///
        /// log f(x) = α·ln(β) - logΓ(α) - (α+1)·ln(x) - β/x; -∞ for x ≤ 0
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= 0.0) return -math.inf(T);
            return self.alpha * @log(self.beta) - logGamma(self.alpha) - (self.alpha + 1.0) * @log(x) - self.beta / x;
        }

        /// Cumulative distribution function (CDF) at x
        ///
        /// F(x; α, β) = 1 - P(α, β/x) where P is the regularized lower incomplete gamma; 0 for x ≤ 0
        ///
        /// Time: O(1) with series/CF approximation | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            return 1.0 - regularizedGammaP(self.alpha, self.beta / x);
        }

        /// Survival function (SF) at x: P(X > x)
        ///
        /// S(x; α, β) = P(α, β/x) where P is the regularized lower incomplete gamma; 1 for x ≤ 0
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            if (x <= 0.0) return 1.0;
            return regularizedGammaP(self.alpha, self.beta / x);
        }

        /// Quantile function (inverse CDF): returns x such that P(X ≤ x) = p
        ///
        /// Uses bisection on the CDF (no closed form exists).
        ///
        /// Errors: p < 0 or p > 1
        ///
        /// Time: O(log(1/ε)) for tolerance ε | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return math.inf(T);

            // Start from mode as initial upper bracket
            var low: T = 0.0;
            var high: T = self.beta / (self.alpha + 1.0); // mode

            // Expand upper bracket until CDF(high) >= p
            while (self.cdf(high) < p) {
                high *= 2.0;
                if (!math.isFinite(high)) return math.inf(T);
            }

            const tolerance: T = 1e-10;
            const max_iter = 100;
            var iter: usize = 0;
            while (iter < max_iter) : (iter += 1) {
                const mid = (low + high) / 2.0;
                if (mid <= 0.0) break;
                const cdf_mid = self.cdf(mid);
                if (@abs(cdf_mid - p) < tolerance) return mid;
                if (cdf_mid < p) {
                    low = mid;
                } else {
                    high = mid;
                }
                if (high - low < tolerance) return (low + high) / 2.0;
            }
            return (low + high) / 2.0;
        }

        /// Mode of the distribution: β / (α + 1)
        ///
        /// The peak of the PDF, always less than the mean for α > 1.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            return self.beta / (self.alpha + 1.0);
        }

        /// Median of the distribution (no closed form, computed via quantile(0.5))
        ///
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn median(self: Self) DistributionError!T {
            return self.quantile(0.5);
        }

        /// Mean (expected value) of the distribution
        ///
        /// E[X] = β / (α - 1) for α > 1, else NaN (undefined)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            if (self.alpha <= 1.0) return math.nan(T);
            return self.beta / (self.alpha - 1.0);
        }

        /// Variance of the distribution
        ///
        /// Var[X] = β² / ((α-1)² · (α-2)) for α > 2, else NaN (undefined)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            if (self.alpha <= 2.0) return math.nan(T);
            const a_minus_1 = self.alpha - 1.0;
            return (self.beta * self.beta) / (a_minus_1 * a_minus_1 * (self.alpha - 2.0));
        }

        /// Differential entropy: α + ln(β) + logΓ(α) - (1+α)·ψ(α)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            return self.alpha + @log(self.beta) + logGamma(self.alpha) - (1.0 + self.alpha) * digamma(T, self.alpha);
        }

        /// Generate a random sample from this distribution
        ///
        /// Uses inverse sampling: X = 1/Y where Y ~ Gamma(α, rate=β).
        /// Marsaglia-Tsang algorithm for Y, with boost trick for α < 1.
        ///
        /// Time: O(1) expected | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            // Generate Y ~ Gamma(alpha, rate=beta) using Marsaglia-Tsang (works for alpha >= 1).
            // For alpha < 1, use boost: generate Gamma(alpha+1), then multiply by U^(1/alpha).
            const alpha_mt = if (self.alpha >= 1.0) self.alpha else self.alpha + 1.0;
            const d = alpha_mt - 1.0 / 3.0;
            const c = 1.0 / @sqrt(9.0 * d);

            var gamma_val: T = undefined;
            while (true) {
                var z: T = undefined;
                var v: T = undefined;
                while (true) {
                    const ra = rng.float(T);
                    const rb = rng.float(T);
                    z = @sqrt(-2.0 * @log(ra)) * @cos(2.0 * math.pi * rb);
                    v = 1.0 + c * z;
                    if (v > 0.0) break;
                }
                v = v * v * v;
                const rc = rng.float(T);
                if (rc < 1.0 - 0.0331 * z * z * z * z) {
                    gamma_val = d * v / self.beta;
                    break;
                }
                if (@log(rc) < 0.5 * z * z + d * (1.0 - v + @log(v))) {
                    gamma_val = d * v / self.beta;
                    break;
                }
            }

            // Boost trick for alpha < 1: X = Y · U^(1/alpha) where Y ~ Gamma(alpha+1)
            if (self.alpha < 1.0) {
                const rb = rng.float(T);
                gamma_val *= std.math.pow(T, rb, 1.0 / self.alpha);
            }

            return 1.0 / gamma_val;
        }

        /// Validate distribution parameters
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (self.alpha <= 0.0 or !math.isFinite(self.alpha)) return error.InvalidParameter;
            if (self.beta <= 0.0 or !math.isFinite(self.beta)) return error.InvalidParameter;
        }

        /// Validate that x is in the support (0, ∞)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validateValue(self: Self, x: T) DistributionError!void {
            _ = self;
            if (x <= 0.0 or !math.isFinite(x)) return error.OutOfDomain;
        }
    };
}

test "InverseGamma: init validation" {
    _ = try InverseGamma(f64).init(3.0, 1.0);
    _ = try InverseGamma(f64).init(0.5, 2.0);
    _ = try InverseGamma(f64).init(1.0, 1.0);
    try expectError(error.InvalidParameter, InverseGamma(f64).init(0.0, 1.0));
    try expectError(error.InvalidParameter, InverseGamma(f64).init(-1.0, 1.0));
    try expectError(error.InvalidParameter, InverseGamma(f64).init(1.0, 0.0));
    try expectError(error.InvalidParameter, InverseGamma(f64).init(1.0, -1.0));
    try expectError(error.InvalidParameter, InverseGamma(f64).init(math.nan(f64), 1.0));
    try expectError(error.InvalidParameter, InverseGamma(f64).init(1.0, math.nan(f64)));
    try expectError(error.InvalidParameter, InverseGamma(f64).init(math.inf(f64), 1.0));
    try expectError(error.InvalidParameter, InverseGamma(f64).init(1.0, math.inf(f64)));
}

test "InverseGamma: pdf exact values for simple cases" {
    // InverseGamma(1, 1): PDF(x) = x^(-2) · exp(-1/x); PDF(1) = e^(-1)
    const dist_1_1 = try InverseGamma(f64).init(1.0, 1.0);
    try expectApproxEqAbs(@exp(-1.0), dist_1_1.pdf(1.0), 1e-12);

    // InverseGamma(3, 1): PDF(x) = (1/2) · x^(-4) · exp(-1/x); PDF(1) = e^(-1)/2
    const dist_3_1 = try InverseGamma(f64).init(3.0, 1.0);
    try expectApproxEqAbs(@exp(-1.0) / 2.0, dist_3_1.pdf(1.0), 1e-12);
}

test "InverseGamma: pdf positive on support" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0, 100.0 };
    for (x_vals) |x| {
        try testing.expect(dist.pdf(x) > 0.0);
    }
}

test "InverseGamma: pdf zero for non-positive x" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    try testing.expect(dist.pdf(0.0) == 0.0);
    try testing.expect(dist.pdf(-1.0) == 0.0);
}

test "InverseGamma: pdf integrates to approximately 1" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    var sum: f64 = 0.0;
    const dx = 0.001;
    var x: f64 = 0.001;
    while (x < 20.0) : (x += dx) {
        sum += dist.pdf(x) * dx;
    }
    try expectApproxEqAbs(1.0, sum, 0.02);
}

test "InverseGamma: logpdf exact values" {
    // InverseGamma(1, 1): logpdf(1) = -1
    const dist_1_1 = try InverseGamma(f64).init(1.0, 1.0);
    try expectApproxEqAbs(-1.0, dist_1_1.logpdf(1.0), 1e-12);

    // InverseGamma(3, 1): logpdf(1) = -1 - ln(2)
    const dist_3_1 = try InverseGamma(f64).init(3.0, 1.0);
    try expectApproxEqAbs(-1.0 - @log(2.0), dist_3_1.logpdf(1.0), 1e-12);
}

test "InverseGamma: logpdf minus inf for non-positive x" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    try testing.expect(math.isNegativeInf(dist.logpdf(0.0)));
    try testing.expect(math.isNegativeInf(dist.logpdf(-1.0)));
}

test "InverseGamma: logpdf equals log(pdf)" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const x_vals = [_]f64{ 0.1, 0.5, 1.0, 2.0, 5.0 };
    for (x_vals) |x| {
        try expectApproxEqAbs(@log(dist.pdf(x)), dist.logpdf(x), 1e-12);
    }
}

test "InverseGamma: cdf monotone and bounded" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    try testing.expect(dist.cdf(0.0) == 0.0);
    try testing.expect(dist.cdf(1e6) > 0.9999);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    var prev = dist.cdf(x_vals[0]);
    for (x_vals[1..]) |x| {
        const c = dist.cdf(x);
        try testing.expect(c >= prev);
        prev = c;
    }
}

test "InverseGamma: cdf exact value for InverseGamma(1,1)" {
    // InverseGamma(1, 1): CDF(x) = e^(-1/x); CDF(1) = e^(-1)
    const dist = try InverseGamma(f64).init(1.0, 1.0);
    try expectApproxEqAbs(@exp(-1.0), dist.cdf(1.0), 1e-10);
}

test "InverseGamma: cdf in [0, 1]" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const x_vals = [_]f64{ 1e-6, 0.01, 0.1, 1.0, 10.0, 1e6 };
    for (x_vals) |x| {
        const c = dist.cdf(x);
        try testing.expect(c >= 0.0);
        try testing.expect(c <= 1.0);
    }
}

test "InverseGamma: sf = 1 - cdf" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    for (x_vals) |x| {
        try expectApproxEqAbs(1.0, dist.cdf(x) + dist.sf(x), 1e-12);
    }
}

test "InverseGamma: quantile roundtrip cdf(quantile(p)) = p" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const probs = [_]f64{ 0.1, 0.25, 0.5, 0.75, 0.9 };
    for (probs) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-8);
    }
}

test "InverseGamma: quantile roundtrip quantile(cdf(x)) = x" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const x_vals = [_]f64{ 0.1, 0.25, 0.5, 1.0, 2.0, 5.0 };
    for (x_vals) |x| {
        const q = try dist.quantile(dist.cdf(x));
        try expectApproxEqAbs(x, q, 1e-7);
    }
}

test "InverseGamma: quantile boundary cases" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    try testing.expect((try dist.quantile(0.0)) == 0.0);
    try testing.expect(math.isInf(try dist.quantile(1.0)));
    // Near-boundary: very small quantile should be positive and much less than mode
    const q_small = try dist.quantile(0.0001);
    try testing.expect(q_small > 0.0 and q_small < 0.2); // mode=0.25 for InverseGamma(3,1)
    const q_large = try dist.quantile(0.9999);
    try testing.expect(q_large > 10.0);
}

test "InverseGamma: quantile rejects invalid probabilities" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    try expectError(error.InvalidProbability, dist.quantile(-0.1));
    try expectError(error.InvalidProbability, dist.quantile(1.1));
    try expectError(error.InvalidProbability, dist.quantile(math.nan(f64)));
}

test "InverseGamma: mode formula" {
    // mode = β / (α + 1)
    const dist_3_1 = try InverseGamma(f64).init(3.0, 1.0);
    try expectApproxEqAbs(0.25, dist_3_1.mode(), 1e-12);

    const dist_1_1 = try InverseGamma(f64).init(1.0, 1.0);
    try expectApproxEqAbs(0.5, dist_1_1.mode(), 1e-12);

    const dist_5_2 = try InverseGamma(f64).init(5.0, 2.0);
    try expectApproxEqAbs(1.0 / 3.0, dist_5_2.mode(), 1e-12);
}

test "InverseGamma: mode is PDF peak" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const m = dist.mode();
    const dx = 0.001;
    try testing.expect(dist.pdf(m) > dist.pdf(m - dx));
    try testing.expect(dist.pdf(m) > dist.pdf(m + dx));
}

test "InverseGamma: mean defined only for alpha > 1" {
    // mean = β / (α - 1)
    const dist_3_1 = try InverseGamma(f64).init(3.0, 1.0);
    try expectApproxEqAbs(0.5, dist_3_1.mean(), 1e-12);

    const dist_5_2 = try InverseGamma(f64).init(5.0, 2.0);
    try expectApproxEqAbs(0.5, dist_5_2.mean(), 1e-12);

    const dist_1_1 = try InverseGamma(f64).init(1.0, 1.0);
    try testing.expect(math.isNan(dist_1_1.mean()));

    const dist_0_5 = try InverseGamma(f64).init(0.5, 2.0);
    try testing.expect(math.isNan(dist_0_5.mean()));
}

test "InverseGamma: variance defined only for alpha > 2" {
    // variance = β² / ((α-1)² · (α-2))
    const dist_3_1 = try InverseGamma(f64).init(3.0, 1.0);
    try expectApproxEqAbs(0.25, dist_3_1.variance(), 1e-12);

    const dist_5_2 = try InverseGamma(f64).init(5.0, 2.0);
    try expectApproxEqAbs(1.0 / 12.0, dist_5_2.variance(), 1e-12);

    const dist_2_1 = try InverseGamma(f64).init(2.0, 1.0);
    try testing.expect(math.isNan(dist_2_1.variance()));

    const dist_1_5 = try InverseGamma(f64).init(1.5, 1.0);
    try testing.expect(math.isNan(dist_1_5.variance()));
}

test "InverseGamma: right-skewed — mode < median < mean" {
    const dist = try InverseGamma(f64).init(5.0, 2.0);
    const m = dist.mode();
    const med = try dist.median();
    const mn = dist.mean();
    try testing.expect(m < med);
    try testing.expect(med < mn);
}

test "InverseGamma: entropy is finite and increases with beta" {
    const dist_1 = try InverseGamma(f64).init(3.0, 1.0);
    const dist_2 = try InverseGamma(f64).init(3.0, 2.0);
    const dist_3 = try InverseGamma(f64).init(3.0, 3.0);
    try testing.expect(math.isFinite(dist_1.entropy()));
    try testing.expect(dist_2.entropy() > dist_1.entropy());
    try testing.expect(dist_3.entropy() > dist_2.entropy());
}

test "InverseGamma: entropy formula spot check" {
    // For InverseGamma(3, 1): entropy = 3 + ln(1) + ln(Γ(3)) - 4·ψ(3)
    //   = 3 + 0 + ln(2) - 4·(1.5 - γ_E)  where γ_E ≈ 0.5772156649
    //   ψ(3) = ψ(1) + 1 + 1/2 = -γ_E + 1 + 0.5 = 1.5 - γ_E ≈ 0.9227843
    //   entropy ≈ 3 + 0.6931 - 4*0.9228 ≈ 3 + 0.6931 - 3.6911 ≈ 0.002
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const gamma_e = 0.5772156649015329;
    const psi_3 = 1.5 - gamma_e;
    const expected = 3.0 + 0.0 + @log(2.0) - 4.0 * psi_3;
    try expectApproxEqAbs(expected, dist.entropy(), 1e-7);
}

test "InverseGamma: sample is positive and finite" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..1000) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "InverseGamma: empirical sample mean converges to theoretical" {
    // InverseGamma(5, 2): mean = 2/4 = 0.5
    const dist = try InverseGamma(f64).init(5.0, 2.0);
    var rng = std.Random.DefaultPrng.init(42);
    var sum: f64 = 0.0;
    const n = 50000;
    for (0..n) |_| {
        sum += dist.sample(rng.random());
    }
    const empirical = sum / @as(f64, @floatFromInt(n));
    try expectApproxEqAbs(0.5, empirical, 0.05);
}

test "InverseGamma: sample also works for alpha < 1" {
    const dist = try InverseGamma(f64).init(0.5, 1.0);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..200) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "InverseGamma: validate passes for valid params" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    try dist.validate();
}

test "InverseGamma: validateValue rejects non-positive and non-finite x" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    try expectError(error.OutOfDomain, dist.validateValue(0.0));
    try expectError(error.OutOfDomain, dist.validateValue(-1.0));
    try expectError(error.OutOfDomain, dist.validateValue(math.nan(f64)));
    try expectError(error.OutOfDomain, dist.validateValue(math.inf(f64)));
}

test "InverseGamma: validateValue accepts positive finite x" {
    const dist = try InverseGamma(f64).init(3.0, 1.0);
    const x_vals = [_]f64{ 1e-6, 0.01, 0.1, 1.0, 10.0, 1e6 };
    for (x_vals) |x| {
        try dist.validateValue(x);
    }
}

test "InverseGamma: f32 support" {
    const dist = try InverseGamma(f32).init(3.0, 1.0);
    try expectApproxEqAbs(0.25, dist.mode(), 1e-5);
    try expectApproxEqAbs(0.5, dist.mean(), 1e-5);
    try expectApproxEqAbs(0.25, dist.variance(), 1e-5);
    try testing.expect(dist.pdf(1.0) > 0.0);
    const c = dist.cdf(1.0);
    try testing.expect(c > 0.0 and c < 1.0);
    const q = try dist.quantile(0.5);
    try testing.expect(q > 0.0);
}

test "InverseGamma: f32 quantile roundtrip" {
    const dist = try InverseGamma(f32).init(5.0, 2.0);
    const probs = [_]f32{ 0.1, 0.5, 0.9 };
    for (probs) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-5);
    }
}

test "InverseGamma: scaling beta scales mode and mean" {
    const dist_1 = try InverseGamma(f64).init(3.0, 1.0);
    const dist_2 = try InverseGamma(f64).init(3.0, 2.0);
    // mode = β/(α+1): doubling β doubles mode
    try expectApproxEqAbs(2.0 * dist_1.mode(), dist_2.mode(), 1e-12);
    // mean = β/(α-1): doubling β doubles mean
    try expectApproxEqAbs(2.0 * dist_1.mean(), dist_2.mean(), 1e-12);
}

test "InverseGamma: increasing alpha tightens distribution" {
    const dist_small = try InverseGamma(f64).init(3.0, 1.0);
    const dist_large = try InverseGamma(f64).init(100.0, 1.0);
    // Variance decreases with alpha
    try testing.expect(dist_small.variance() > dist_large.variance());
    // mode = β/(α+1) decreases with alpha (for fixed β)
    try testing.expect(dist_small.mode() > dist_large.mode());
}

test "InverseGamma: cdf(mode) < 0.5 (right-skewed distribution)" {
    const dist = try InverseGamma(f64).init(5.0, 2.0);
    try testing.expect(dist.cdf(dist.mode()) < 0.5);
}

/// Chi(k) distribution — generalization of Rayleigh, HalfNormal, and Maxwell-Boltzmann.
///
/// X ~ Chi(k) ⟺ X = √(X₁² + ... + Xₖ²), Xᵢ ~ N(0,1) i.i.d.
/// Equivalently, X = √Y where Y ~ ChiSquared(k) = Gamma(k/2, rate=0.5).
///
/// Parameter: k > 0 (degrees of freedom, continuous)
/// Support: [0, ∞)
pub fn Chi(comptime T: type) type {
    return struct {
        k: T, // degrees of freedom, k > 0

        const Self = @This();

        /// Create a Chi distribution with k degrees of freedom.
        ///
        /// Errors: k ≤ 0, NaN, or infinite k.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(k: T) DistributionError!Self {
            if (k <= 0.0 or !math.isFinite(k)) return error.InvalidParameter;
            return Self{ .k = k };
        }

        /// Probability density function (PDF) at x
        ///
        /// f(x; k) = 2^(1-k/2) · x^(k-1) · exp(-x²/2) / Γ(k/2)  for x > 0; 0 otherwise
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            return @exp(self.logpdf(x));
        }

        /// Log probability density function (log PDF) at x
        ///
        /// log f(x) = (1-k/2)·ln(2) + (k-1)·ln(x) - x²/2 - logΓ(k/2); -∞ for x ≤ 0
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= 0.0) return -math.inf(T);
            return (1.0 - self.k / 2.0) * @log(2.0) + (self.k - 1.0) * @log(x) - x * x / 2.0 - logGamma(self.k / 2.0);
        }

        /// Cumulative distribution function (CDF) at x
        ///
        /// F(x; k) = P(k/2, x²/2)  where P is the regularized lower incomplete gamma; 0 for x ≤ 0
        ///
        /// Time: O(1) with series/CF approximation | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            return regularizedGammaP(self.k / 2.0, x * x / 2.0);
        }

        /// Survival function (SF) at x: P(X > x)
        ///
        /// S(x; k) = 1 - P(k/2, x²/2); 1 for x ≤ 0
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            if (x <= 0.0) return 1.0;
            return 1.0 - self.cdf(x);
        }

        /// Quantile function (inverse CDF): returns x such that P(X ≤ x) = p
        ///
        /// Uses bisection on the CDF (no closed form exists).
        ///
        /// Errors: p < 0 or p > 1
        ///
        /// Time: O(log(1/ε)) for tolerance ε | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return math.inf(T);

            var low: T = 0.0;
            var high: T = @max(1.0, self.mode() + 1.0);

            while (self.cdf(high) < p) {
                high *= 2.0;
                if (!math.isFinite(high)) return math.inf(T);
            }

            const tolerance: T = 1e-10;
            const max_iter = 100;
            var iter: usize = 0;
            while (iter < max_iter) : (iter += 1) {
                const mid = (low + high) / 2.0;
                if (mid <= 0.0) break;
                const cdf_mid = self.cdf(mid);
                if (@abs(cdf_mid - p) < tolerance) return mid;
                if (cdf_mid < p) {
                    low = mid;
                } else {
                    high = mid;
                }
                if (high - low < tolerance) return (low + high) / 2.0;
            }
            return (low + high) / 2.0;
        }

        /// Mode of the distribution
        ///
        /// mode = √(k - 1) for k ≥ 1; 0 for k < 1
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            if (self.k < 1.0) return 0.0;
            return @sqrt(self.k - 1.0);
        }

        /// Median of the distribution (no closed form, computed via quantile(0.5))
        ///
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn median(self: Self) DistributionError!T {
            return self.quantile(0.5);
        }

        /// Mean (expected value) of the distribution
        ///
        /// E[X] = √2 · Γ((k+1)/2) / Γ(k/2)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            return @sqrt(2.0) * @exp(logGamma((self.k + 1.0) / 2.0) - logGamma(self.k / 2.0));
        }

        /// Variance of the distribution
        ///
        /// Var[X] = k - E[X]²
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            const mu = self.mean();
            return self.k - mu * mu;
        }

        /// Differential entropy
        ///
        /// H(X) = logΓ(k/2) + k/2 - ½·ln(2) - ((k-1)/2)·ψ(k/2)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            const half_k = self.k / 2.0;
            return logGamma(half_k) + half_k - 0.5 * @log(2.0) - (self.k - 1.0) / 2.0 * digamma(T, half_k);
        }

        /// Generate a random sample from this distribution
        ///
        /// Uses Chi²(k) = 2·Gamma(k/2, rate=1) via Marsaglia-Tsang, then Chi = sqrt(Chi²).
        /// Boost trick applied for k/2 < 1.
        ///
        /// Time: O(1) expected | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const half_k = self.k / 2.0;
            const alpha_mt = if (half_k >= 1.0) half_k else half_k + 1.0;
            const d = alpha_mt - 1.0 / 3.0;
            const c = 1.0 / @sqrt(9.0 * d);

            var gamma_val: T = undefined;
            while (true) {
                var z: T = undefined;
                var v: T = undefined;
                while (true) {
                    const ra = rng.float(T);
                    const rb = rng.float(T);
                    z = @sqrt(-2.0 * @log(ra)) * @cos(2.0 * math.pi * rb);
                    v = 1.0 + c * z;
                    if (v > 0.0) break;
                }
                v = v * v * v;
                const rc = rng.float(T);
                if (rc < 1.0 - 0.0331 * z * z * z * z) {
                    gamma_val = d * v;
                    break;
                }
                if (@log(rc) < 0.5 * z * z + d * (1.0 - v + @log(v))) {
                    gamma_val = d * v;
                    break;
                }
            }

            // Boost trick for half_k < 1: Y ~ Gamma(half_k+1) · U^(1/half_k)
            if (half_k < 1.0) {
                const rb = rng.float(T);
                gamma_val *= std.math.pow(T, rb, 1.0 / half_k);
            }

            // Chi²(k) = 2 * Gamma(k/2, rate=1); Chi(k) = sqrt(Chi²(k))
            return @sqrt(2.0 * gamma_val);
        }

        /// Validate distribution parameters
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (self.k <= 0.0 or !math.isFinite(self.k)) return error.InvalidParameter;
        }

        /// Validate that x is in the support (0, ∞)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validateValue(self: Self, x: T) DistributionError!void {
            _ = self;
            if (x <= 0.0 or !math.isFinite(x)) return error.OutOfDomain;
        }
    };
}

test "Chi: init validation" {
    _ = try Chi(f64).init(1.0);
    _ = try Chi(f64).init(2.0);
    _ = try Chi(f64).init(0.5);
    try expectError(error.InvalidParameter, Chi(f64).init(0.0));
    try expectError(error.InvalidParameter, Chi(f64).init(-1.0));
    try expectError(error.InvalidParameter, Chi(f64).init(-0.5));
    try expectError(error.InvalidParameter, Chi(f64).init(math.nan(f64)));
    try expectError(error.InvalidParameter, Chi(f64).init(math.inf(f64)));
    try expectError(error.InvalidParameter, Chi(f64).init(-math.inf(f64)));
}

test "Chi: pdf exact value Chi(1).pdf(1) = sqrt(2/π) * e^(-0.5)" {
    const dist = try Chi(f64).init(1.0);
    const expected = @sqrt(2.0 / math.pi) * @exp(-0.5);
    try expectApproxEqAbs(expected, dist.pdf(1.0), 1e-12);
}

test "Chi: pdf exact value Chi(2).pdf(1) = e^(-0.5)" {
    const dist = try Chi(f64).init(2.0);
    const expected = @exp(-0.5);
    try expectApproxEqAbs(expected, dist.pdf(1.0), 1e-12);
}

test "Chi: pdf exact value Chi(3).pdf(1) = sqrt(2/π) * e^(-0.5)" {
    const dist = try Chi(f64).init(3.0);
    const expected = @sqrt(2.0 / math.pi) * @exp(-0.5);
    try expectApproxEqAbs(expected, dist.pdf(1.0), 1e-12);
}

test "Chi: pdf positive on support" {
    const dist = try Chi(f64).init(3.0);
    // x=100 underflows exp(-x²/2) to 0 in float64 — test up to x=15
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0, 15.0 };
    for (x_vals) |x| {
        try testing.expect(dist.pdf(x) > 0.0);
    }
}

test "Chi: pdf zero for non-positive x" {
    const dist = try Chi(f64).init(3.0);
    try testing.expect(dist.pdf(0.0) == 0.0);
    try testing.expect(dist.pdf(-1.0) == 0.0);
    try testing.expect(dist.pdf(-0.01) == 0.0);
}

test "Chi: pdf integrates to approximately 1" {
    const dist = try Chi(f64).init(3.0);
    var sum: f64 = 0.0;
    const dx = 0.01;
    var x: f64 = 0.01;
    while (x < 20.0) : (x += dx) {
        sum += dist.pdf(x) * dx;
    }
    try expectApproxEqAbs(1.0, sum, 0.02);
}

test "Chi: logpdf exact values" {
    const dist_1 = try Chi(f64).init(1.0);
    const dist_2 = try Chi(f64).init(2.0);
    const dist_3 = try Chi(f64).init(3.0);

    // Chi(1).logpdf(1) = ln(sqrt(2/π)) - 0.5
    const log_pdf_1 = dist_1.logpdf(1.0);
    const expected_1 = 0.5 * @log(2.0 / math.pi) - 0.5;
    try expectApproxEqAbs(expected_1, log_pdf_1, 1e-12);

    // Chi(2).logpdf(1) = -0.5
    const log_pdf_2 = dist_2.logpdf(1.0);
    try expectApproxEqAbs(-0.5, log_pdf_2, 1e-12);

    // Chi(3).logpdf(1) = ln(sqrt(2/π)) - 0.5
    const log_pdf_3 = dist_3.logpdf(1.0);
    try expectApproxEqAbs(expected_1, log_pdf_3, 1e-12);
}

test "Chi: logpdf equals log(pdf)" {
    const dist = try Chi(f64).init(3.0);
    const x_vals = [_]f64{ 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    for (x_vals) |x| {
        try expectApproxEqAbs(@log(dist.pdf(x)), dist.logpdf(x), 1e-12);
    }
}

test "Chi: logpdf negative infinity for non-positive x" {
    const dist = try Chi(f64).init(3.0);
    try testing.expect(math.isNegativeInf(dist.logpdf(0.0)));
    try testing.expect(math.isNegativeInf(dist.logpdf(-1.0)));
}

test "Chi: cdf monotone and bounded" {
    const dist = try Chi(f64).init(3.0);
    try testing.expect(dist.cdf(0.0) == 0.0);
    try testing.expect(dist.cdf(1e6) > 0.9999);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0, 50.0 };
    var prev = dist.cdf(x_vals[0]);
    for (x_vals[1..]) |x| {
        const c = dist.cdf(x);
        try testing.expect(c >= prev);
        prev = c;
    }
}

test "Chi: cdf exact formula for Chi(2): 1 - e^(-x^2/2)" {
    const dist = try Chi(f64).init(2.0);
    const x_vals = [_]f64{ 0.5, 1.0, 1.5, 2.0, 3.0 };
    for (x_vals) |x| {
        const expected = 1.0 - @exp(-x * x / 2.0);
        // regularizedGammaP has ~1e-11 precision
        try expectApproxEqAbs(expected, dist.cdf(x), 1e-10);
    }
}

test "Chi: cdf in [0, 1]" {
    const dist = try Chi(f64).init(3.0);
    const x_vals = [_]f64{ 1e-6, 0.01, 0.1, 1.0, 10.0, 1e3 };
    for (x_vals) |x| {
        const c = dist.cdf(x);
        try testing.expect(c >= 0.0);
        try testing.expect(c <= 1.0);
    }
}

test "Chi: sf = 1 - cdf" {
    const dist = try Chi(f64).init(3.0);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    for (x_vals) |x| {
        try expectApproxEqAbs(1.0, dist.cdf(x) + dist.sf(x), 1e-12);
    }
}

test "Chi: quantile roundtrip cdf(quantile(p)) = p" {
    const dist = try Chi(f64).init(3.0);
    const probs = [_]f64{ 0.1, 0.25, 0.5, 0.75, 0.9 };
    for (probs) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-8);
    }
}

test "Chi: quantile roundtrip quantile(cdf(x)) = x" {
    const dist = try Chi(f64).init(3.0);
    // Exclude very large x where cdf(x) rounds to exactly 1.0 (quantile returns inf)
    const x_vals = [_]f64{ 0.1, 0.5, 1.0, 2.0, 5.0 };
    for (x_vals) |x| {
        const q = try dist.quantile(dist.cdf(x));
        try expectApproxEqAbs(x, q, 1e-7);
    }
}

test "Chi: quantile boundary cases" {
    const dist = try Chi(f64).init(3.0);
    try testing.expect((try dist.quantile(0.0)) == 0.0);
    try testing.expect(math.isInf(try dist.quantile(1.0)));
    // Near-boundary: very small quantile should be positive and small
    const q_small = try dist.quantile(0.0001);
    try testing.expect(q_small > 0.0 and q_small < 1.0);
    // Chi(3) 99.99th percentile ≈ sqrt(Chi²(3) at 0.9999) ≈ sqrt(18.5) ≈ 4.3
    const q_large = try dist.quantile(0.9999);
    try testing.expect(q_large > 3.0);
}

test "Chi: quantile rejects invalid probabilities" {
    const dist = try Chi(f64).init(3.0);
    try expectError(error.InvalidProbability, dist.quantile(-0.1));
    try expectError(error.InvalidProbability, dist.quantile(1.1));
    try expectError(error.InvalidProbability, dist.quantile(math.nan(f64)));
}

test "Chi: mode formula sqrt(k-1) for k >= 1" {
    // Chi(1): mode = 0
    const dist_1 = try Chi(f64).init(1.0);
    try expectApproxEqAbs(0.0, dist_1.mode(), 1e-12);

    // Chi(2): mode = 1
    const dist_2 = try Chi(f64).init(2.0);
    try expectApproxEqAbs(1.0, dist_2.mode(), 1e-12);

    // Chi(5): mode = 2
    const dist_5 = try Chi(f64).init(5.0);
    try expectApproxEqAbs(2.0, dist_5.mode(), 1e-12);
}

test "Chi: mode is zero for k < 1" {
    const dist = try Chi(f64).init(0.5);
    try expectApproxEqAbs(0.0, dist.mode(), 1e-12);
}

test "Chi: mode is PDF peak" {
    const dist = try Chi(f64).init(5.0);
    const m = dist.mode();
    const dx = 0.001;
    try testing.expect(dist.pdf(m) > dist.pdf(m - dx));
    try testing.expect(dist.pdf(m) > dist.pdf(m + dx));
}

test "Chi: mean exact values" {
    // Chi(1).mean() = sqrt(2/π)
    const dist_1 = try Chi(f64).init(1.0);
    const expected_1 = @sqrt(2.0 / math.pi);
    try expectApproxEqAbs(expected_1, dist_1.mean(), 1e-12);

    // Chi(2).mean() = sqrt(π/2)
    const dist_2 = try Chi(f64).init(2.0);
    const expected_2 = @sqrt(math.pi / 2.0);
    try expectApproxEqAbs(expected_2, dist_2.mean(), 1e-12);

    // Chi(3).mean() = 2 * sqrt(2/π)
    const dist_3 = try Chi(f64).init(3.0);
    const expected_3 = 2.0 * @sqrt(2.0 / math.pi);
    try expectApproxEqAbs(expected_3, dist_3.mean(), 1e-12);
}

test "Chi: variance = k - mean^2" {
    // Chi(1).variance() = 1 - 2/π
    const dist_1 = try Chi(f64).init(1.0);
    const expected_1 = 1.0 - 2.0 / math.pi;
    try expectApproxEqAbs(expected_1, dist_1.variance(), 1e-12);

    // Chi(2).variance() = 2 - π/2
    const dist_2 = try Chi(f64).init(2.0);
    const expected_2 = 2.0 - math.pi / 2.0;
    try expectApproxEqAbs(expected_2, dist_2.variance(), 1e-12);

    // Chi(3).variance() = 3 - 8/π
    const dist_3 = try Chi(f64).init(3.0);
    const expected_3 = 3.0 - 8.0 / math.pi;
    try expectApproxEqAbs(expected_3, dist_3.variance(), 1e-12);
}

test "Chi: entropy formula matches related distributions" {
    // Chi(1) entropy = 0.5*ln(π/2) + 0.5  [= HalfNormal(σ=1) entropy]
    const dist_1 = try Chi(f64).init(1.0);
    const expected_1 = 0.5 * @log(math.pi / 2.0) + 0.5;
    try expectApproxEqAbs(expected_1, dist_1.entropy(), 1e-7);

    // Chi(2) entropy = 1 - 0.5*ln(2) + γ/2  [= Rayleigh(σ=1) entropy]
    const dist_2 = try Chi(f64).init(2.0);
    const gamma_e = 0.5772156649015329;
    const expected_2 = 1.0 - 0.5 * @log(2.0) + gamma_e / 2.0;
    try expectApproxEqAbs(expected_2, dist_2.entropy(), 1e-7);

    // Chi(3) entropy = 0.5*ln(2π) + γ - 0.5  [= MaxwellBoltzmann(a=1) entropy]
    const dist_3 = try Chi(f64).init(3.0);
    const expected_3 = 0.5 * @log(2.0 * math.pi) + gamma_e - 0.5;
    try expectApproxEqAbs(expected_3, dist_3.entropy(), 1e-7);
}

test "Chi: sample is positive and finite" {
    const dist = try Chi(f64).init(3.0);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..1000) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "Chi: empirical sample mean converges to theoretical" {
    // Chi(3).mean() = 2 * sqrt(2/π)
    const dist = try Chi(f64).init(3.0);
    const expected_mean = 2.0 * @sqrt(2.0 / math.pi);
    var rng = std.Random.DefaultPrng.init(42);
    var sum: f64 = 0.0;
    const n = 50000;
    for (0..n) |_| {
        sum += dist.sample(rng.random());
    }
    const empirical = sum / @as(f64, @floatFromInt(n));
    try expectApproxEqAbs(expected_mean, empirical, 0.05);
}

test "Chi: sample works with non-integer k=2.5" {
    const dist = try Chi(f64).init(2.5);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..200) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "Chi: sample works with k=0.5 (exercises boost trick)" {
    const dist = try Chi(f64).init(0.5);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..200) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "Chi: validate passes for valid params" {
    const dist = try Chi(f64).init(3.0);
    try dist.validate();
}

test "Chi: validateValue rejects non-positive and non-finite x" {
    const dist = try Chi(f64).init(3.0);
    try expectError(error.OutOfDomain, dist.validateValue(0.0));
    try expectError(error.OutOfDomain, dist.validateValue(-1.0));
    try expectError(error.OutOfDomain, dist.validateValue(math.nan(f64)));
    try expectError(error.OutOfDomain, dist.validateValue(math.inf(f64)));
}

test "Chi: validateValue accepts positive finite x" {
    const dist = try Chi(f64).init(3.0);
    const x_vals = [_]f64{ 1e-6, 0.01, 0.1, 1.0, 10.0, 1e6 };
    for (x_vals) |x| {
        try dist.validateValue(x);
    }
}

test "Chi: f32 support basic operations" {
    const dist = try Chi(f32).init(3.0);
    try testing.expect(dist.mean() > 0.0);
    try testing.expect(dist.variance() > 0.0);
    try testing.expect(dist.pdf(1.0) > 0.0);
    const c = dist.cdf(1.0);
    try testing.expect(c > 0.0 and c < 1.0);
    const q = try dist.quantile(0.5);
    try testing.expect(q > 0.0);
}

test "Chi: f32 quantile roundtrip" {
    const dist = try Chi(f32).init(3.0);
    const probs = [_]f32{ 0.1, 0.5, 0.9 };
    for (probs) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-4);
    }
}

test "Chi: increasing k increases mean" {
    const dist_1 = try Chi(f64).init(1.0);
    const dist_2 = try Chi(f64).init(2.0);
    const dist_3 = try Chi(f64).init(3.0);
    const dist_10 = try Chi(f64).init(10.0);
    try testing.expect(dist_1.mean() < dist_2.mean());
    try testing.expect(dist_2.mean() < dist_3.mean());
    try testing.expect(dist_3.mean() < dist_10.mean());
}

test "Chi: mode < mean (right-skewed for k >= 2)" {
    const dist = try Chi(f64).init(5.0);
    const m = dist.mode();
    const mn = dist.mean();
    try testing.expect(m < mn);
}

// ============================================================================
// Noncentral Chi-Squared Distribution
// ============================================================================

pub fn NoncentralChiSquared(comptime T: type) type {
    return struct {
        k: T,      // degrees of freedom, k > 0
        lambda: T, // noncentrality parameter, lambda >= 0

        const Self = @This();

        /// Create a noncentral chi-squared distribution with k degrees of freedom and noncentrality lambda.
        ///
        /// Errors: k ≤ 0, lambda < 0, NaN, or infinite values.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(k: T, lambda: T) DistributionError!Self {
            if (k <= 0.0 or !math.isFinite(k)) return error.InvalidParameter;
            if (lambda < 0.0 or !math.isFinite(lambda)) return error.InvalidParameter;
            return Self{ .k = k, .lambda = lambda };
        }

        /// Probability density function (PDF) at x
        ///
        /// f(x; k, λ) = exp(-(k+λ)/2) · (x/λ)^(k/4-1/2) · I_{k/2-1}(√(λx))
        /// where I is the modified Bessel function of the first kind.
        /// Alternatively via Poisson mixture: f(x) = Σ_{j=0}^∞ w_j · f_χ²_{k+2j}(x)
        ///
        /// Time: O(1) for λ=0, O(series_terms) for λ>0 | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            return @exp(self.logpdf(x));
        }

        /// Log probability density function (log PDF) at x
        ///
        /// Time: O(1) for λ=0, O(series_terms) for λ>0 | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= 0.0) return -math.inf(T);

            // Special case: lambda = 0 reduces to chi-squared
            if (self.lambda == 0.0) {
                // Chi²(k) PDF log: (k/2-1)·ln(x) - x/2 - (k/2)·ln(2) - logΓ(k/2)
                return (self.k / 2.0 - 1.0) * @log(x) - x / 2.0 - (self.k / 2.0) * @log(2.0) - logGamma(self.k / 2.0);
            }

            // General case: Poisson mixture
            // f(x) = Σ_{j=0}^∞ w_j · f_χ²_{k+2j}(x)
            // where w_j = exp(-λ/2) · (λ/2)^j / j!
            var sum: T = 0.0;
            const half_lambda = self.lambda / 2.0;

            // Smart starting index: peak of Poisson(λ/2) is near λ/2
            var j_start: usize = 0;
            if (self.lambda > 0.0) {
                const peak = half_lambda;
                j_start = if (peak > 6.0 * @sqrt(peak)) @intFromFloat(@floor(peak - 6.0 * @sqrt(peak))) else 0;
            }

            // Compute first log_w at j_start
            var log_w: T = -half_lambda + @as(T, @floatFromInt(j_start)) * @log(half_lambda) - logGamma(@as(T, @floatFromInt(j_start)) + 1.0);

            // Accumulate series
            const max_terms = 300;
            var j = j_start;
            while (j < j_start + max_terms) : (j += 1) {
                const w = @exp(log_w);

                // Chi²(k+2j) PDF log: ((k+2j)/2 - 1)·ln(x) - x/2 - ((k+2j)/2)·ln(2) - logΓ((k+2j)/2)
                const k_plus_2j = self.k + 2.0 * @as(T, @floatFromInt(j));
                const half_k_plus_2j = k_plus_2j / 2.0;
                const chi2_logpdf = (half_k_plus_2j - 1.0) * @log(x) - x / 2.0 - half_k_plus_2j * @log(2.0) - logGamma(half_k_plus_2j);
                const term = w * @exp(chi2_logpdf);

                sum += term;

                // Stop when term is negligible AND j is past the peak (to catch all significant mass for large λ)
                if (term < 1e-14 and @as(T, @floatFromInt(j)) > half_lambda) break;

                // Update log_w for next iteration: log_w_{j+1} = log_w_j + log(λ/2) - log(j+1)
                log_w += @log(half_lambda) - @log(@as(T, @floatFromInt(j + 1)));
            }

            return @log(sum);
        }

        /// Cumulative distribution function (CDF) at x
        ///
        /// F(x; k, λ) = Σ_{j=0}^∞ w_j · P((k+2j)/2, x/2)
        /// where P is the regularized lower incomplete gamma and w_j is Poisson(λ/2) PMF.
        ///
        /// Time: O(1) for λ=0, O(series_terms) for λ>0 | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;

            // Special case: lambda = 0 reduces to chi-squared
            if (self.lambda == 0.0) {
                return regularizedGammaP(self.k / 2.0, x / 2.0);
            }

            // General case: Poisson mixture of incomplete gammas
            var sum: T = 0.0;
            const half_lambda = self.lambda / 2.0;

            // Smart starting index
            var j_start: usize = 0;
            if (self.lambda > 0.0) {
                const peak = half_lambda;
                j_start = if (peak > 6.0 * @sqrt(peak)) @intFromFloat(@floor(peak - 6.0 * @sqrt(peak))) else 0;
            }

            var log_w: T = -half_lambda + @as(T, @floatFromInt(j_start)) * @log(half_lambda) - logGamma(@as(T, @floatFromInt(j_start)) + 1.0);

            const max_terms = 300;
            var j = j_start;
            while (j < j_start + max_terms) : (j += 1) {
                const w = @exp(log_w);
                const k_plus_2j = self.k + 2.0 * @as(T, @floatFromInt(j));
                const gamma_p = regularizedGammaP(k_plus_2j / 2.0, x / 2.0);
                const term = w * gamma_p;

                sum += term;

                if (@abs(w) < 1e-14 and @as(T, @floatFromInt(j)) > half_lambda) break;

                log_w += @log(half_lambda) - @log(@as(T, @floatFromInt(j + 1)));
            }

            return @min(1.0, @max(0.0, sum));
        }

        /// Survival function (SF) at x: P(X > x)
        ///
        /// S(x; k, λ) = 1 - F(x; k, λ)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            if (x <= 0.0) return 1.0;
            return 1.0 - self.cdf(x);
        }

        /// Quantile function (inverse CDF): returns x such that P(X ≤ x) = p
        ///
        /// Uses bisection on the CDF (no closed form exists).
        ///
        /// Errors: p < 0 or p > 1
        ///
        /// Time: O(log(1/ε)) for tolerance ε | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return math.inf(T);

            var low: T = 0.0;
            var high: T = @max(self.k + self.lambda, 10.0);

            while (self.cdf(high) < p) {
                high *= 2.0;
                if (!math.isFinite(high)) return math.inf(T);
            }

            const tolerance: T = 1e-10;
            const max_iter = 100;
            var iter: usize = 0;
            while (iter < max_iter) : (iter += 1) {
                const mid = (low + high) / 2.0;
                if (mid <= 0.0) break;
                const cdf_mid = self.cdf(mid);
                if (@abs(cdf_mid - p) < tolerance) return mid;
                if (cdf_mid < p) {
                    low = mid;
                } else {
                    high = mid;
                }
                if (high - low < tolerance) return (low + high) / 2.0;
            }
            return (low + high) / 2.0;
        }

        /// Mode of the distribution
        ///
        /// For noncentral chi-squared, mode ≈ max(0, k + λ - 2) [exact for central chi-squared]
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            return @max(0.0, self.k + self.lambda - 2.0);
        }

        /// Mean (expected value) of the distribution
        ///
        /// E[X] = k + λ
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            return self.k + self.lambda;
        }

        /// Variance of the distribution
        ///
        /// Var[X] = 2·(k + 2λ)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            return 2.0 * (self.k + 2.0 * self.lambda);
        }

        /// Differential entropy
        ///
        /// H(X) = 0.5·log(2π·e·(k+λ)) + ψ(k/2)
        /// (approximate; exact formula involves modified Bessel function)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            const k_plus_lambda = self.k + self.lambda;
            const half_k = self.k / 2.0;
            return 0.5 * @log(2.0 * math.pi * math.e * k_plus_lambda) + digamma(T, half_k);
        }

        /// Generate a random sample from this distribution
        ///
        /// Uses mixture: M ~ Poisson(λ/2), then X ~ Chi²(k + 2M) via Gamma.
        ///
        /// Time: O(1) expected | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            // Step 1: Sample M ~ Poisson(λ/2)
            // For λ=0: M=0 always; Knuth inter-arrival otherwise
            const half_lambda = self.lambda / 2.0;
            const m: usize = blk: {
                if (half_lambda == 0.0) break :blk 0;
                var cnt: usize = 0;
                var cumsum: T = 0.0;
                while (true) {
                    cumsum += -@log(rng.float(T)) / half_lambda;
                    if (cumsum >= 1.0) break;
                    cnt += 1;
                }
                break :blk cnt;
            };

            // Step 2: X ~ 2·Gamma(k/2 + M, rate=1) via Marsaglia-Tsang with boost trick
            const alpha = self.k / 2.0 + @as(T, @floatFromInt(m));
            const alpha_mt = if (alpha >= 1.0) alpha else alpha + 1.0;
            const d = alpha_mt - 1.0 / 3.0;
            const c = 1.0 / @sqrt(9.0 * d);

            var gamma_val: T = undefined;
            while (true) {
                var z: T = undefined;
                var v: T = undefined;
                while (true) {
                    const ra = rng.float(T);
                    const rb = rng.float(T);
                    z = @sqrt(-2.0 * @log(ra)) * @cos(2.0 * math.pi * rb);
                    v = 1.0 + c * z;
                    if (v > 0.0) break;
                }
                v = v * v * v;
                const rc = rng.float(T);
                if (rc < 1.0 - 0.0331 * z * z * z * z) {
                    gamma_val = d * v;
                    break;
                }
                if (@log(rc) < 0.5 * z * z + d * (1.0 - v + @log(v))) {
                    gamma_val = d * v;
                    break;
                }
            }
            if (alpha < 1.0) {
                const rb = rng.float(T);
                gamma_val *= math.pow(T, rb, 1.0 / alpha);
            }

            return 2.0 * gamma_val;
        }

        /// Validate distribution parameters
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (self.k <= 0.0 or !math.isFinite(self.k)) return error.InvalidParameter;
            if (self.lambda < 0.0 or !math.isFinite(self.lambda)) return error.InvalidParameter;
        }

        /// Validate that x is in the support (0, ∞)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validateValue(self: Self, x: T) DistributionError!void {
            _ = self;
            if (x <= 0.0 or !math.isFinite(x)) return error.OutOfDomain;
        }
    };
}

test "NoncentralChiSquared: init valid parameters" {
    _ = try NoncentralChiSquared(f64).init(1.0, 0.0);
    _ = try NoncentralChiSquared(f64).init(2.0, 3.0);
    _ = try NoncentralChiSquared(f64).init(0.5, 0.0);
    _ = try NoncentralChiSquared(f64).init(10.0, 10.0);
}

test "NoncentralChiSquared: init invalid k zero" {
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(0.0, 1.0));
}

test "NoncentralChiSquared: init invalid k negative" {
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(-1.0, 1.0));
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(-0.5, 0.0));
}

test "NoncentralChiSquared: init invalid k NaN" {
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(math.nan(f64), 0.0));
}

test "NoncentralChiSquared: init invalid k infinity" {
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(math.inf(f64), 1.0));
}

test "NoncentralChiSquared: init invalid lambda negative" {
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(2.0, -0.1));
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(3.0, -1.0));
}

test "NoncentralChiSquared: init invalid lambda infinity" {
    try expectError(error.InvalidParameter, NoncentralChiSquared(f64).init(2.0, math.inf(f64)));
}

test "NoncentralChiSquared: validate passes for valid params" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 2.0);
    try dist.validate();
}

test "NoncentralChiSquared: validateValue rejects non-positive x" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 1.0);
    try expectError(error.OutOfDomain, dist.validateValue(0.0));
    try expectError(error.OutOfDomain, dist.validateValue(-1.0));
    try expectError(error.OutOfDomain, dist.validateValue(-0.01));
}

test "NoncentralChiSquared: validateValue rejects NaN and infinity" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 1.0);
    try expectError(error.OutOfDomain, dist.validateValue(math.nan(f64)));
    try expectError(error.OutOfDomain, dist.validateValue(math.inf(f64)));
}

test "NoncentralChiSquared: validateValue accepts positive finite x" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 1.0);
    const x_vals = [_]f64{ 1e-6, 0.01, 0.1, 1.0, 10.0, 1e6 };
    for (x_vals) |x| {
        try dist.validateValue(x);
    }
}

test "NoncentralChiSquared: lambda=0 cdf matches chi-squared" {
    // k=4, lambda=0: cdf(4) should match Chi²(4) = regularizedGammaP(2, 2)
    const dist = try NoncentralChiSquared(f64).init(4.0, 0.0);
    const expected = regularizedGammaP(2.0, 2.0); // ≈ 1 - 3·exp(-2) ≈ 0.59399
    try expectApproxEqAbs(expected, dist.cdf(4.0), 1e-6);
}

test "NoncentralChiSquared: lambda=0 cdf matches chi-squared k=2" {
    // k=2, lambda=0: cdf(2) should match Chi²(2) = regularizedGammaP(1, 1) = 1 - exp(-1)
    const dist = try NoncentralChiSquared(f64).init(2.0, 0.0);
    const expected = 1.0 - @exp(-1.0); // ≈ 0.63212
    try expectApproxEqAbs(expected, dist.cdf(2.0), 1e-6);
}

test "NoncentralChiSquared: mean formula k + lambda" {
    const dist1 = try NoncentralChiSquared(f64).init(3.0, 4.0);
    try expectApproxEqAbs(7.0, dist1.mean(), 1e-12);

    const dist2 = try NoncentralChiSquared(f64).init(5.0, 0.0);
    try expectApproxEqAbs(5.0, dist2.mean(), 1e-12);

    const dist3 = try NoncentralChiSquared(f64).init(2.0, 6.0);
    try expectApproxEqAbs(8.0, dist3.mean(), 1e-12);
}

test "NoncentralChiSquared: variance formula 2(k + 2λ)" {
    const dist1 = try NoncentralChiSquared(f64).init(3.0, 4.0);
    const expected1 = 2.0 * (3.0 + 2.0 * 4.0); // = 2 * 11 = 22
    try expectApproxEqAbs(expected1, dist1.variance(), 1e-12);

    const dist2 = try NoncentralChiSquared(f64).init(5.0, 0.0);
    const expected2 = 2.0 * 5.0; // = 10
    try expectApproxEqAbs(expected2, dist2.variance(), 1e-12);

    const dist3 = try NoncentralChiSquared(f64).init(2.0, 6.0);
    const expected3 = 2.0 * (2.0 + 2.0 * 6.0); // = 28
    try expectApproxEqAbs(expected3, dist3.variance(), 1e-12);
}

test "NoncentralChiSquared: mode formula k + lambda - 2" {
    const dist1 = try NoncentralChiSquared(f64).init(4.0, 2.0);
    try expectApproxEqAbs(4.0, dist1.mode(), 1e-12); // 4 + 2 - 2 = 4

    const dist2 = try NoncentralChiSquared(f64).init(1.0, 0.0);
    try expectApproxEqAbs(0.0, dist2.mode(), 1e-12); // max(0, 1 + 0 - 2) = 0

    const dist3 = try NoncentralChiSquared(f64).init(2.0, 0.0);
    try expectApproxEqAbs(0.0, dist3.mode(), 1e-12); // max(0, 2 + 0 - 2) = 0

    const dist4 = try NoncentralChiSquared(f64).init(5.0, 3.0);
    try expectApproxEqAbs(6.0, dist4.mode(), 1e-12); // 5 + 3 - 2 = 6
}

test "NoncentralChiSquared: pdf positive on support" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 2.0);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0, 20.0 };
    for (x_vals) |x| {
        try testing.expect(dist.pdf(x) > 0.0);
    }
}

test "NoncentralChiSquared: pdf zero for non-positive x" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 1.0);
    try testing.expect(dist.pdf(0.0) == 0.0);
    try testing.expect(dist.pdf(-1.0) == 0.0);
    try testing.expect(dist.pdf(-0.01) == 0.0);
}

test "NoncentralChiSquared: logpdf equals log of pdf" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 1.0);
    const x_vals = [_]f64{ 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    for (x_vals) |x| {
        try expectApproxEqAbs(@log(dist.pdf(x)), dist.logpdf(x), 1e-10);
    }
}

test "NoncentralChiSquared: logpdf negative infinity for non-positive x" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 1.0);
    try testing.expect(math.isNegativeInf(dist.logpdf(0.0)));
    try testing.expect(math.isNegativeInf(dist.logpdf(-1.0)));
}

test "NoncentralChiSquared: pdf integrates to approximately 1" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 1.0);
    var sum: f64 = 0.0;
    const dx = 0.05;
    var x: f64 = 0.05;
    while (x < 50.0) : (x += dx) {
        sum += dist.pdf(x) * dx;
    }
    try expectApproxEqAbs(1.0, sum, 0.02);
}

test "NoncentralChiSquared: cdf zero at origin" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 2.0);
    try testing.expect(dist.cdf(0.0) == 0.0);
}

test "NoncentralChiSquared: cdf approaches one" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 2.0);
    try testing.expect(dist.cdf(1e6) > 0.9999);
}

test "NoncentralChiSquared: cdf is monotonically increasing" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 2.0);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0, 50.0 };
    var prev = dist.cdf(x_vals[0]);
    for (x_vals[1..]) |x| {
        const c = dist.cdf(x);
        try testing.expect(c >= prev);
        prev = c;
    }
}

test "NoncentralChiSquared: cdf in [0, 1]" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 2.0);
    const x_vals = [_]f64{ 1e-6, 0.01, 0.1, 1.0, 10.0, 1e3 };
    for (x_vals) |x| {
        const c = dist.cdf(x);
        try testing.expect(c >= 0.0 and c <= 1.0);
    }
}

test "NoncentralChiSquared: sf equals 1 minus cdf" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 1.0);
    const x_vals = [_]f64{ 0.01, 0.1, 0.5, 1.0, 2.0, 5.0, 10.0 };
    for (x_vals) |x| {
        try expectApproxEqAbs(1.0, dist.cdf(x) + dist.sf(x), 1e-12);
    }
}

test "NoncentralChiSquared: quantile roundtrip cdf(quantile(p)) = p" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 2.0);
    const probs = [_]f64{ 0.1, 0.25, 0.5, 0.75, 0.9 };
    for (probs) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-7);
    }
}

test "NoncentralChiSquared: quantile boundary cases" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 1.0);
    try testing.expect((try dist.quantile(0.0)) == 0.0);
    try testing.expect(math.isInf(try dist.quantile(1.0)));
}

test "NoncentralChiSquared: quantile rejects invalid probabilities" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 1.0);
    try expectError(error.InvalidProbability, dist.quantile(-0.1));
    try expectError(error.InvalidProbability, dist.quantile(1.1));
    try expectError(error.InvalidProbability, dist.quantile(math.nan(f64)));
}

test "NoncentralChiSquared: higher lambda shifts cdf left (smaller CDF for fixed x)" {
    const dist_0 = try NoncentralChiSquared(f64).init(4.0, 0.0);
    const dist_2 = try NoncentralChiSquared(f64).init(4.0, 2.0);
    const x = 6.0;
    // Higher lambda shifts distribution right, so CDF(x) is smaller
    try testing.expect(dist_2.cdf(x) < dist_0.cdf(x));
}

test "NoncentralChiSquared: sample is positive and finite" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 2.0);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..1000) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "NoncentralChiSquared: empirical sample mean converges to theoretical" {
    const dist = try NoncentralChiSquared(f64).init(4.0, 2.0);
    const expected_mean = 6.0; // k + lambda = 4 + 2
    var rng = std.Random.DefaultPrng.init(42);
    var sum: f64 = 0.0;
    const n = 50000;
    for (0..n) |_| {
        sum += dist.sample(rng.random());
    }
    const empirical = sum / @as(f64, @floatFromInt(n));
    try expectApproxEqAbs(expected_mean, empirical, 0.1);
}

test "NoncentralChiSquared: sample works with lambda=0" {
    const dist = try NoncentralChiSquared(f64).init(3.0, 0.0);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..200) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "NoncentralChiSquared: f32 support basic operations" {
    const dist = try NoncentralChiSquared(f32).init(3.0, 1.0);
    try testing.expect(dist.mean() > 0.0);
    try testing.expect(dist.variance() > 0.0);
    try testing.expect(dist.pdf(1.0) > 0.0);
    const c = dist.cdf(1.0);
    try testing.expect(c > 0.0 and c < 1.0);
    const q = try dist.quantile(0.5);
    try testing.expect(q > 0.0);
}

test "NoncentralChiSquared: f32 quantile roundtrip" {
    const dist = try NoncentralChiSquared(f32).init(4.0, 1.0);
    const probs = [_]f32{ 0.1, 0.5, 0.9 };
    for (probs) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-3);
    }
}

test "NoncentralChiSquared: sample works with small k (exercises boost trick)" {
    // k=0.5 gives alpha=k/2+m; for m=0 alpha=0.25 < 1 — must use boost trick
    const dist = try NoncentralChiSquared(f64).init(0.5, 0.0);
    var rng = std.Random.DefaultPrng.init(42);
    for (0..200) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0.0);
        try testing.expect(math.isFinite(s));
    }
}

test "NoncentralChiSquared: sample lambda=0 empirical mean converges to k" {
    const k = 5.0;
    const dist = try NoncentralChiSquared(f64).init(k, 0.0);
    var rng = std.Random.DefaultPrng.init(99);
    var sum: f64 = 0.0;
    const n = 50000;
    for (0..n) |_| {
        sum += dist.sample(rng.random());
    }
    const empirical = sum / @as(f64, @floatFromInt(n));
    // For lambda=0 this is chi-squared(5), mean = 5
    try expectApproxEqAbs(k, empirical, 0.1);
}

pub fn ToppLeone(comptime T: type) type {
    return struct {
        alpha: T, // shape parameter, alpha > 0

        const Self = @This();

        /// Create a Topp-Leone distribution with shape parameter alpha.
        ///
        /// Errors: alpha ≤ 0, NaN, or infinite values.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(alpha: T) DistributionError!Self {
            if (!(alpha > 0.0) or !math.isFinite(alpha)) return error.InvalidParameter;
            return Self{ .alpha = alpha };
        }

        /// Probability density function (PDF) at x
        ///
        /// f(x; α) = 2α(1-x)(2x-x²)^(α-1)  for x ∈ [0, 1]
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x < 0.0 or x > 1.0) return 0.0;
            if (x == 1.0) return 0.0;
            const u = 2.0 * x - x * x; // = x(2-x) = 1-(1-x)²
            if (u <= 0.0) return 0.0;
            return 2.0 * self.alpha * (1.0 - x) * math.pow(T, u, self.alpha - 1.0);
        }

        /// Log probability density function (log PDF) at x
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x < 0.0 or x > 1.0) return -math.inf(T);
            if (x == 1.0) return -math.inf(T);
            const u = 2.0 * x - x * x;
            if (u <= 0.0) return -math.inf(T);
            return @log(2.0 * self.alpha) + @log(1.0 - x) + (self.alpha - 1.0) * @log(u);
        }

        /// Cumulative distribution function (CDF) at x
        ///
        /// F(x; α) = (2x - x²)^α  for x ∈ [0, 1]
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            if (x >= 1.0) return 1.0;
            const u = 2.0 * x - x * x;
            return math.pow(T, u, self.alpha);
        }

        /// Survival function (SF) at x: P(X > x)
        ///
        /// S(x; α) = 1 - (2x - x²)^α
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            return 1.0 - self.cdf(x);
        }

        /// Quantile function (inverse CDF): returns x such that P(X ≤ x) = p
        ///
        /// x = 1 - √(1 - p^(1/α))   [exact closed form]
        ///
        /// Errors: p < 0 or p > 1
        ///
        /// Time: O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return 1.0;
            const u = math.pow(T, p, 1.0 / self.alpha);
            return 1.0 - @sqrt(1.0 - u);
        }

        /// Mode of the distribution
        ///
        /// For α ≥ 1: mode = 1 - 1/√(2α-1)
        /// For 0 < α < 1: mode = 0 (PDF is decreasing from ∞ near 0)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            if (self.alpha >= 1.0) {
                return 1.0 - 1.0 / @sqrt(2.0 * self.alpha - 1.0);
            }
            return 0.0;
        }

        /// Mean (expected value) of the distribution
        ///
        /// E[X] = 1 - (√π/2) · exp(logΓ(α+1) - logΓ(α+3/2))
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            const log_ratio = logGamma(self.alpha + 1.0) - logGamma(self.alpha + 1.5);
            return 1.0 - 0.5 * @sqrt(math.pi) * @exp(log_ratio);
        }

        /// Variance of the distribution
        ///
        /// Var[X] = E[X²] - (E[X])²
        /// where E[X²] = 1 - √π·exp(logΓ(α+1) - logΓ(α+3/2)) + 1/(α+1)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            const m = self.mean();
            const log_ratio = logGamma(self.alpha + 1.0) - logGamma(self.alpha + 3.0 / 2.0);
            const ex2 = 1.0 - @sqrt(math.pi) * @exp(log_ratio) + 1.0 / (self.alpha + 1.0);
            return ex2 - m * m;
        }

        /// Differential entropy (numerical approximation via Simpson's rule)
        ///
        /// H(X) = -∫₀¹ f(x)·ln f(x) dx
        ///
        /// Time: O(N) | Space: O(1)
        pub fn entropy(self: Self) T {
            // Avoid boundary issues with very small/large x
            const n = 1000;
            const a: T = 1e-9;
            const b: T = 1.0 - 1e-9;
            const h = (b - a) / @as(T, @floatFromInt(n));
            var sum: T = 0.0;
            var i: usize = 0;
            while (i <= n) : (i += 1) {
                const xi = a + @as(T, @floatFromInt(i)) * h;
                const fi = self.pdf(xi);
                const lfi = self.logpdf(xi);
                const val = if (fi > 0.0) -fi * lfi else 0.0;
                const weight: T = if (i == 0 or i == n) 1.0 else if (i % 2 == 0) 2.0 else 4.0;
                sum += weight * val;
            }
            return sum * h / 3.0;
        }

        /// Generate a random sample from this distribution
        ///
        /// Uses inversion: x = 1 - √(1 - U^(1/α)), U ~ Uniform(0,1)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const u = rng.float(T);
            const upow = math.pow(T, u, 1.0 / self.alpha);
            return 1.0 - @sqrt(1.0 - upow);
        }

        /// Validate distribution parameters
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (!(self.alpha > 0.0) or !math.isFinite(self.alpha)) return error.InvalidParameter;
        }

        /// Validate that x is in the support [0, 1]
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validateValue(self: Self, x: T) DistributionError!void {
            _ = self;
            if (!(x >= 0.0 and x <= 1.0) or !math.isFinite(x)) return error.OutOfSupport;
        }
    };
}

