    const dist = try ToppLeone(f64).init(2.0);
    // F(0.5) = (2*0.5 - 0.5^2)^2 = 0.75^2 = 0.5625
    try expectApproxEqAbs(0.5625, dist.cdf(0.5), 1e-12);
