    const dist = try HalfLogistic(f64).init(1.0);
    const p = dist.pdf(0.0);
    try testing.expectApproxEqAbs(0.5, p, 1e-10);
}

test "HalfLogistic: pdf(0; sigma=2) = 0.25" {
