test "Bates: cdf monotonically increasing for n=1" {
    const dist = try Bates(f64).init(1);
    var prev_cdf: f64 = 0.0;
    var x: f64 = 0.0;
    while (x <= 1.0) : (x += 0.05) {
        const c = dist.cdf(x);
        try testing.expect(c >= prev_cdf);
        prev_cdf = c;
    }
}

