}

test "JohnsonSU: cdf is valid probability [0,1]" {
    const dist = try JohnsonSU(f64).init(0.0, 1.0, 0.0, 1.0);
    for ([_]f64{ -1000.0, -100.0, -1.0, 0.0, 1.0, 100.0, 1000.0 }) |x| {
