    // mode = 1 * ((3-1)/2)^(1/2) = sqrt(1) = 1.0
    const dist = try GeneralizedGamma(f64).init(1.0, 3.0, 2.0);
    const m = dist.mode();
    try testing.expectApproxEqAbs(1.0, m, 1e-5);
}

