}

test "LogitNormal: entropy increases with sigma (sigma=0.5 vs sigma=1.0)" {
    const dist1 = try LogitNormal(f64).init(0.0, 0.5);
    const dist2 = try LogitNormal(f64).init(0.0, 1.0);
