}

test "NoncentralBeta: exact pdf test NoncentralBeta(1,1,2).pdf(0.5)" {
    const dist = try NoncentralBeta(f64).init(1.0, 1.0, 2.0);
    const expected = 1.5 * @exp(-0.5);
