test "NoncentralBeta: exact variance test lambda=0 reduces to Beta(2,3) variance" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 0.0);
    const expected = 0.04;
    const actual = dist.variance();
    try testing.expectApproxEqAbs(expected, actual, 1.0e-4);
}

test "NoncentralBeta: mode is in [0, 1]" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    const m = dist.mode();
    try testing.expect(m >= 0.0 and m <= 1.0);
}

test "NoncentralBeta: entropy is finite" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    const e = dist.entropy();
    try testing.expect(math.isFinite(e));
}

test "NoncentralBeta: sample produces values in [0, 1]" {
    var rng = std.Random.DefaultPrng.init(0x12345678);
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    for (0..100) |_| {
        const x = dist.sample(rng.random());
        try testing.expect(x >= 0.0 and x <= 1.0);
    }
}

test "NoncentralBeta: sample mean convergence (N=20000)" {
    var rng = std.Random.DefaultPrng.init(0x87654321);
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    const expected_mean = dist.mean();

    var sum: f64 = 0.0;
    const n = 20000;
    for (0..n) |_| {
        const x = dist.sample(rng.random());
        sum += x;
    }
    const sample_mean = sum / @as(f64, @floatFromInt(n));
    const error_pct = @abs(sample_mean - expected_mean) / expected_mean * 100.0;
    try testing.expect(error_pct < 5.0);
}

test "NoncentralBeta: validate() passes for valid params" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    try dist.validate();
}

test "NoncentralBeta: validateValue passes for x in (0,1)" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    try dist.validateValue(0.5);
}

test "NoncentralBeta: validateValue fails for x < 0" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    const result = dist.validateValue(-0.1);
    try testing.expectError(error.OutOfSupport, result);
}

test "NoncentralBeta: validateValue fails for x > 1" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 1.5);
    const result = dist.validateValue(1.1);
    try testing.expectError(error.OutOfSupport, result);
}

test "NoncentralBeta(f32): init and pdf with f32" {
    const dist = try NoncentralBeta(f32).init(1.0, 2.0, 0.5);
    const p = dist.pdf(0.5);
    try testing.expect(math.isFinite(p));
    try testing.expect(p >= 0.0);
}

test "NoncentralBeta(f32): cdf in [0,1]" {
    const dist = try NoncentralBeta(f32).init(1.0, 2.0, 0.5);
    const c = dist.cdf(0.5);
    try testing.expect(c >= 0.0 and c <= 1.0);
}

test "NoncentralBeta: large lambda pdf is positive and finite" {
    const dist = try NoncentralBeta(f64).init(2.0, 3.0, 5.0);
    const p = dist.pdf(0.5);
    try testing.expect(p > 0.0);
    try testing.expect(math.isFinite(p));
}

// ============================================================================
// Yule-Simon Distribution
// ============================================================================

/// Yule-Simon distribution YuleSimon(ρ) — a discrete power-law distribution.
///
/// Arises as the limiting distribution in the Pólya urn model and describes
/// word-frequency ranks (Zipf's law), city sizes, species distributions,
/// and citation counts (Price's law).
///
/// Support: {1, 2, 3, ...}
/// Parameter: ρ > 0 (shape; larger ρ → lighter tail, more mass at k=1)
///
/// PMF: P(X=k; ρ) = ρ·B(k, ρ+1) = ρ·Γ(k)·Γ(ρ+1)/Γ(k+ρ+1)
/// CDF: F(k; ρ) = 1 − ρ·B(k+1, ρ) = 1 − ρ·Γ(k+1)·Γ(ρ)/Γ(k+ρ+1)
///
/// Survival recurrence: S(k) = S(k−1)·k/(k+ρ), S(0)=1
/// PMF recurrence:      P(k+1) = P(k)·k/(k+ρ+1), P(1)=ρ/(ρ+1)
///
/// Mean:     ρ/(ρ−1)                       for ρ > 1  (else +∞)
/// Variance: ρ²/((ρ−1)²(ρ−2))             for ρ > 2  (else +∞)
/// Mode:     1  (PMF strictly decreasing)

// ============================================================================
// Conway-Maxwell-Poisson Distribution
// ============================================================================

/// Conway-Maxwell-Poisson distribution CMP(λ, ν)
///
/// Generalizes Poisson (ν=1), Geometric (ν=0, λ<1), and Bernoulli (ν→∞).
///
/// PMF: P(X=k) = λ^k / ((k!)^ν · Z(λ,ν))
/// where Z(λ,ν) = Σ_{j=0}^∞ λ^j / (j!)^ν is the normalizing constant.
///
/// Parameters:
///   - lambda (λ): rate parameter (λ > 0)
///   - nu (ν): dispersion parameter (ν ≥ 0; ν=0 requires λ < 1)
///     * ν < 1: overdispersed (Var > Mean)
///     * ν = 1: equidispersed Poisson (Var = Mean)
///     * ν > 1: underdispersed (Var < Mean)
///
/// Time: O(k*) for pmf/cdf where k* is effective support size | Space: O(1)
pub fn ConwayMaxwellPoisson(comptime T: type) type {
    return struct {
        lambda: T,
        nu: T,
        log_z: T, // cached log normalizing constant

        const Self = @This();

        /// Initialize CMP(λ, ν).
        /// λ > 0; ν ≥ 0; if ν = 0 then additionally λ < 1.
        ///
        /// Computes and caches the log normalizing constant log Z(λ, ν).
        ///
        /// Time: O(k*) where k* ≈ max(λ^(1/ν) + 6√(λ^(1/ν)/ν), 50) | Space: O(1)
        pub fn init(lambda: T, nu: T) DistributionError!Self {
            if (!(lambda > 0.0) or !math.isFinite(lambda)) return error.InvalidParameter;
            if (!(nu >= 0.0) or !math.isFinite(nu)) return error.InvalidParameter;
            if (nu == 0.0 and !(lambda < 1.0)) return error.InvalidParameter;
            const lz = computeCMPLogZ(T, lambda, nu);
            return Self{ .lambda = lambda, .nu = nu, .log_z = lz };
        }

        /// Probability mass function P(X=k).
        ///
        /// P(X=k) = λ^k / ((k!)^ν · Z(λ,ν))
        ///
        /// Time: O(k) | Space: O(1)
        pub fn pmf(self: Self, k: u64) T {
            return @exp(self.logpmf(k));
        }

        /// Log probability mass function.
        ///
        /// log P(X=k) = k·log(λ) - ν·log(k!) - log(Z)
        ///
        /// Time: O(k) | Space: O(1)
        pub fn logpmf(self: Self, k: u64) T {
            const kf: T = @floatFromInt(k);
            return kf * @log(self.lambda) - self.nu * logGamma(kf + 1.0) - self.log_z;
        }

        /// Cumulative distribution function P(X ≤ k).
        ///
        /// F(k) = Σ_{j=0}^{k} P(X=j)
        ///
        /// Time: O(k) | Space: O(1)
        pub fn cdf(self: Self, k: u64) T {
            var sum: T = 0.0;
            var i: u64 = 0;
            while (i <= k) : (i += 1) {
                sum += self.pmf(i);
            }
            return @min(sum, 1.0);
        }

        /// Quantile function (inverse CDF) - returns k such that P(X ≤ k) ≥ p.
        ///
        /// Time: O(k*) where k* is the result | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!u64 {
            if (!(p >= 0.0) or !(p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0;

            var cumulative: T = 0.0;
            var k: u64 = 0;
            while (k < 100_000) : (k += 1) {
                cumulative += self.pmf(k);
                if (cumulative >= p) return k;
            }
            return k;
        }

        /// Mean of the distribution.
        ///
        /// Computed numerically: Σ k·P(X=k)
        ///
        /// Time: O(k*) | Space: O(1)
        pub fn mean(self: Self) T {
            var sum: T = 0.0;
            const eps = math.floatEps(T);
            var k: u64 = 1;
            while (k < 100_000) : (k += 1) {
                const pmf_k = self.pmf(k);
                if (pmf_k < eps) break;
                sum += @as(T, @floatFromInt(k)) * pmf_k;
            }
            return sum;
        }

        /// Variance of the distribution.
        ///
        /// Var = E[X²] - (E[X])²
        ///
        /// Time: O(k*) | Space: O(1)
        pub fn variance(self: Self) T {
            const m = self.mean();
            var e_x2: T = 0.0;
            const eps = math.floatEps(T);
            var k: u64 = 1;
            while (k < 100_000) : (k += 1) {
                const pmf_k = self.pmf(k);
                if (pmf_k < eps) break;
                const kf: T = @floatFromInt(k);
                e_x2 += kf * kf * pmf_k;
            }
            return e_x2 - m * m;
        }

        /// Mode of the distribution.
        ///
        /// For ν > 0: floor(λ^(1/ν))
        /// For ν = 0: 0 (geometric, strictly decreasing)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) u64 {
            if (self.nu == 0.0) return 0;
            const mode_f = @exp(@log(self.lambda) / self.nu);
            if (!math.isFinite(mode_f) or mode_f < 0.0) return 0;
            return @intFromFloat(@floor(mode_f));
        }

        /// Entropy of the distribution in nats.
        ///
        /// H = -Σ P(X=k)·log(P(X=k))
        ///
        /// Time: O(k*) | Space: O(1)
        pub fn entropy(self: Self) T {
            var sum: T = 0.0;
            const eps = math.floatEps(T);
            var k: u64 = 0;
            while (k < 100_000) : (k += 1) {
                const pmf_k = self.pmf(k);
                if (pmf_k < eps) break;
                if (pmf_k > 0.0) {
                    sum -= pmf_k * @log(pmf_k);
                }
            }
            return sum;
        }

        /// Generate a random sample from this distribution using inverse CDF.
        ///
        /// Time: O(k*) where k* is the sample value | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) u64 {
            const u = rng.float(T);
            var cumulative: T = 0.0;
            var k: u64 = 0;
            while (k < 100_000) : (k += 1) {
                cumulative += self.pmf(k);
                if (cumulative >= u) return k;
            }
            return k;
        }

        /// Assert that parameters are valid.
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) !void {
            if (!(self.lambda > 0.0) or !math.isFinite(self.lambda)) return DistributionError.InvalidParameter;
            if (!(self.nu >= 0.0) or !math.isFinite(self.nu)) return DistributionError.InvalidParameter;
            if (self.nu == 0.0 and !(self.lambda < 1.0)) return DistributionError.InvalidParameter;
            if (!math.isFinite(self.log_z)) return DistributionError.InvalidParameter;
        }
    };
}

/// Compute log Z(λ, ν) = log(Σ_{k=0}^∞ λ^k / (k!)^ν).
///
/// Uses unimodal two-pass approach:
/// - Pass 1: walk k=0,1,2,... tracking max log-term.
/// - Once past the peak, stop when the term is 40 log-units below the max.
/// - Pass 2: sum exp(log_term - log_max) over the same range.
/// - Return log_max + log(sum).
///
/// Time: O(k*) where k* ≈ effective support size | Space: O(1)
fn computeCMPLogZ(comptime T: type, lambda: T, nu: T) T {
    const log_lambda = @log(lambda);
    const MAX_K: u64 = 50_000;

    // Pass 1: find effective truncation k_stop and max log-term
    var log_max: T = 0.0; // k=0: log_term = 0
    var past_peak: bool = false;
    var k_stop: u64 = 0;

    var k: u64 = 1;
    while (k <= MAX_K) : (k += 1) {
        const kf: T = @floatFromInt(k);
        const lt = kf * log_lambda - nu * logGamma(kf + 1.0);
        if (lt > log_max) {
            log_max = lt;
        } else {
            past_peak = true;
        }
        if (past_peak and lt < log_max - 40.0) {
            k_stop = k;
            break;
        }
        k_stop = k;
    }

    // Pass 2: sum exp(log_term - log_max)
    var sum: T = 0.0;
    var j: u64 = 0;
    while (j <= k_stop) : (j += 1) {
        const jf: T = @floatFromInt(j);
        const lt = jf * log_lambda - nu * logGamma(jf + 1.0);
        sum += @exp(lt - log_max);
    }

    return log_max + @log(sum);
}

pub fn YuleSimon(comptime T: type) type {
    return struct {
        rho: T,

        const Self = @This();

        /// Initialize YuleSimon(ρ) distribution.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(rho: T) DistributionError!Self {
            if (!(rho > 0.0) or !math.isFinite(rho)) return error.InvalidParameter;
            return Self{ .rho = rho };
        }

        /// Probability mass function P(X=k).
        ///
        /// P(X=k) = ρ·B(k, ρ+1) = exp(log(ρ) + lgamma(k) + lgamma(ρ+1) − lgamma(k+ρ+1))
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pmf(self: Self, k: u64) T {
            if (k == 0) return 0.0;
            return @exp(self.logpmf(k));
        }

        /// Log probability mass function log P(X=k).
        ///
        /// log P(X=k) = log(ρ) + lgamma(k) + lgamma(ρ+1) − lgamma(k+ρ+1)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpmf(self: Self, k: u64) T {
            if (k == 0) return -math.inf(T);
            const kf: T = @floatFromInt(k);
            return @log(self.rho) + logGamma(kf) + logGamma(self.rho + 1.0) - logGamma(kf + self.rho + 1.0);
        }

        /// Survival function P(X > k) = ρ·B(k+1, ρ).
        ///
        /// sf(0) = 1; sf(k) = ρ·Γ(k+1)·Γ(ρ)/Γ(k+ρ+1) for k ≥ 1
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, k: u64) T {
            if (k == 0) return 1.0;
            const kf: T = @floatFromInt(k);
            const log_s = @log(self.rho) + logGamma(kf + 1.0) + logGamma(self.rho) - logGamma(kf + self.rho + 1.0);
            return @exp(log_s);
        }

        /// Cumulative distribution function P(X ≤ k).
        ///
        /// F(k) = 1 − S(k) = 1 − ρ·B(k+1, ρ)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, k: u64) T {
            if (k == 0) return 0.0;
            return 1.0 - self.sf(k);
        }

        /// Quantile function: smallest k ≥ 1 such that CDF(k) ≥ prob.
        ///
        /// Uses the survival recurrence S(k) = S(k−1)·k/(k+ρ) for O(k*) time
        /// where k* is the returned quantile.
        ///
        /// Time: O(k*) | Space: O(1)
        pub fn quantile(self: Self, prob: T) u64 {
            if (prob <= 0.0) return 1;
            const p = if (prob >= 1.0) 1.0 - math.floatEps(T) else prob;
            // Walk via survival recurrence: S(k) = P(X > k)
            // Return first k with CDF(k) = 1−S(k) ≥ p, i.e. S(k) ≤ 1−p
            var s: T = 1.0; // S(0) = 1
            var k: u64 = 0;
            while (k < 10_000_000) {
                k += 1;
                const kf: T = @floatFromInt(k);
                s *= kf / (kf + self.rho);
                if (s <= 1.0 - p) return k;
            }
            return k;
        }

        /// Mean: ρ/(ρ−1) for ρ > 1, else +∞.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            if (self.rho <= 1.0) return math.inf(T);
            return self.rho / (self.rho - 1.0);
        }

        /// Variance: ρ²/((ρ−1)²(ρ−2)) for ρ > 2, else +∞.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            if (self.rho <= 2.0) return math.inf(T);
            const rho_m1 = self.rho - 1.0;
            const rho_m2 = self.rho - 2.0;
            return (self.rho * self.rho) / (rho_m1 * rho_m1 * rho_m2);
        }

        /// Mode of the distribution (always 1; PMF is strictly decreasing).
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) u64 {
            _ = self;
            return 1;
        }

        /// Shannon entropy H(X) in nats, computed via truncated series.
        ///
        /// H = −Σ_{k=1}^{N} P(k)·log(P(k)) until tail contribution < ε.
        ///
        /// Time: O(N) where N is the truncation point | Space: O(1)
        pub fn entropy(self: Self) T {
            // Use PMF recurrence: P(k+1) = P(k)·k/(k+ρ+1)
            var p_k: T = self.rho / (self.rho + 1.0); // P(1)
            var h: T = 0.0;
            const max_iter: u64 = 100_000;
            var k: u64 = 1;
            while (k <= max_iter) : (k += 1) {
                if (p_k < math.floatEps(T)) break;
                const kf: T = @floatFromInt(k);
                h -= p_k * (self.logpmf(k));
                // advance recurrence: P(k+1) = P(k)·k/(k+ρ+1)
                p_k *= kf / (kf + self.rho + 1.0);
            }
            return h;
        }

        /// Generate a random sample using the survival recurrence.
        ///
        /// Generates U ~ Uniform(0,1) then finds k via S(k) ≤ 1−U.
        ///
        /// Time: O(E[X]) expected | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) u64 {
            const u = rng.float(T);
            var s: T = 1.0; // S(0) = 1
            var k: u64 = 0;
            while (k < 10_000_000) {
                k += 1;
                const kf: T = @floatFromInt(k);
                s *= kf / (kf + self.rho);
                if (s <= 1.0 - u) return k;
            }
            return k;
        }

        /// Validate internal invariants: ρ > 0 and finite.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) !void {
            if (!(self.rho > 0.0) or !math.isFinite(self.rho)) return error.InvalidParameter;
        }
    };
}

// ============================================================================
// Yule-Simon Distribution Tests (88th distribution, 17th discrete)
// ============================================================================

test "YuleSimon: init with valid rho=1.0 succeeds" {
    const dist = try YuleSimon(f64).init(1.0);
    try testing.expect(dist.rho == 1.0);
}

test "YuleSimon: init with valid rho=2.0 succeeds" {
    const dist = try YuleSimon(f64).init(2.0);
    try testing.expect(dist.rho == 2.0);
}

test "YuleSimon: init with valid rho=3.0 succeeds" {
    const dist = try YuleSimon(f64).init(3.0);
    try testing.expect(dist.rho == 3.0);
}

test "YuleSimon: init with rho=0.0 returns InvalidParameter error" {
    const result = YuleSimon(f64).init(0.0);
    try testing.expectError(error.InvalidParameter, result);
}

test "YuleSimon: init with negative rho returns InvalidParameter error" {
    const result = YuleSimon(f64).init(-1.5);
    try testing.expectError(error.InvalidParameter, result);
}

test "YuleSimon: init with NaN rho returns InvalidParameter error" {
    const result = YuleSimon(f64).init(math.nan(f64));
    try testing.expectError(error.InvalidParameter, result);
}

test "YuleSimon: pmf k=0 returns 0.0" {
    const dist = try YuleSimon(f64).init(1.0);
    const pmf_val = dist.pmf(0);
    try testing.expectEqual(0.0, pmf_val);
}

test "YuleSimon: pmf k=1 rho=1 equals 0.5" {
    const dist = try YuleSimon(f64).init(1.0);
    const pmf_val = dist.pmf(1);
    const expected: f64 = 0.5;
    try testing.expectApproxEqAbs(expected, pmf_val, 1e-9);
}

test "YuleSimon: pmf k=2 rho=1 equals 1/6" {
    const dist = try YuleSimon(f64).init(1.0);
    const pmf_val = dist.pmf(2);
    const expected: f64 = 1.0 / 6.0;
    try testing.expectApproxEqAbs(expected, pmf_val, 1e-9);
}

test "YuleSimon: pmf k=3 rho=1 equals 1/12" {
    const dist = try YuleSimon(f64).init(1.0);
    const pmf_val = dist.pmf(3);
    const expected: f64 = 1.0 / 12.0;
    try testing.expectApproxEqAbs(expected, pmf_val, 1e-9);
}

test "YuleSimon: pmf k=1 rho=2 equals 2/3" {
    const dist = try YuleSimon(f64).init(2.0);
    const pmf_val = dist.pmf(1);
    const expected: f64 = 2.0 / 3.0;
    try testing.expectApproxEqAbs(expected, pmf_val, 1e-9);
}

test "YuleSimon: pmf k=1 rho=3 equals 0.75" {
    const dist = try YuleSimon(f64).init(3.0);
    const pmf_val = dist.pmf(1);
    const expected: f64 = 0.75;
    try testing.expectApproxEqAbs(expected, pmf_val, 1e-9);
}

test "YuleSimon: pmf k=2 rho=3 equals 0.15" {
    const dist = try YuleSimon(f64).init(3.0);
    const pmf_val = dist.pmf(2);
    const expected: f64 = 0.15;
    try testing.expectApproxEqAbs(expected, pmf_val, 1e-9);
}

test "YuleSimon: logpmf k=0 returns -inf" {
    const dist = try YuleSimon(f64).init(1.0);
    const logpmf_val = dist.logpmf(0);
    try testing.expect(math.isNegativeInf(logpmf_val));
}

test "YuleSimon: logpmf k=1 rho=1 equals ln(0.5)" {
    const dist = try YuleSimon(f64).init(1.0);
    const logpmf_val = dist.logpmf(1);
    const expected: f64 = @log(0.5);
    try testing.expectApproxEqAbs(expected, logpmf_val, 1e-9);
}

test "YuleSimon: logpmf consistent with pmf" {
    const dist = try YuleSimon(f64).init(2.0);
    for (1..6) |k| {
        const pmf_val = dist.pmf(k);
        const logpmf_val = dist.logpmf(k);
        const expected = @log(pmf_val);
        try testing.expectApproxEqAbs(expected, logpmf_val, 1e-9);
    }
}

test "YuleSimon: cdf k=0 returns 0.0" {
    const dist = try YuleSimon(f64).init(1.0);
    const cdf_val = dist.cdf(0);
    try testing.expectEqual(0.0, cdf_val);
}

test "YuleSimon: cdf k=1 rho=1 equals 0.5" {
    const dist = try YuleSimon(f64).init(1.0);
    const cdf_val = dist.cdf(1);
    const expected: f64 = 0.5;
    try testing.expectApproxEqAbs(expected, cdf_val, 1e-9);
}

test "YuleSimon: cdf k=2 rho=1 equals 2/3" {
    const dist = try YuleSimon(f64).init(1.0);
    const cdf_val = dist.cdf(2);
    const expected: f64 = 2.0 / 3.0;
    try testing.expectApproxEqAbs(expected, cdf_val, 1e-9);
