}

// ============================================================================
// Erlang Distribution
// ============================================================================

/// Erlang distribution — integer-shape specialization of the Gamma distribution.
/// Widely used in queuing theory (Erlang-C formula), telecommunications, and reliability.
///
/// Parameters: k ∈ ℕ⁺ (shape/phases, k ≥ 1), λ > 0 (rate)
/// Support: x ≥ 0
/// PDF: f(x) = λ^k · x^(k-1) · e^{-λx} / (k-1)!
/// CDF: 1 - e^{-λx} · Σ_{m=0}^{k-1} (λx)^m / m!
/// Special cases: k=1 → Exponential(λ); k=2,λ=0.5 → Chi²(2)/2
pub fn Erlang(comptime T: type) type {
    return struct {
        k: u32,
        lambda: T,

        const Self = @This();

        /// Create an Erlang distribution with shape k (≥ 1) and rate λ (> 0)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(k: u32, lambda: T) DistributionError!Self {
            if (k == 0) return error.InvalidParameter;
            if (!(lambda > 0.0) or !math.isFinite(lambda)) return error.InvalidParameter;
            return Self{ .k = k, .lambda = lambda };
        }

        /// Probability density function (PDF) at x
        ///
        /// f(x) = λ^k · x^(k-1) · exp(-λx) / (k-1)!  for x ≥ 0, else 0
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x < 0.0) return 0.0;
            if (x == 0.0) {
                return if (self.k == 1) self.lambda else 0.0;
            }
            return @exp(self.logpdf(x));
        }

        /// Log probability density function (log PDF) at x
        ///
        /// log f(x) = k·ln(λ) + (k-1)·ln(x) - λx - logΓ(k)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x < 0.0) return -math.inf(T);
            if (x == 0.0) {
                return if (self.k == 1) @log(self.lambda) else -math.inf(T);
            }
            const k_f = @as(T, @floatFromInt(self.k));
            return k_f * @log(self.lambda) + (k_f - 1.0) * @log(x) - self.lambda * x - logGamma(k_f);
        }

        /// Cumulative distribution function (CDF) at x
        ///
        /// F(x) = 1 - e^{-u} · Σ_{m=0}^{k-1} u^m/m!  where u = λx
        ///
        /// Time: O(k) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            const u = self.lambda * x;
            var term: T = 1.0;
            var sum: T = 1.0;
            for (1..@as(usize, self.k)) |m| {
                term *= u / @as(T, @floatFromInt(m));
                sum += term;
            }
            return 1.0 - @exp(-u) * sum;
        }

        /// Survival function (SF) at x: 1 - CDF(x)
        ///
        /// S(x) = e^{-u} · Σ_{m=0}^{k-1} u^m/m!  where u = λx
        ///
        /// Time: O(k) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            if (x <= 0.0) return 1.0;
            const u = self.lambda * x;
            var term: T = 1.0;
            var sum: T = 1.0;
            for (1..@as(usize, self.k)) |m| {
                term *= u / @as(T, @floatFromInt(m));
                sum += term;
            }
            return @exp(-u) * sum;
        }

        /// Quantile function (inverse CDF) — returns x such that P(X ≤ x) = p
        ///
        /// Uses bisection; no closed form exists for general k.
        ///
        /// Errors: error.InvalidProbability if p ∉ [0, 1] or NaN
        ///
        /// Time: O(k · log(1/ε)) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return math.inf(T);
            const k_f = @as(T, @floatFromInt(self.k));
            const mn = k_f / self.lambda;
            const std_dev = @sqrt(k_f) / self.lambda;
            var lo: T = 0.0;
            var hi: T = mn + 20.0 * std_dev;
            // Ensure upper bound is above the target quantile
            while (self.cdf(hi) < p) hi *= 2.0;
            var i: u32 = 0;
            while (i < 200) : (i += 1) {
                const mid = 0.5 * (lo + hi);
                if (self.cdf(mid) < p) lo = mid else hi = mid;
                if (hi - lo < 1e-12) break;
            }
            return 0.5 * (lo + hi);
        }

        /// Mean of the distribution: k / λ
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            return @as(T, @floatFromInt(self.k)) / self.lambda;
        }

        /// Variance of the distribution: k / λ²
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            return @as(T, @floatFromInt(self.k)) / (self.lambda * self.lambda);
        }

        /// Mode of the distribution: (k - 1) / λ
        ///
        /// For k = 1 (Exponential special case), mode = 0.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            if (self.k == 1) return 0.0;
            return @as(T, @floatFromInt(self.k - 1)) / self.lambda;
        }

        /// Differential entropy: logΓ(k) - ln(λ) + (1 - k)·ψ(k) + k
        ///
        /// where ψ is the digamma function
        ///
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            const k_f = @as(T, @floatFromInt(self.k));
            return logGamma(k_f) - @log(self.lambda) + (1.0 - k_f) * digamma(T, k_f) + k_f;
        }

        /// Generate a random sample using the product-of-uniforms method
        ///
        /// X = -(1/λ) · Σ_{i=1}^k ln(U_i)  where U_i ~ Uniform(0, 1)
        /// Equivalent to summing k independent Exponential(λ) samples.
        ///
        /// Time: O(k) | Space: O(1)
        pub fn sample(self: Self, rng: anytype) T {
            var log_prod: T = 0.0;
            for (0..@as(usize, self.k)) |_| {
                const u = @max(rng.float(T), @as(T, 1e-15));
                log_prod += @log(u);
            }
            return -log_prod / self.lambda;
        }

        /// Validate distribution parameters
        ///
        /// Returns error.InvalidParameter if k < 1, λ ≤ 0, or λ is not finite
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) !void {
            if (self.k == 0) return error.InvalidParameter;
            if (!(self.lambda > 0.0) or !math.isFinite(self.lambda)) return error.InvalidParameter;
        }
    };
}

test "Erlang: init succeeds with valid parameters k=1, lambda=1.0" {
    const dist = try Erlang(f64).init(1, 1.0);
    try testing.expect(dist.k == 1);
    try testing.expectEqual(@as(f64, 1.0), dist.lambda);
}

test "Erlang: init succeeds with valid parameters k=5, lambda=2.0" {
    const dist = try Erlang(f64).init(5, 2.0);
    try testing.expect(dist.k == 5);
    try testing.expectEqual(@as(f64, 2.0), dist.lambda);
}

test "Erlang: init fails for k=0" {
