// ContinuousBernoulli(T) — bounded [0,1] distribution; ML/VAE latent space modeling
pub fn ContinuousBernoulli(comptime T: type) type {
    return struct {
        lambda: T,

        const Self = @This();

        // Threshold for treating lambda as 0.5 (Uniform limit).
        // Below this |2λ-1|, the general formulas become 0/0; use limit values instead.
        const eps: T = 1e-10;

        /// Create a Continuous Bernoulli distribution with parameter lambda ∈ (0, 1)
        ///
        /// Introduced by Loaiza-Ganem & Cunningham (2019) for VAE decoders on [0, 1] data.
        ///
        /// Errors: lambda ≤ 0, lambda ≥ 1, NaN, or ±∞
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(lambda: T) DistributionError!Self {
            if (!(lambda > 0.0 and lambda < 1.0)) return error.InvalidParameter;
            return Self{ .lambda = lambda };
        }

        // Normalizing constant C(λ) = ln(λ/(1-λ)) / (2λ-1)
        // Limit as λ→0.5: C(0.5) = 2 (Uniform normalization).
        inline fn normConst(self: Self) T {
            const d = 2.0 * self.lambda - 1.0;
            if (@abs(d) < eps) return 2.0;
            return @log(self.lambda / (1.0 - self.lambda)) / d;
        }

        /// Probability density function
        ///
        /// f(x;λ) = C(λ)·λ^x·(1-λ)^(1-x)  for x ∈ [0, 1], else 0
        ///
        /// f(x;0.5) = 1 for all x ∈ [0, 1] (Uniform limit).
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x < 0.0 or x > 1.0) return 0.0;
            const c = self.normConst();
            return c * math.pow(T, self.lambda, x) * math.pow(T, 1.0 - self.lambda, 1.0 - x);
        }

        /// Log probability density function
        ///
        /// log f(x;λ) = ln(C(λ)) + x·ln(λ) + (1-x)·ln(1-λ)  for x ∈ [0, 1]
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x < 0.0 or x > 1.0) return -math.inf(T);
            const c = self.normConst();
            return @log(c) + x * @log(self.lambda) + (1.0 - x) * @log(1.0 - self.lambda);
        }

        /// Cumulative distribution function
        ///
        /// F(x;λ) = (1-λ)·(1-(λ/(1-λ))^x) / (1-2λ)  for λ≠0.5
        /// F(x;0.5) = x  (Uniform limit)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            if (x >= 1.0) return 1.0;
            const d = 1.0 - 2.0 * self.lambda;
            if (@abs(d) < eps) return x;
            const r = self.lambda / (1.0 - self.lambda);
            return (1.0 - self.lambda) * (1.0 - math.pow(T, r, x)) / d;
        }

        /// Quantile function (inverse CDF) — returns x such that P(X ≤ x) = p
        ///
        /// Q(p;λ) = ln(1 - p·(1-2λ)/(1-λ)) / ln(λ/(1-λ))  for λ≠0.5
        /// Q(p;0.5) = p  (Uniform limit)
        ///
        /// Errors: error.InvalidProbability if p ∉ [0, 1] or NaN
        ///
        /// Time: O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return 1.0;
            const d = 1.0 - 2.0 * self.lambda;
            if (@abs(d) < eps) return p;
            const log_r = @log(self.lambda / (1.0 - self.lambda));
            const arg = 1.0 - p * d / (1.0 - self.lambda);
            return @log(arg) / log_r;
        }

        /// Generate a random sample using the exact inverse-CDF transform
        ///
        /// X = Q(U)  where U ~ Uniform(0, 1)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sample(self: Self, rng: anytype) T {
            const u = rng.float(T);
            if (u == 0.0) return 0.0;
            if (u == 1.0) return 1.0;
            const d = 1.0 - 2.0 * self.lambda;
            if (@abs(d) < eps) return u;
            const log_r = @log(self.lambda / (1.0 - self.lambda));
            const arg = 1.0 - u * d / (1.0 - self.lambda);
            return @log(arg) / log_r;
        }

        /// Mean of the distribution: λ/(2λ-1) - 1/ln(λ/(1-λ))  for λ≠0.5
        ///
        /// Mean = 0.5 for λ=0.5; mean > 0.5 for λ>0.5; mean < 0.5 for λ<0.5.
        /// Symmetry: mean(λ) + mean(1-λ) = 1 for all λ.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            const d = 2.0 * self.lambda - 1.0;
            if (@abs(d) < eps) return 0.5;
            const log_r = @log(self.lambda / (1.0 - self.lambda));
            return self.lambda / d - 1.0 / log_r;
        }

        /// Mode of the distribution
        ///
        /// Mode = 0.0 for λ < 0.5 (monotone decreasing PDF)
        /// Mode = 1.0 for λ > 0.5 (monotone increasing PDF)
        /// Mode = 0.5 for λ = 0.5 (Uniform — all values equally likely)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            if (self.lambda < 0.5) return 0.0;
            if (self.lambda > 0.5) return 1.0;
            return 0.5;
        }

        /// Variance: E[X²] - (E[X])² computed via 200-point Simpson's rule
        ///
        /// Variance = 1/12 for λ=0.5 (Uniform limit).
        ///
        /// Time: O(200) | Space: O(1)
        pub fn variance(self: Self) T {
            const mu = self.mean();
            const n: usize = 200;
            const h: T = 1.0 / @as(T, @floatFromInt(n));
            var e_x2: T = 0.0;
            var i: usize = 0;
            while (i <= n) : (i += 1) {
                const x = @as(T, @floatFromInt(i)) * h;
                const w: T = if (i == 0 or i == n) 1.0 else if (i % 2 == 1) 4.0 else 2.0;
                e_x2 += w * x * x * self.pdf(x);
            }
            e_x2 *= h / 3.0;
            return e_x2 - mu * mu;
        }

        /// Differential entropy: -ln(C(λ)) - ln(λ/(1-λ))·E[X] - ln(1-λ)
        ///
        /// Entropy = 0 for λ=0.5 (Uniform(0,1) limit).
        /// Entropy ≤ 0 for all λ — the distribution is always at most as spread
        /// as Uniform(0,1), which has differential entropy 0.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            const c = self.normConst();
            const mu = self.mean();
            const log_r = @log(self.lambda / (1.0 - self.lambda));
            return -@log(c) - log_r * mu - @log(1.0 - self.lambda);
        }

        /// Validate distribution parameters
        ///
        /// Returns error.InvalidParameter if lambda ∉ (0, 1) or not finite
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) !void {
            if (!(self.lambda > 0.0 and self.lambda < 1.0)) return error.InvalidParameter;
        }
    };
}

// ============================================================================
// PERT Distribution — Beta(α₁, α₂) with linear transformation [min, max]
// ============================================================================

pub fn PERT(comptime T: type) type {
    return struct {
        min: T,
        mode_val: T,
        max: T,
        shape: T,
        alpha1: T,
        alpha2: T,

        const Self = @This();

        /// Create a PERT (Program Evaluation and Review Technique) distribution
        ///
        /// Parameters:
        ///   - min: minimum value (a), must satisfy a < mode_val < max
        ///   - mode_val: most likely value (m)
        ///   - max: maximum value (b)
        ///   - shape: shape parameter λ > 0 (default 4 in PERT)
        ///
        /// Derived:
        ///   - α₁ = 1 + λ·(m - a)/(b - a)
        ///   - α₂ = 1 + λ·(b - m)/(b - a)
        ///
        /// Relationship: X = a + (b - a)·Y where Y ~ Beta(α₁, α₂)
        ///
        /// Errors: a ≥ m, m ≥ b, λ ≤ 0, or any parameter is NaN/inf
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(min: T, mode_val: T, max: T, shape: T) DistributionError!Self {
            // Check for NaN or inf in any parameter
            if (!math.isFinite(min) or !math.isFinite(mode_val) or !math.isFinite(max) or !math.isFinite(shape)) {
                return error.InvalidParameter;
            }
            // Check constraints: a < m < b and λ > 0
            if (!(min < mode_val and mode_val < max and shape > 0.0)) {
                return error.InvalidParameter;
            }
            // Compute alpha parameters
            const range = max - min;
            const alpha1 = 1.0 + shape * (mode_val - min) / range;
            const alpha2 = 1.0 + shape * (max - mode_val) / range;
            return Self{
                .min = min,
                .mode_val = mode_val,
                .max = max,
                .shape = shape,
                .alpha1 = alpha1,
                .alpha2 = alpha2,
            };
        }

        /// Probability density function
        ///
        /// f(x) = (x-a)^(α₁-1)·(b-x)^(α₂-1) / (B(α₁,α₂)·(b-a)^(α₁+α₂-1)) for x ∈ [a, b], else 0
        ///
        /// Computed via log-space for numerical stability:
        /// log f(x) = (α₁-1)·ln(y) + (α₂-1)·ln(1-y) - ln(B(α₁,α₂)) - ln(b-a)
        /// where y = (x-a)/(b-a)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x <= self.min or x >= self.max) return 0.0;
            const range = self.max - self.min;
            const y = (x - self.min) / range;
            const log_beta_const = logBeta(self.alpha1, self.alpha2);
            const log_pdf_val = (self.alpha1 - 1.0) * @log(y) + (self.alpha2 - 1.0) * @log(1.0 - y) - log_beta_const - @log(range);
            return @exp(log_pdf_val);
        }

        /// Cumulative distribution function
        ///
        /// F(x) = I((x-a)/(b-a); α₁, α₂)  where I is the regularized incomplete Beta
        ///
        /// Boundary: F(a) = 0, F(b) = 1
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= self.min) return 0.0;
            if (x >= self.max) return 1.0;
            const y = (x - self.min) / (self.max - self.min);
            return regularizedBetaI(self.alpha1, self.alpha2, y);
        }

        /// Quantile function (inverse CDF) — returns x such that P(X ≤ x) = p
        ///
        /// Uses bisection on CDF with 100 iterations to solve F(x) = p
        ///
        /// Errors: error.InvalidProbability if p ∉ [0, 1] or NaN
        ///
        /// Time: O(100) ≈ O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return self.min;
            if (p == 1.0) return self.max;

            // Bisection: find x such that cdf(x) = p
            var lo = self.min;
            var hi = self.max;
            var x: T = (lo + hi) / 2.0;
            for (0..100) |_| {
                const cdf_x = self.cdf(x);
                if (cdf_x < p) {
                    lo = x;
                } else {
                    hi = x;
                }
                x = (lo + hi) / 2.0;
            }
            return x;
        }

        /// Mean of the distribution
        ///
        /// E[X] = min + (max - min)·E[Y]  where Y ~ Beta(α₁, α₂)
        ///      = min + (max - min)·α₁/(α₁ + α₂)
        ///      = (min + shape·mode_val + max) / (shape + 2)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            return self.min + (self.max - self.min) * self.alpha1 / (self.alpha1 + self.alpha2);
        }

        /// Variance of the distribution
        ///
        /// Var[X] = (max - min)²·Var[Y]  where Y ~ Beta(α₁, α₂)
        ///        = (max - min)²·(α₁·α₂) / ((α₁+α₂)²·(α₁+α₂+1))
        ///        = (mean - min)·(max - mean) / (shape + 3)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            const mu = self.mean();
            return (mu - self.min) * (self.max - mu) / (self.shape + 3.0);
        }

        /// Mode of the distribution
        ///
        /// Always returns the mode_val parameter (the most likely value)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            return self.mode_val;
        }

        /// Differential entropy
        ///
        /// H = ln(B(α₁, α₂)) - (α₁-1)·ψ(α₁) - (α₂-1)·ψ(α₂) + (α₁+α₂-2)·ψ(α₁+α₂) + ln(b-a)
        ///
        /// where ψ is the digamma function and B is the Beta function
        ///
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            const log_beta_const = logBeta(self.alpha1, self.alpha2);
            const dg_a1 = digamma(T, self.alpha1);
            const dg_a2 = digamma(T, self.alpha2);
            const dg_sum = digamma(T, self.alpha1 + self.alpha2);
            const range = self.max - self.min;
            return log_beta_const - (self.alpha1 - 1.0) * dg_a1 - (self.alpha2 - 1.0) * dg_a2 + (self.alpha1 + self.alpha2 - 2.0) * dg_sum + @log(range);
        }

        /// Generate a random sample using the Gamma ratio method
        ///
        /// Sample Y ~ Beta(α₁, α₂) via:
        ///   g1 ~ Gamma(α₁, rate=1)
        ///   g2 ~ Gamma(α₂, rate=1)
        ///   y = g1 / (g1 + g2)
        /// Then return X = min + (max - min)·y
        ///
        /// Time: O(1) expected | Space: O(1)
        pub fn sample(self: Self, rng: anytype) T {
            // alpha1, alpha2 > 0 and rate=1.0 are guaranteed by init — Gamma.init cannot fail here
            const g1_sampler = Gamma(T).init(self.alpha1, 1.0) catch unreachable;
            const g2_sampler = Gamma(T).init(self.alpha2, 1.0) catch unreachable;
            const g1 = g1_sampler.sample(rng);
            const g2 = g2_sampler.sample(rng);
            const y = g1 / (g1 + g2);
            return self.min + (self.max - self.min) * y;
        }

        /// Validate distribution parameters
        ///
        /// Returns error.InvalidParameter if:
        ///   - min ≥ mode_val
        ///   - mode_val ≥ max
        ///   - shape ≤ 0
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) !void {
            if (!(self.min < self.mode_val and self.mode_val < self.max and self.shape > 0.0)) {
                return error.InvalidParameter;
            }
        }
    };
}

