    for (0..5000) |_| {
        sum += dist.sample(rng.random());
    }
    const sample_mean = sum / 5000.0;
    const theoretical_mean = dist.mean();
    try testing.expectApproxEqAbs(theoretical_mean, sample_mean, 0.05);
}

