/// Log-Gamma distribution — distribution of Y = log(X) where X ~ Gamma(α, β).
///
/// If X follows a Gamma(α, β) distribution [rate parameterization], then Y = log(X)
/// follows the LogGamma(α, β) distribution. Natural complement to LogNormal and LogLogistic.
///
/// Parameters: α > 0 (shape), β > 0 (rate of underlying Gamma)
/// Support: ℝ = (−∞, +∞)
/// PDF: f(y) = β^α / Γ(α) · exp(α·y − β·exp(y))
/// CDF: F(y) = P(α, β·exp(y))  [regularized incomplete gamma]
/// Mean: ψ(α) − log(β)
/// Variance: ψ'(α) = trigamma(α)  [independent of β — β is a location shift in log-space]
/// Mode: log(α/β)
/// Entropy: lgamma(α) + α·(1 − ψ(α))  [independent of β]
/// Special case: α=1, β=1 → −Y ~ Gumbel(0, 1)
pub fn LogGamma(comptime T: type) type {
    return struct {
        const Self = @This();

        alpha: T,
        beta: T,
        /// Precomputed log-normalizing constant: α·log(β) − lgamma(α)
        _log_norm: T,

        /// Initialize LogGamma distribution.
        /// Returns error.InvalidParameter if α ≤ 0 or β ≤ 0.
        /// Time: O(1) | Space: O(1)
        pub fn init(alpha: T, beta: T) DistributionError!Self {
            if (!(alpha > 0.0)) return error.InvalidParameter;
            if (!(beta > 0.0)) return error.InvalidParameter;
            return Self{
                .alpha = alpha,
                .beta = beta,
                ._log_norm = alpha * @log(beta) - logGamma(alpha),
            };
        }

        /// Log probability density function: α·log(β) − lgamma(α) + α·y − β·exp(y).
        /// Time: O(1) | Space: O(1)
        pub fn logPdf(self: Self, y: T) T {
            return self._log_norm + self.alpha * y - self.beta * @exp(y);
        }

        /// Probability density function: exp(logPdf(y)).
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, y: T) T {
            return @exp(self.logPdf(y));
        }

        /// Cumulative distribution function: P(α, β·exp(y)).
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, y: T) T {
            return regularizedGammaP(self.alpha, self.beta * @exp(y));
        }

        /// Survival function: 1 − CDF(y).
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, y: T) T {
            return 1.0 - self.cdf(y);
        }

        /// Quantile function via bisection on the CDF.
        /// Returns error.InvalidProbability if p ∉ [0, 1].
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return -math.inf(T);
            if (p == 1.0) return math.inf(T);

            var lo: T = -500.0;
            var hi: T = 50.0;
            while (self.cdf(lo) >= p) lo -= 100.0;
            while (self.cdf(hi) <= p) hi += 10.0;

            var i: usize = 0;
            while (i < 100) : (i += 1) {
                const mid = (lo + hi) / 2.0;
                if (self.cdf(mid) < p) {
                    lo = mid;
                } else {
                    hi = mid;
                }
            }
            return (lo + hi) / 2.0;
        }

        /// Random sample: generate G ~ Gamma(α, β) and return log(G).
        /// Time: O(1) amortized | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const g = Gamma(T){ .shape = self.alpha, .rate = self.beta };
            return @log(g.sample(rng));
        }

        /// Expected value: ψ(α) − log(β).
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            return digamma(T, self.alpha) - @log(self.beta);
        }

        /// Variance: ψ'(α) = trigamma(α). Independent of β.
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            return trigamma(T, self.alpha);
        }

        /// Mode: log(α/β).
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            return @log(self.alpha / self.beta);
        }

        /// Differential entropy: lgamma(α) + α·(1 − ψ(α)). Independent of β.
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            return logGamma(self.alpha) + self.alpha * (1.0 - digamma(T, self.alpha));
        }

        /// Validate distribution parameters.
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) !void {
            if (!(self.alpha > 0.0)) return error.InvalidParameter;
            if (!(self.beta > 0.0)) return error.InvalidParameter;
        }
    };
}
