test "ShiftedGompertz: sf + cdf = 1" {
    const dist = try ShiftedGompertz(f64).init(1.0, 1.0);
    const x_vals = [_]f64{ 0.0, 0.5, 1.0, 2.0, 3.0, 5.0 };
    for (x_vals) |x| {
        const sum = dist.cdf(x) + dist.sf(x);
        try std.testing.expectApproxEqAbs(1.0, sum, 1e-10);
    }
}

