test "Biweight: quantile roundtrip cdf->quantile for p=0.25" {
    const dist = try Biweight(f64).init(0.0, 1.0);
    const q = try dist.quantile(0.25);
    const c = dist.cdf(q);
    try std.testing.expectApproxEqAbs(0.25, c, 1e-9);
