test "Triweight: init with valid parameters (mu=0, h=1)" {
    const dist = try Triweight(f64).init(0.0, 1.0);
    try std.testing.expectApproxEqAbs(0.0, dist.mu, 1e-10);
    try std.testing.expectApproxEqAbs(1.0, dist.h, 1e-10);
}

