    const m = dist.mode();
    // mode = (nu * scale2) / (nu + 2) = 4/6 ≈ 0.66667
    try testing.expectApproxEqAbs(2.0 / 3.0, m, 1e-10);
}

test "ScaledInverseChiSquared: mode for nu=4, scale2=2" {
    const dist = try ScaledInverseChiSquared(f64).init(4.0, 2.0);
    const m = dist.mode();
    // mode = (4 * 2) / (4 + 2) ≈ 1.33333
    try testing.expectApproxEqAbs(4.0 / 3.0, m, 1e-10);
}

test "ScaledInverseChiSquared: mode for nu=6, scale2=1" {
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 1.0);
    const m = dist.mode();
    // mode = 6 / 8 = 0.75
    try testing.expectApproxEqAbs(0.75, m, 1e-10);
}

test "ScaledInverseChiSquared: mean for nu=4, scale2=1" {
    const dist = try ScaledInverseChiSquared(f64).init(4.0, 1.0);
    const mn = dist.mean();
    // mean = (nu * scale2) / (nu - 2) = 4/2 = 2.0
    try testing.expectApproxEqAbs(2.0, mn, 1e-10);
}

test "ScaledInverseChiSquared: mean for nu=6, scale2=2" {
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 2.0);
    const mn = dist.mean();
    // mean = (6 * 2) / (6 - 2) = 12/4 = 3.0
    try testing.expectApproxEqAbs(3.0, mn, 1e-10);
}

test "ScaledInverseChiSquared: mean for nu <= 2 is infinity" {
    const dist_nu2 = try ScaledInverseChiSquared(f64).init(2.0, 1.0);
    try testing.expect(dist_nu2.mean() == math.inf(f64));
    const dist_nu1 = try ScaledInverseChiSquared(f64).init(1.0, 1.0);
    try testing.expect(dist_nu1.mean() == math.inf(f64));
}

test "ScaledInverseChiSquared: variance for nu=6, scale2=1" {
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 1.0);
    const v = dist.variance();
    // variance = 2*nu²*scale2² / ((nu-2)²*(nu-4))
    // = 2*36*1 / (16*2) = 72/32 = 2.25
    try testing.expectApproxEqAbs(2.25, v, 1e-10);
}

test "ScaledInverseChiSquared: variance for nu=6, scale2=2" {
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 2.0);
    const v = dist.variance();
    // variance = 2*36*4 / (16*2) = 288/32 = 9.0
    try testing.expectApproxEqAbs(9.0, v, 1e-10);
}

test "ScaledInverseChiSquared: variance for nu=8, scale2=1" {
    const dist = try ScaledInverseChiSquared(f64).init(8.0, 1.0);
    const v = dist.variance();
    // variance = 2*64*1 / (36*4) = 128/144 ≈ 0.88889
    try testing.expectApproxEqAbs(128.0 / 144.0, v, 1e-6);
}

test "ScaledInverseChiSquared: variance for nu <= 4 is infinity" {
    const dist_nu4 = try ScaledInverseChiSquared(f64).init(4.0, 1.0);
    try testing.expect(dist_nu4.variance() == math.inf(f64));
    const dist_nu2 = try ScaledInverseChiSquared(f64).init(2.0, 1.0);
    try testing.expect(dist_nu2.variance() == math.inf(f64));
}

test "ScaledInverseChiSquared: entropy for nu=4, scale2=1" {
    const dist = try ScaledInverseChiSquared(f64).init(4.0, 1.0);
    const ent = dist.entropy();
    // ScaledInvChiSq(4,1) ≡ InvGamma(2,2); entropy≈1.4248
    try testing.expectApproxEqAbs(1.4248, ent, 0.001);
}

test "ScaledInverseChiSquared: entropy is finite" {
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 1.0);
    const ent = dist.entropy();
    try testing.expect(math.isFinite(ent));
}

test "ScaledInverseChiSquared: sample returns positive values" {
    var rng = std.Random.DefaultPrng.init(42);
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 1.0);
    for (0..100) |_| {
        const s = dist.sample(rng.random());
        try testing.expect(s > 0);
    }
}

test "ScaledInverseChiSquared: sample convergence to mean" {
    var rng = std.Random.DefaultPrng.init(123);
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 1.0);
    var sum: f64 = 0.0;
    const n = 5000;
    for (0..n) |_| {
        sum += dist.sample(rng.random());
    }
    const sample_mean = sum / @as(f64, @floatFromInt(n));
    const expected_mean = dist.mean();
    try testing.expectApproxEqAbs(expected_mean, sample_mean, 0.05);
}

test "ScaledInverseChiSquared: validate passes for valid params" {
    const dist = try ScaledInverseChiSquared(f64).init(4.0, 1.0);
    try dist.validate();
}

test "ScaledInverseChiSquared: validate passes for scale2 != 1" {
    const dist = try ScaledInverseChiSquared(f64).init(6.0, 2.5);
    try dist.validate();
}

test "ScaledInverseChiSquared: format output contains nu and scale2" {
    const dist = try ScaledInverseChiSquared(f64).init(4.0, 2.0);
    var buf: [64]u8 = undefined;
    var stream = std.io.fixedBufferStream(&buf);
    try dist.format("", std.fmt.FormatOptions{}, stream.writer());
    const output = stream.getWritten();
    try testing.expect(std.mem.containsAtLeast(u8, output, 1, "4"));
    try testing.expect(std.mem.containsAtLeast(u8, output, 1, "2"));
}

test "ScaledInverseChiSquared: f32 type support" {
    const dist = try ScaledInverseChiSquared(f32).init(4.0, 1.0);
    try testing.expect(math.isFinite(dist.pdf(1.0)));
    const q = try dist.quantile(0.5);
    try testing.expect(q > 0);
    const m = dist.mode();
    try testing.expect(math.isFinite(m));
    try testing.expect(m > 0);
}

// ============================================================================
// Exponentiated Weibull Distribution
// ============================================================================

/// Exponentiated Weibull distribution EW(α, λ, k)
///
/// CDF: F(x) = [1 − exp(−(x/λ)^k)]^α for x > 0
///
/// Parameters:
///   - alpha (α): Exponent shape parameter (α > 0)
///   - scale (λ): Scale parameter (λ > 0)
///   - shape (k): Weibull shape parameter (k > 0)
///
/// Support: (0, ∞)
///
/// Mean: α·λ·Γ(1+1/k) · Σ_{j≥0} (−1)^j·C(α−1,j)/(j+1)^{1+1/k}
/// Mode: 0 if αk ≤ 1; λ·u*^{1/k} where u* solves (k−1)−ku+(α−1)ku·e^{−u}/(1−e^{−u})=0
///
/// Time: O(1) for pdf/cdf/quantile/sample | O(N) for mean/variance/entropy
pub fn ExponentiatedWeibull(comptime T: type) type {
    return struct {
        alpha: T,
        scale: T,
        shape: T,

        const Self = @This();

        /// Create an ExponentiatedWeibull distribution.
        ///
        /// Errors: any parameter ≤ 0 or non-finite.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(alpha: T, scale: T, shape: T) DistributionError!Self {
            if (!(alpha > 0.0) or !math.isFinite(alpha)) return error.InvalidParameter;
            if (!(scale > 0.0) or !math.isFinite(scale)) return error.InvalidParameter;
            if (!(shape > 0.0) or !math.isFinite(shape)) return error.InvalidParameter;
            return Self{ .alpha = alpha, .scale = scale, .shape = shape };
        }

        /// Log probability density function at x.
        ///
        /// log f(x) = log(αk/λ) + (k−1)·log(x/λ) − (x/λ)^k + (α−1)·log(1−e^{−(x/λ)^k})
        ///
        /// Returns −∞ for x ≤ 0.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= 0.0) return -math.inf(T);
            const scaled = x / self.scale;
            const uk = math.pow(T, scaled, self.shape);
            const g = 1.0 - @exp(-uk);
            if (g <= 0.0) return -math.inf(T);
            return @log(self.alpha) + @log(self.shape) - @log(self.scale) +
                (self.shape - 1.0) * @log(scaled) - uk +
                (self.alpha - 1.0) * @log(g);
        }

        /// Probability density function at x.
        ///
        /// f(x) = (αk/λ)·(x/λ)^{k−1}·exp(−(x/λ)^k)·[1−exp(−(x/λ)^k)]^{α−1}
        ///
        /// Returns 0 for x ≤ 0.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            return @exp(self.logpdf(x));
        }

        /// Cumulative distribution function at x.
        ///
        /// F(x) = [1 − exp(−(x/λ)^k)]^α
        ///
        /// Returns 0 for x ≤ 0.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            const uk = math.pow(T, x / self.scale, self.shape);
            const g = 1.0 - @exp(-uk);
            if (g <= 0.0) return 0.0;
            return math.pow(T, g, self.alpha);
        }

        /// Survival function: P(X > x) = 1 − F(x).
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            return 1.0 - self.cdf(x);
        }

        /// Quantile function: Q(p) = λ·[−ln(1 − p^{1/α})]^{1/k}.
        ///
        /// Q(0) = 0, Q(1) = +∞.
        ///
        /// Errors: !(p ≥ 0 ∧ p ≤ 1)
        ///
        /// Time: O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            return self.quantileRaw(p);
        }

        fn quantileRaw(self: Self, p: T) T {
            if (p <= 0.0) return 0.0;
            if (p >= 1.0) return math.inf(T);
            const p1a = math.pow(T, p, 1.0 / self.alpha);
            const inner = -@log(1.0 - p1a);
            return self.scale * math.pow(T, inner, 1.0 / self.shape);
        }

        // E[X^r] via convergent binomial series:
        // E[X^r] = α·λ^r·Γ(1+r/k) · Σ_{j≥0} (−1)^j·C(α−1,j)/(j+1)^{1+r/k}
        // b_0=1, b_{j+1} = b_j·(α−1−j)/(j+1)
        fn momentR(self: Self, r: T) T {
            const s = 1.0 + r / self.shape;
            const gs = @exp(logGamma(s));
            var sum: T = 0.0;
            var b: T = 1.0;
            var j: usize = 0;
            while (j < 500) : (j += 1) {
                const jf: T = @floatFromInt(j);
                const denom = math.pow(T, jf + 1.0, s);
                if (!math.isFinite(denom) or denom == 0.0) break;
                const sign: T = if (j % 2 == 0) 1.0 else -1.0;
                const term = sign * b / denom;
                sum += term;
                if (@abs(term) < 1e-14 * @abs(sum) + 1e-300) break;
                b = b * (self.alpha - 1.0 - jf) / (jf + 1.0);
            }
            return self.alpha * math.pow(T, self.scale, r) * gs * sum;
        }

        /// Mean of the distribution via generalized binomial series.
        ///
        /// E[X] = α·λ·Γ(1+1/k) · Σ_{j≥0} (−1)^j·C(α−1,j)/(j+1)^{1+1/k}
        ///
        /// Time: O(α) for integer α, O(500) worst case | Space: O(1)
        pub fn mean(self: Self) T {
            return self.momentR(1.0);
        }

        /// Variance of the distribution: E[X²] − E[X]².
        ///
        /// Time: O(α) for integer α, O(500) worst case | Space: O(1)
        pub fn variance(self: Self) T {
            const ex = self.mean();
            const ex2 = self.momentR(2.0);
            return @max(0.0, ex2 - ex * ex);
        }

        // h(u) for mode bisection: (k−1) − k·u + (α−1)·k·u·e^{−u}/(1−e^{−u})
        // h(0+) = αk−1 > 0 (when αk > 1), h(∞) → −∞
        fn hMode(alpha_: T, shape_: T, u: T) T {
            const eu = @exp(-u);
            const g = 1.0 - eu;
            if (g < 1e-300) return alpha_ * shape_ - 1.0;
            return (shape_ - 1.0) - shape_ * u + (alpha_ - 1.0) * shape_ * u * eu / g;
        }

        /// Mode of the distribution.
        ///
        /// Returns 0 if α·k ≤ 1 (PDF decreasing from origin or pole at origin).
        /// Otherwise bisects h(u) = (k−1)−ku+(α−1)ku·e^{−u}/(1−e^{−u}) = 0 for u*,
        /// then mode = λ·u*^{1/k}.
        ///
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn mode(self: Self) T {
            if (self.alpha * self.shape <= 1.0) return 0.0;
            var lo: T = 1e-10;
            var hi: T = 1000.0;
            var guard: usize = 0;
            while (hMode(self.alpha, self.shape, hi) >= 0.0 and guard < 50) : (guard += 1) {
                hi *= 2.0;
            }
            var iter: usize = 0;
            while (iter < 100) : (iter += 1) {
                const mid = (lo + hi) / 2.0;
                if (hi - lo < 1e-10) break;
                if (hMode(self.alpha, self.shape, mid) > 0.0) {
                    lo = mid;
                } else {
                    hi = mid;
                }
            }
            return self.scale * math.pow(T, (lo + hi) / 2.0, 1.0 / self.shape);
        }

        /// Differential entropy estimated via 500-point midpoint quadrature.
        ///
        /// H ≈ −(1/500)·Σ_i logpdf(Q((i+0.5)/500))
        ///
        /// Time: O(500) | Space: O(1)
        pub fn entropy(self: Self) T {
            const N: usize = 500;
            const Nf: T = @floatFromInt(N);
            var sum: T = 0.0;
            var i: usize = 0;
            while (i < N) : (i += 1) {
                const p: T = (@as(T, @floatFromInt(i)) + 0.5) / Nf;
                const x = self.quantileRaw(p);
                sum -= self.logpdf(x);
            }
            return sum / Nf;
        }

        /// Generate a random sample via inverse CDF.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            return self.quantileRaw(rng.float(T));
        }

        /// Validate parameters: α > 0, λ > 0, k > 0, all finite.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (!(self.alpha > 0.0) or !math.isFinite(self.alpha)) return error.InvalidParameter;
            if (!(self.scale > 0.0) or !math.isFinite(self.scale)) return error.InvalidParameter;
            if (!(self.shape > 0.0) or !math.isFinite(self.shape)) return error.InvalidParameter;
        }

        /// Format the distribution for display.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn format(self: Self, comptime fmt: []const u8, options: std.fmt.FormatOptions, writer: anytype) !void {
            _ = fmt;
            _ = options;
            try writer.print("EW(α={d:.4}, λ={d:.4}, k={d:.4})", .{ self.alpha, self.scale, self.shape });
        }
    };
}

// Exponentiated Weibull Distribution Tests

test "ExponentiatedWeibull: init with valid parameters" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 1.0);
    try expectEqual(@as(f64, 2.0), dist.alpha);
    try expectEqual(@as(f64, 1.0), dist.scale);
    try expectEqual(@as(f64, 1.0), dist.shape);
}

test "ExponentiatedWeibull: init with various valid parameters" {
    _ = try ExponentiatedWeibull(f64).init(0.5, 2.5, 3.0);
    _ = try ExponentiatedWeibull(f64).init(5.0, 0.1, 0.5);
    _ = try ExponentiatedWeibull(f64).init(1.0, 1.0, 1.0);
}

test "ExponentiatedWeibull: init rejects alpha = 0" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(0.0, 1.0, 1.0));
}

test "ExponentiatedWeibull: init rejects negative alpha" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(-1.0, 1.0, 1.0));
}

test "ExponentiatedWeibull: init rejects NaN alpha" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(math.nan(f64), 1.0, 1.0));
}

test "ExponentiatedWeibull: init rejects inf alpha" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(math.inf(f64), 1.0, 1.0));
}

test "ExponentiatedWeibull: init rejects scale = 0" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, 0.0, 1.0));
}

test "ExponentiatedWeibull: init rejects negative scale" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, -1.0, 1.0));
}

test "ExponentiatedWeibull: init rejects NaN scale" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, math.nan(f64), 1.0));
}

test "ExponentiatedWeibull: init rejects inf scale" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, math.inf(f64), 1.0));
}

test "ExponentiatedWeibull: init rejects shape = 0" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, 1.0, 0.0));
}

test "ExponentiatedWeibull: init rejects negative shape" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, 1.0, -1.0));
}

test "ExponentiatedWeibull: init rejects NaN shape" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, 1.0, math.nan(f64)));
}

test "ExponentiatedWeibull: init rejects inf shape" {
    try expectError(error.InvalidParameter, ExponentiatedWeibull(f64).init(1.0, 1.0, math.inf(f64)));
}

test "ExponentiatedWeibull: pdf returns 0 for x <= 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expectEqual(@as(f64, 0.0), dist.pdf(0.0));
    try expectEqual(@as(f64, 0.0), dist.pdf(-1.0));
}

test "ExponentiatedWeibull: pdf positive for x > 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expect(dist.pdf(0.5) > 0.0);
    try expect(dist.pdf(1.0) > 0.0);
    try expect(dist.pdf(2.0) > 0.0);
}

test "ExponentiatedWeibull: pdf exact value at x=1 with alpha=2, scale=1, shape=2" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    // f = 4·e^{-1}·(1-e^{-1}) = 4·e^{-1}·e^{-1}/(e^{-1}... = 4(e^{-1}-e^{-2}) ≈ 0.93018
    try expectApproxEqAbs(@as(f64, 0.93018), dist.pdf(1.0), 0.001);
}

test "ExponentiatedWeibull: pdf monotone decreasing for alpha*shape < 1" {
    // alpha=0.5, shape=1: alpha*shape=0.5 < 1 → PDF decreases from infinity at origin
    const dist = try ExponentiatedWeibull(f64).init(0.5, 1.0, 1.0);
    try expect(dist.pdf(0.01) > dist.pdf(0.1));
    try expect(dist.pdf(0.1) > dist.pdf(1.0));
}

test "ExponentiatedWeibull: logpdf returns -inf for x <= 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expect(dist.logpdf(0.0) == -math.inf(f64));
    try expect(dist.logpdf(-1.0) == -math.inf(f64));
}

test "ExponentiatedWeibull: logpdf equals log(pdf) for x > 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const x = 0.75;
    try expectApproxEqAbs(@log(dist.pdf(x)), dist.logpdf(x), 1e-10);
}

test "ExponentiatedWeibull: cdf returns 0 at x <= 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expectEqual(@as(f64, 0.0), dist.cdf(0.0));
    try expectEqual(@as(f64, 0.0), dist.cdf(-1.0));
}

test "ExponentiatedWeibull: cdf exact value at x=1 with alpha=2, scale=1, shape=2" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    // F = (1-e^{-1})^2 ≈ 0.39958
    try expectApproxEqAbs(@as(f64, 0.39958), dist.cdf(1.0), 0.0001);
}

test "ExponentiatedWeibull: cdf is monotone increasing" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expect(dist.cdf(0.5) < dist.cdf(1.0));
    try expect(dist.cdf(1.0) < dist.cdf(2.0));
    try expect(dist.cdf(2.0) < dist.cdf(5.0));
}

test "ExponentiatedWeibull: cdf approaches 1 for large x" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expect(dist.cdf(100.0) > 0.999);
}

test "ExponentiatedWeibull: cdf + sf = 1" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const x = 0.75;
    try expectApproxEqAbs(@as(f64, 1.0), dist.cdf(x) + dist.sf(x), 1e-14);
}

test "ExponentiatedWeibull: sf returns 1 at x = 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expectEqual(@as(f64, 1.0), dist.sf(0.0));
}

test "ExponentiatedWeibull: quantile Q(0) = 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expectEqual(@as(f64, 0.0), try dist.quantile(0.0));
}

test "ExponentiatedWeibull: quantile Q(1) = +inf" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expect(try dist.quantile(1.0) == math.inf(f64));
}

test "ExponentiatedWeibull: quantile rejects p < 0" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expectError(error.InvalidProbability, dist.quantile(-0.1));
}

test "ExponentiatedWeibull: quantile rejects p > 1" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expectError(error.InvalidProbability, dist.quantile(1.1));
}

test "ExponentiatedWeibull: quantile rejects NaN" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expectError(error.InvalidProbability, dist.quantile(math.nan(f64)));
}

test "ExponentiatedWeibull: quantile roundtrip cdf(Q(p)) = p at p=0.25" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const q = try dist.quantile(0.25);
    try expectApproxEqAbs(@as(f64, 0.25), dist.cdf(q), 1e-10);
}

test "ExponentiatedWeibull: quantile roundtrip cdf(Q(p)) = p at p=0.5" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const q = try dist.quantile(0.5);
    try expectApproxEqAbs(@as(f64, 0.5), dist.cdf(q), 1e-10);
}

test "ExponentiatedWeibull: quantile roundtrip cdf(Q(p)) = p at p=0.75" {
    const dist = try ExponentiatedWeibull(f64).init(3.0, 2.0, 1.5);
    const q = try dist.quantile(0.75);
    try expectApproxEqAbs(@as(f64, 0.75), dist.cdf(q), 1e-10);
}

test "ExponentiatedWeibull: mean = 1.5 for alpha=2, scale=1, shape=1" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 1.0);
    // Exact: 2·Γ(2)·(1/1^2 - 1/2^2) = 2·1·(1-0.25) = 1.5
    try expectApproxEqAbs(@as(f64, 1.5), dist.mean(), 1e-6);
}

test "ExponentiatedWeibull: mean = scale*Gamma(1+1/shape) for alpha=1 (Weibull special case)" {
    const dist = try ExponentiatedWeibull(f64).init(1.0, 2.0, 3.0);
    // E[X] = 2·Γ(4/3) ≈ 2·0.89298 ≈ 1.78596
    try expectApproxEqAbs(@as(f64, 2.0 * 0.89298), dist.mean(), 0.001);
}

test "ExponentiatedWeibull: mean increases with scale" {
    const dist1 = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const dist2 = try ExponentiatedWeibull(f64).init(2.0, 2.0, 2.0);
    try expect(dist2.mean() > dist1.mean());
}

test "ExponentiatedWeibull: variance positive for valid params" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expect(dist.variance() > 0.0);
}

test "ExponentiatedWeibull: variance matches Weibull for alpha=1, scale=1, shape=2" {
    const dist = try ExponentiatedWeibull(f64).init(1.0, 1.0, 2.0);
    // Weibull(k=2,λ=1) variance = Γ(2) - Γ(3/2)^2 = 1 - π/4 ≈ 0.21460
    try expectApproxEqAbs(@as(f64, 1.0 - math.pi / 4.0), dist.variance(), 1e-5);
}

test "ExponentiatedWeibull: mode = 0 when alpha*shape <= 1" {
    const dist = try ExponentiatedWeibull(f64).init(0.5, 1.0, 1.0);
    try expectEqual(@as(f64, 0.0), dist.mode());
}

test "ExponentiatedWeibull: mode = 0 when alpha*shape = 1 exactly" {
    const dist = try ExponentiatedWeibull(f64).init(1.0, 1.0, 1.0);
    try expectEqual(@as(f64, 0.0), dist.mode());
}

test "ExponentiatedWeibull: mode = ln(2) for alpha=2, scale=1, shape=1" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 1.0);
    // k=1: u* = ln(alpha) = ln(2), mode = scale * ln(2)^(1/1)
    try expectApproxEqAbs(@log(@as(f64, 2.0)), dist.mode(), 1e-4);
}

test "ExponentiatedWeibull: mode = 1/sqrt(2) for alpha=1, scale=1, shape=2" {
    const dist = try ExponentiatedWeibull(f64).init(1.0, 1.0, 2.0);
    // Weibull(k=2,λ=1) mode = ((k-1)/k)^(1/k) = (1/2)^(1/2) = 1/sqrt(2)
    try expectApproxEqAbs(@as(f64, 1.0 / @sqrt(2.0)), dist.mode(), 1e-4);
}

test "ExponentiatedWeibull: mode scales with scale parameter" {
    const dist1 = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const dist2 = try ExponentiatedWeibull(f64).init(2.0, 3.0, 2.0);
    try expectApproxEqAbs(@as(f64, 3.0) * dist1.mode(), dist2.mode(), 1e-8);
}

test "ExponentiatedWeibull: entropy is finite for valid params" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try expect(math.isFinite(dist.entropy()));
}

test "ExponentiatedWeibull: entropy increases with scale" {
    const dist1 = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const dist2 = try ExponentiatedWeibull(f64).init(2.0, 2.0, 2.0);
    // Larger scale → larger entropy (H_λ = H_1 + ln(λ))
    try expect(dist2.entropy() > dist1.entropy());
}

test "ExponentiatedWeibull: sample generates positive values" {
    var prng = std.Random.DefaultPrng.init(42);
    const rng = prng.random();
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    var i: usize = 0;
    while (i < 200) : (i += 1) {
        const s = dist.sample(rng);
        try expect(s >= 0.0 and math.isFinite(s));
    }
}

test "ExponentiatedWeibull: sample mean converges to distribution mean" {
    var prng = std.Random.DefaultPrng.init(99);
    const rng = prng.random();
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    const expected_mean = dist.mean();
    var sum: f64 = 0.0;
    const n: usize = 5000;
    var i: usize = 0;
    while (i < n) : (i += 1) {
        sum += dist.sample(rng);
    }
    try expectApproxEqAbs(expected_mean, sum / @as(f64, @floatFromInt(n)), 0.1);
}

test "ExponentiatedWeibull: validate passes for valid params" {
    const dist = try ExponentiatedWeibull(f64).init(2.0, 1.0, 2.0);
    try dist.validate();
}

test "ExponentiatedWeibull: f32 type support" {
    const dist = try ExponentiatedWeibull(f32).init(2.0, 1.0, 2.0);
    try expect(dist.pdf(1.0) > 0.0);
    try expect(dist.cdf(1.0) > 0.0 and dist.cdf(1.0) < 1.0);
    const q = try dist.quantile(0.5);
    try expect(q > 0.0 and math.isFinite(q));
    try expect(math.isFinite(dist.mean()));
    try dist.validate();
}

// ============================================================================
// U-Quadratic Distribution
// ============================================================================

/// U-Quadratic distribution on a bounded interval [a, b].
///
/// The PDF is a upward-opening parabola:
///   f(x) = α·(x − β)²   for x ∈ [a, b]
///
/// where β = (a+b)/2 (midpoint) and α = 12/(b−a)³ (normalising constant).
///
/// The density is zero at the centre (antimode) and maximum 3/(b−a) at both
/// endpoints, giving the characteristic U-shape from which the distribution
/// takes its name.
///
/// Parameters:
///   a — lower bound (finite)
///   b — upper bound (finite, b > a)
///
/// Key properties (exact closed forms):
///   CDF:      F(x) = 4/(b−a)³ · [(x−β)³ + ((b−a)/2)³]
///   Quantile: Q(p) = β + (b−a)/2 · ∛(2p−1)
///   Mean:     β = (a+b)/2
///   Variance: 3(b−a)²/20
///   Entropy:  ln((b−a)/3) + 2/3  nats
///
/// Mode: bimodal — modes at both a and b; antimode at β.
///   mode() returns the lower mode a.
///
/// Time: O(1) for all operations
pub fn UQuadratic(comptime T: type) type {
    return struct {
        a: T,
        b: T,

        const Self = @This();

        /// Create a UQuadratic distribution on [a, b].
        ///
        /// Errors: a ≥ b, or either parameter non-finite.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(a: T, b: T) DistributionError!Self {
            if (!math.isFinite(a) or !math.isFinite(b)) return error.InvalidParameter;
            if (!(b > a)) return error.InvalidParameter;
            return Self{ .a = a, .b = b };
        }

        /// Log probability density function at x.
        ///
        /// log f(x) = log(α) + 2·log|x − β|   for x ∈ (a, b), x ≠ β
        /// Returns −∞ outside [a, b] and at x = β (antimode).
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x < self.a or x > self.b) return -math.inf(T);
            const beta = (self.a + self.b) / 2.0;
            const dx = x - beta;
            if (dx == 0.0) return -math.inf(T);
            const span = self.b - self.a;
            const log_alpha = @log(@as(T, 12.0)) - 3.0 * @log(span);
            return log_alpha + 2.0 * @log(@abs(dx));
        }

        /// Probability density function at x.
        ///
        /// f(x) = 12/(b−a)³ · (x−β)²   for x ∈ [a, b]
        /// Returns 0 outside [a, b].
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x < self.a or x > self.b) return 0.0;
            const beta = (self.a + self.b) / 2.0;
            const span = self.b - self.a;
            const alpha = 12.0 / (span * span * span);
            const dx = x - beta;
            return alpha * dx * dx;
        }

        /// Cumulative distribution function at x.
        ///
        /// F(x) = 4/(b−a)³ · [(x−β)³ + ((b−a)/2)³]
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= self.a) return 0.0;
            if (x >= self.b) return 1.0;
            const beta = (self.a + self.b) / 2.0;
            const span = self.b - self.a;
            const half = span / 2.0;
            const dx = x - beta;
            return 4.0 / (span * span * span) * (dx * dx * dx + half * half * half);
        }

        /// Quantile function (inverse CDF).
        ///
        /// Q(p) = β + (b−a)/2 · ∛(2p−1)   — exact closed form
        ///
        /// Errors: p outside [0, 1] or NaN.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return self.a;
            if (p == 1.0) return self.b;
            const beta = (self.a + self.b) / 2.0;
            const half = (self.b - self.a) / 2.0;
            return beta + half * math.cbrt(2.0 * p - 1.0);
        }

        /// Sample a value from the distribution using the inverse-CDF method.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const u = rng.float(T);
            return self.quantile(u) catch unreachable;
        }

        /// Mean of the distribution: β = (a+b)/2.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mean(self: Self) T {
            return (self.a + self.b) / 2.0;
        }

        /// Variance of the distribution: 3(b−a)²/20.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn variance(self: Self) T {
            const span = self.b - self.a;
            return 3.0 * span * span / 20.0;
        }

        /// Mode of the distribution.
        ///
        /// The U-quadratic is bimodal with modes at both a and b (the endpoints)
        /// and an antimode (minimum) at β = (a+b)/2.
        /// Returns the lower mode a.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            return self.a;
        }

        /// Shannon differential entropy in nats: ln((b−a)/3) + 2/3.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn entropy(self: Self) T {
            return @log((self.b - self.a) / 3.0) + 2.0 / 3.0;
        }

        /// Validate internal invariants.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (!math.isFinite(self.a) or !math.isFinite(self.b)) return error.InvalidParameter;
            if (!(self.b > self.a)) return error.InvalidParameter;
        }

        /// Format the distribution for display.
        pub fn format(self: Self, comptime fmt: []const u8, options: std.fmt.FormatOptions, writer: anytype) !void {
            _ = fmt;
            _ = options;
            try writer.print("UQuadratic(a={d}, b={d})", .{ self.a, self.b });
        }
    };
}

test "UQuadratic: init rejects a >= b" {
    try expectError(error.InvalidParameter, UQuadratic(f64).init(1.0, 0.0));
    try expectError(error.InvalidParameter, UQuadratic(f64).init(1.0, 1.0));
}

test "UQuadratic: init rejects non-finite parameters" {
    try expectError(error.InvalidParameter, UQuadratic(f64).init(math.inf(f64), 1.0));
    try expectError(error.InvalidParameter, UQuadratic(f64).init(0.0, math.nan(f64)));
}

test "UQuadratic: pdf is zero outside support" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectEqual(@as(f64, 0.0), dist.pdf(-0.1));
    try expectEqual(@as(f64, 0.0), dist.pdf(2.1));
}

test "UQuadratic: pdf at boundaries equals 3/(b-a)" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    // pdf(a) = pdf(b) = 3/(b-a) = 3/2 = 1.5
    try expectApproxEqAbs(@as(f64, 1.5), dist.pdf(0.0), 1e-14);
    try expectApproxEqAbs(@as(f64, 1.5), dist.pdf(2.0), 1e-14);
}

test "UQuadratic: pdf at antimode (centre) is zero" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectEqual(@as(f64, 0.0), dist.pdf(1.0));
}

test "UQuadratic: pdf at interior point" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    // pdf(1.5) = (3/2)·(0.5)² = 3/8 = 0.375
    try expectApproxEqAbs(@as(f64, 0.375), dist.pdf(1.5), 1e-14);
    // Symmetric: pdf(0.5) = pdf(1.5)
    try expectApproxEqAbs(@as(f64, 0.375), dist.pdf(0.5), 1e-14);
}

test "UQuadratic: pdf on [0,1] at boundaries equals 3" {
    const dist = try UQuadratic(f64).init(0.0, 1.0);
    try expectApproxEqAbs(@as(f64, 3.0), dist.pdf(0.0), 1e-14);
    try expectApproxEqAbs(@as(f64, 3.0), dist.pdf(1.0), 1e-14);
}

test "UQuadratic: logpdf matches log(pdf) at interior points" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    for ([_]f64{ 0.1, 0.5, 1.5, 1.9 }) |x| {
        const lp = dist.logpdf(x);
        const p = dist.pdf(x);
        try expectApproxEqAbs(@log(p), lp, 1e-12);
    }
}

test "UQuadratic: logpdf is -inf outside support" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectEqual(-math.inf(f64), dist.logpdf(-1.0));
    try expectEqual(-math.inf(f64), dist.logpdf(3.0));
}

test "UQuadratic: logpdf is -inf at antimode" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectEqual(-math.inf(f64), dist.logpdf(1.0));
}

test "UQuadratic: cdf at bounds" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectEqual(@as(f64, 0.0), dist.cdf(-1.0));
    try expectEqual(@as(f64, 0.0), dist.cdf(0.0));
    try expectEqual(@as(f64, 1.0), dist.cdf(2.0));
    try expectEqual(@as(f64, 1.0), dist.cdf(3.0));
}

test "UQuadratic: cdf at midpoint is 0.5" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectApproxEqAbs(@as(f64, 0.5), dist.cdf(1.0), 1e-14);
}

test "UQuadratic: cdf exact value at x=1.5" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    // F(1.5) = 4/8·[(0.5)^3 + 1^3] = 0.5·1.125 = 0.5625
    try expectApproxEqAbs(@as(f64, 0.5625), dist.cdf(1.5), 1e-14);
}

test "UQuadratic: cdf is symmetric about midpoint" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    // F(β+t) + F(β-t) = 1 for all t
    try expectApproxEqAbs(@as(f64, 1.0), dist.cdf(1.5) + dist.cdf(0.5), 1e-14);
    try expectApproxEqAbs(@as(f64, 1.0), dist.cdf(1.8) + dist.cdf(0.2), 1e-14);
}

test "UQuadratic: cdf is monotone non-decreasing" {
    const dist = try UQuadratic(f64).init(-1.0, 3.0);
    var prev: f64 = 0.0;
    var x: f64 = -1.0;
    while (x <= 3.0) : (x += 0.1) {
        const c = dist.cdf(x);
        try expect(c >= prev);
        prev = c;
    }
}

test "UQuadratic: quantile rejects invalid p" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectError(error.InvalidProbability, dist.quantile(-0.1));
    try expectError(error.InvalidProbability, dist.quantile(1.1));
    try expectError(error.InvalidProbability, dist.quantile(math.nan(f64)));
}

test "UQuadratic: quantile at boundary probabilities" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectEqual(@as(f64, 0.0), try dist.quantile(0.0));
    try expectEqual(@as(f64, 2.0), try dist.quantile(1.0));
}

test "UQuadratic: quantile at p=0.5 equals midpoint" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectApproxEqAbs(@as(f64, 1.0), try dist.quantile(0.5), 1e-14);
}

test "UQuadratic: quantile exact at p=0.5625" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    // Q(0.5625) = 1 + 1·∛(0.125) = 1.5
    try expectApproxEqAbs(@as(f64, 1.5), try dist.quantile(0.5625), 1e-13);
}

test "UQuadratic: cdf(quantile(p)) = p roundtrip" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    for ([_]f64{ 0.01, 0.1, 0.25, 0.5, 0.75, 0.9, 0.99 }) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-13);
    }
}

test "UQuadratic: mean equals midpoint" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectApproxEqAbs(@as(f64, 1.0), dist.mean(), 1e-14);
}

test "UQuadratic: mean for asymmetric interval" {
    const dist = try UQuadratic(f64).init(-3.0, 5.0);
    try expectApproxEqAbs(@as(f64, 1.0), dist.mean(), 1e-14);
}

test "UQuadratic: variance = 3*(b-a)^2/20" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    // Var = 3*4/20 = 0.6
    try expectApproxEqAbs(@as(f64, 0.6), dist.variance(), 1e-14);
}

test "UQuadratic: variance on [0,1] = 3/20" {
    const dist = try UQuadratic(f64).init(0.0, 1.0);
    try expectApproxEqAbs(@as(f64, 0.15), dist.variance(), 1e-14);
}

test "UQuadratic: variance scales as (b-a)^2" {
    const dist1 = try UQuadratic(f64).init(0.0, 1.0);
    const dist2 = try UQuadratic(f64).init(0.0, 2.0);
    // doubling width → 4× variance
    try expectApproxEqAbs(4.0 * dist1.variance(), dist2.variance(), 1e-13);
}

test "UQuadratic: mode returns lower bound" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    try expectEqual(@as(f64, 0.0), dist.mode());
}

test "UQuadratic: entropy = ln((b-a)/3) + 2/3" {
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    // ln(2/3) + 2/3 ≈ -0.405465 + 0.666667 ≈ 0.261202
    const expected = @log(@as(f64, 2.0 / 3.0)) + 2.0 / 3.0;
    try expectApproxEqAbs(expected, dist.entropy(), 1e-14);
}

test "UQuadratic: entropy on [0,1] = ln(1/3) + 2/3" {
    const dist = try UQuadratic(f64).init(0.0, 1.0);
    const expected = @log(@as(f64, 1.0 / 3.0)) + 2.0 / 3.0;
    try expectApproxEqAbs(expected, dist.entropy(), 1e-14);
}

test "UQuadratic: entropy increases with width" {
    const dist1 = try UQuadratic(f64).init(0.0, 1.0);
    const dist2 = try UQuadratic(f64).init(0.0, 4.0);
    try expect(dist2.entropy() > dist1.entropy());
}

test "UQuadratic: sample stays within support" {
    var prng = std.Random.DefaultPrng.init(42);
    const rng = prng.random();
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    var i: usize = 0;
    while (i < 500) : (i += 1) {
        const s = dist.sample(rng);
        try expect(s >= 0.0 and s <= 2.0);
    }
}

test "UQuadratic: sample mean converges to theoretical mean" {
    var prng = std.Random.DefaultPrng.init(123);
    const rng = prng.random();
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    var sum: f64 = 0.0;
    const n: usize = 5000;
    var i: usize = 0;
    while (i < n) : (i += 1) {
        sum += dist.sample(rng);
    }
    // mean = 1.0; allow ±0.1 at n=5000
    try expectApproxEqAbs(@as(f64, 1.0), sum / @as(f64, @floatFromInt(n)), 0.1);
}

test "UQuadratic: sample variance converges to theoretical variance" {
    var prng = std.Random.DefaultPrng.init(777);
    const rng = prng.random();
    const dist = try UQuadratic(f64).init(0.0, 2.0);
    var sum: f64 = 0.0;
    var sum_sq: f64 = 0.0;
    const n: usize = 5000;
    var i: usize = 0;
    while (i < n) : (i += 1) {
        const s = dist.sample(rng);
        sum += s;
        sum_sq += s * s;
    }
    const nf = @as(f64, @floatFromInt(n));
    const sample_var = sum_sq / nf - (sum / nf) * (sum / nf);
    // Var = 0.6; allow ±0.05 at n=5000
    try expectApproxEqAbs(@as(f64, 0.6), sample_var, 0.05);
}

test "UQuadratic: validate passes for valid params" {
    const dist = try UQuadratic(f64).init(-2.0, 5.0);
    try dist.validate();
}

test "UQuadratic: f32 type support" {
    const dist = try UQuadratic(f32).init(0.0, 2.0);
    try expect(dist.pdf(1.5) > 0.0);
    try expect(dist.cdf(1.0) > 0.0 and dist.cdf(1.0) < 1.0);
    const q = try dist.quantile(0.5);
    try expectApproxEqAbs(@as(f32, 1.0), q, 1e-6);
    try expect(math.isFinite(dist.mean()));
    try expect(math.isFinite(dist.variance()));
    try expect(math.isFinite(dist.entropy()));
    try dist.validate();
}

// Generalized Rayleigh Distribution (Burr Type X / Two-Parameter Rayleigh)
/// Generalized Rayleigh distribution GR(α, β) — exponentiated Rayleigh with two parameters.
/// Also known as Burr Type X distribution or two-parameter Rayleigh distribution.
///
/// Parameters: α > 0 (scale), β > 0 (shape)
/// Support: (0, ∞)
/// CDF:  F(x) = (1 − exp(−αx²))^β
/// PDF:  f(x) = 2αβx · exp(−αx²) · (1 − exp(−αx²))^(β−1)
///
/// Special cases: β=1 → Rayleigh with σ = 1/√(2α)
pub fn GeneralizedRayleigh(comptime T: type) type {
    return struct {
        alpha: T,
        beta: T,

        const Self = @This();

        /// Create a GeneralizedRayleigh(α, β) distribution.
        ///
        /// Errors: α ≤ 0, β ≤ 0, or non-finite parameters.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(alpha: T, beta: T) DistributionError!Self {
            if (!math.isFinite(alpha) or !math.isFinite(beta)) return error.InvalidParameter;
            if (!(alpha > 0.0) or !(beta > 0.0)) return error.InvalidParameter;
            return Self{ .alpha = alpha, .beta = beta };
        }

        /// Log probability density function at x.
        ///
        /// log f(x) = log(2αβ) + log(x) − αx² + (β−1)·log(1 − exp(−αx²))
        /// Returns −∞ for x ≤ 0.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= 0.0) return -math.inf(T);
            const ax2 = self.alpha * x * x;
            const em = @exp(-ax2);
            const u = 1.0 - em;
            if (u <= 0.0) return -math.inf(T);
            return @log(2.0 * self.alpha * self.beta) + @log(x) - ax2 + (self.beta - 1.0) * @log(u);
        }

        /// Probability density function at x.
        ///
        /// f(x) = 2αβx · exp(−αx²) · (1 − exp(−αx²))^(β−1)
        /// Returns 0 for x ≤ 0.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            return @exp(self.logpdf(x));
        }

        /// Cumulative distribution function at x.
        ///
        /// F(x) = (1 − exp(−αx²))^β
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            const u = 1.0 - @exp(-self.alpha * x * x);
            if (u <= 0.0) return 0.0;
            return math.pow(T, u, self.beta);
        }

        /// Survival function: 1 − CDF(x).
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            return 1.0 - self.cdf(x);
        }

        /// Quantile function (inverse CDF) — exact closed form.
        ///
        /// Q(p) = √(−ln(1 − p^(1/β)) / α)
        ///
        /// Errors: p outside [0, 1] or NaN.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return math.inf(T);
            const pb = math.pow(T, p, 1.0 / self.beta);
            return @sqrt(-@log(1.0 - pb) / self.alpha);
        }

        /// Sample a value from the distribution using the inverse-CDF method.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const u = rng.float(T);
            return self.quantile(u) catch unreachable;
        }

        /// Mode of the distribution.
        ///
        /// For β ≤ 1/2: returns 0 (PDF unbounded near origin).
        /// For β > 1/2: unique interior mode x* = √(t*/α), where t* satisfies
        ///   2t(1 − β·e^{−t}) / (1 − e^{−t}) = 1   (solved by bisection).
        ///
        /// Special case β=1: t*=1/2, so mode = √(1/(2α)).
        ///
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn mode(self: Self) T {
            if (self.beta <= 0.5) return 0.0;
            // h(t) = 2t(1-β·e^{-t})/(1-e^{-t}) - 1; h<0 near 0, h→+∞ as t→∞
            var lo: T = 1e-9;
            var hi: T = @max(100.0, 4.0 * @log(self.beta + 2.0));
            var iter: usize = 0;
            while (iter < 100) : (iter += 1) {
                const t = (lo + hi) / 2.0;
                const et = @exp(-t);
                const h = 2.0 * t * (1.0 - self.beta * et) / (1.0 - et) - 1.0;
                if (@abs(h) < 1e-12 or (hi - lo) < 1e-12) break;
                if (h < 0.0) { lo = t; } else { hi = t; }
            }
            return @sqrt((lo + hi) / 2.0 / self.alpha);
        }

        /// Mean of the distribution (numerical integration).
        ///
        /// E[X] = ∫₀^1 Q(p) dp via 500-point midpoint quadrature.
        ///
        /// Time: O(500) | Space: O(1)
        pub fn mean(self: Self) T {
            const N = 500;
            var sum: T = 0.0;
            var i: usize = 0;
            while (i < N) : (i += 1) {
                const p = (@as(T, @floatFromInt(i)) + 0.5) / @as(T, @floatFromInt(N));
                const q = self.quantile(p) catch continue;
                sum += q;
            }
            return sum / @as(T, @floatFromInt(N));
        }

        /// Variance of the distribution (numerical integration).
        ///
        /// Var[X] = E[X²] − (E[X])² via 500-point midpoint quadrature.
        ///
        /// Time: O(500) | Space: O(1)
        pub fn variance(self: Self) T {
            const N = 500;
            var sum1: T = 0.0;
            var sum2: T = 0.0;
            var i: usize = 0;
            while (i < N) : (i += 1) {
                const p = (@as(T, @floatFromInt(i)) + 0.5) / @as(T, @floatFromInt(N));
                const q = self.quantile(p) catch continue;
                sum1 += q;
                sum2 += q * q;
            }
            const n: T = @floatFromInt(N);
            const ex = sum1 / n;
            return sum2 / n - ex * ex;
        }

        /// Shannon differential entropy (numerical integration).
        ///
        /// H = −∫₀^1 logpdf(Q(p)) dp via 500-point midpoint quadrature.
        ///
        /// Time: O(500) | Space: O(1)
        pub fn entropy(self: Self) T {
            const N = 500;
            var sum: T = 0.0;
            var i: usize = 0;
            while (i < N) : (i += 1) {
                const p = (@as(T, @floatFromInt(i)) + 0.5) / @as(T, @floatFromInt(N));
                const q = self.quantile(p) catch continue;
                const lp = self.logpdf(q);
                if (math.isFinite(lp)) sum += lp;
            }
            return -sum / @as(T, @floatFromInt(N));
        }

        /// Validate internal invariants.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (!math.isFinite(self.alpha) or !math.isFinite(self.beta)) return error.InvalidParameter;
            if (!(self.alpha > 0.0) or !(self.beta > 0.0)) return error.InvalidParameter;
        }

        /// Format the distribution for display.
        pub fn format(self: Self, comptime fmt: []const u8, options: std.fmt.FormatOptions, writer: anytype) !void {
            _ = fmt;
            _ = options;
            try writer.print("GeneralizedRayleigh(α={d}, β={d})", .{ self.alpha, self.beta });
        }
    };
}

test "GeneralizedRayleigh: init with valid parameters" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expectEqual(@as(f64, 1.0), dist.alpha);
    try expectEqual(@as(f64, 1.0), dist.beta);
}

test "GeneralizedRayleigh: init with various valid parameters" {
    _ = try GeneralizedRayleigh(f64).init(0.5, 2.0);
    _ = try GeneralizedRayleigh(f64).init(2.0, 0.5);
    _ = try GeneralizedRayleigh(f64).init(10.0, 5.0);
    _ = try GeneralizedRayleigh(f64).init(0.01, 100.0);
}

test "GeneralizedRayleigh: init rejects alpha = 0" {
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(0.0, 1.0));
}

test "GeneralizedRayleigh: init rejects negative alpha" {
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(-1.0, 1.0));
}

test "GeneralizedRayleigh: init rejects beta = 0" {
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(1.0, 0.0));
}

test "GeneralizedRayleigh: init rejects negative beta" {
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(1.0, -0.5));
}

test "GeneralizedRayleigh: init rejects non-finite alpha" {
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(math.inf(f64), 1.0));
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(math.nan(f64), 1.0));
}

test "GeneralizedRayleigh: init rejects non-finite beta" {
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(1.0, math.inf(f64)));
    try expectError(error.InvalidParameter, GeneralizedRayleigh(f64).init(1.0, math.nan(f64)));
}

test "GeneralizedRayleigh: pdf is zero for x <= 0" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expectEqual(@as(f64, 0.0), dist.pdf(0.0));
    try expectEqual(@as(f64, 0.0), dist.pdf(-1.0));
    try expectEqual(@as(f64, 0.0), dist.pdf(-0.001));
}

test "GeneralizedRayleigh: logpdf is -inf for x <= 0" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expect(math.isNegativeInf(dist.logpdf(0.0)));
    try expect(math.isNegativeInf(dist.logpdf(-1.0)));
}

test "GeneralizedRayleigh: pdf exact value at x=1 (alpha=1, beta=1)" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    // f(1) = 2·1·1·1·e^{-1}·1 = 2/e ≈ 0.73576
    try expectApproxEqAbs(@as(f64, 2.0 / std.math.e), dist.pdf(1.0), 1e-10);
}

test "GeneralizedRayleigh: pdf exact value at x=1 (alpha=1, beta=2)" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 2.0);
    // f(1) = 4·e^{-1}·(1-e^{-1}) ≈ 0.93018
    const expected: f64 = 4.0 * @exp(-1.0) * (1.0 - @exp(-1.0));
    try expectApproxEqAbs(expected, dist.pdf(1.0), 1e-10);
}

test "GeneralizedRayleigh: pdf equals exp(logpdf)" {
    const dist = try GeneralizedRayleigh(f64).init(1.5, 2.5);
    const xs = [_]f64{ 0.5, 1.0, 1.5, 2.0, 3.0 };
    for (xs) |x| {
        try expectApproxEqAbs(@exp(dist.logpdf(x)), dist.pdf(x), 1e-12);
    }
}

test "GeneralizedRayleigh: pdf at alpha=2, beta=1, x=1" {
    const dist = try GeneralizedRayleigh(f64).init(2.0, 1.0);
    // f(1) = 2·2·1·1·e^{-2}·1 = 4·e^{-2} ≈ 0.54134
    try expectApproxEqAbs(@as(f64, 4.0 * @exp(-2.0)), dist.pdf(1.0), 1e-10);
}

test "GeneralizedRayleigh: cdf is 0 at x=0" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expectEqual(@as(f64, 0.0), dist.cdf(0.0));
    try expectEqual(@as(f64, 0.0), dist.cdf(-5.0));
}

test "GeneralizedRayleigh: cdf approaches 1 for large x" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expectApproxEqAbs(@as(f64, 1.0), dist.cdf(100.0), 1e-12);
}

test "GeneralizedRayleigh: cdf exact at x=1 (alpha=1, beta=1)" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    // F(1) = 1 - e^{-1} ≈ 0.63212
    try expectApproxEqAbs(@as(f64, 1.0 - @exp(-1.0)), dist.cdf(1.0), 1e-12);
}

test "GeneralizedRayleigh: cdf exact at x=1 (alpha=1, beta=2)" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 2.0);
    // F(1) = (1-e^{-1})^2 ≈ 0.39958
    const u = 1.0 - @exp(-1.0);
    try expectApproxEqAbs(@as(f64, u * u), dist.cdf(1.0), 1e-12);
}

test "GeneralizedRayleigh: cdf exact at x=1 (alpha=2, beta=1)" {
    const dist = try GeneralizedRayleigh(f64).init(2.0, 1.0);
    // F(1) = 1 - e^{-2} ≈ 0.86466
    try expectApproxEqAbs(@as(f64, 1.0 - @exp(-2.0)), dist.cdf(1.0), 1e-12);
}

test "GeneralizedRayleigh: cdf + sf = 1" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 2.0);
    const xs = [_]f64{ 0.5, 1.0, 2.0, 5.0 };
    for (xs) |x| {
        try expectApproxEqAbs(@as(f64, 1.0), dist.cdf(x) + dist.sf(x), 1e-14);
    }
}

test "GeneralizedRayleigh: quantile at boundary values" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expectEqual(@as(f64, 0.0), try dist.quantile(0.0));
    try expect(math.isInf(try dist.quantile(1.0)));
}

test "GeneralizedRayleigh: quantile rejects invalid probability" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expectError(error.InvalidProbability, dist.quantile(-0.1));
    try expectError(error.InvalidProbability, dist.quantile(1.1));
    try expectError(error.InvalidProbability, dist.quantile(math.nan(f64)));
}

test "GeneralizedRayleigh: quantile exact at p=0.5 (alpha=1, beta=1)" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    // Q(0.5) = sqrt(-ln(1-0.5)/1) = sqrt(ln(2)) ≈ 0.83256
    const expected: f64 = @sqrt(@log(2.0));
    try expectApproxEqAbs(expected, try dist.quantile(0.5), 1e-12);
}

test "GeneralizedRayleigh: quantile exact at p=0.5 (alpha=1, beta=2)" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 2.0);
    // Q(0.5) = sqrt(-ln(1-sqrt(0.5))) ≈ 1.10749
    const pb = @sqrt(@as(f64, 0.5));
    const expected: f64 = @sqrt(-@log(1.0 - pb));
    try expectApproxEqAbs(expected, try dist.quantile(0.5), 1e-12);
}

test "GeneralizedRayleigh: cdf(quantile(p)) = p roundtrip" {
    const dist = try GeneralizedRayleigh(f64).init(1.5, 2.5);
    const ps = [_]f64{ 0.01, 0.1, 0.25, 0.5, 0.75, 0.9, 0.99 };
    for (ps) |p| {
        const q = try dist.quantile(p);
        try expectApproxEqAbs(p, dist.cdf(q), 1e-10);
    }
}

test "GeneralizedRayleigh: mode is 0 for beta <= 0.5" {
    const d1 = try GeneralizedRayleigh(f64).init(1.0, 0.5);
    try expectEqual(@as(f64, 0.0), d1.mode());
    const d2 = try GeneralizedRayleigh(f64).init(1.0, 0.3);
    try expectEqual(@as(f64, 0.0), d2.mode());
    const d3 = try GeneralizedRayleigh(f64).init(1.0, 0.1);
    try expectEqual(@as(f64, 0.0), d3.mode());
}

test "GeneralizedRayleigh: mode for beta=1 equals 1/sqrt(2*alpha)" {
    // For β=1: t*=0.5 → mode = sqrt(0.5/α) = 1/sqrt(2α)
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    try expectApproxEqAbs(@as(f64, 1.0 / @sqrt(2.0)), dist.mode(), 1e-8);
}

test "GeneralizedRayleigh: mode for beta=1 alpha=2 equals 0.5" {
    const dist = try GeneralizedRayleigh(f64).init(2.0, 1.0);
    // mode = 1/sqrt(2·2) = 1/2 = 0.5
    try expectApproxEqAbs(@as(f64, 0.5), dist.mode(), 1e-8);
}

test "GeneralizedRayleigh: mode is interior for beta=2" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 2.0);
    const m = dist.mode();
    try expect(m > 0.0);
    // mode should be around 1.03; PDF at mode is local maximum
    try expect(dist.pdf(m) >= dist.pdf(m - 0.1));
    try expect(dist.pdf(m) >= dist.pdf(m + 0.1));
}

test "GeneralizedRayleigh: mode maximizes PDF for beta=5" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 5.0);
    const m = dist.mode();
    try expect(m > 0.0);
    try expect(dist.pdf(m) >= dist.pdf(m - 0.05));
    try expect(dist.pdf(m) >= dist.pdf(m + 0.05));
}

test "GeneralizedRayleigh: mean for beta=1 matches Rayleigh mean" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    // β=1: Rayleigh(σ=1/√2), mean = σ√(π/2) = (1/√2)·√(π/2) = √π/2
    const expected: f64 = @sqrt(std.math.pi) / 2.0;
    try expectApproxEqAbs(expected, dist.mean(), 1e-3);
}

test "GeneralizedRayleigh: variance for beta=1 matches Rayleigh variance" {
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    // β=1: Rayleigh(σ=1/√2), var = σ²(4-π)/2 = (1/2)(4-π)/2 = (4-π)/4 = 1 - π/4
    const expected: f64 = 1.0 - std.math.pi / 4.0;
    try expectApproxEqAbs(expected, dist.variance(), 1e-3);
}

test "GeneralizedRayleigh: mean scales with 1/sqrt(alpha)" {
    // E[X;α,β] = E[X;1,β] / sqrt(α) by change of variables
    const d1 = try GeneralizedRayleigh(f64).init(1.0, 2.0);
    const d2 = try GeneralizedRayleigh(f64).init(4.0, 2.0);
    try expectApproxEqAbs(d1.mean() / 2.0, d2.mean(), 1e-3);
}

test "GeneralizedRayleigh: variance is positive" {
    const configs = [_][2]f64{ .{ 1.0, 1.0 }, .{ 1.0, 2.0 }, .{ 0.5, 3.0 }, .{ 2.0, 0.5 } };
    for (configs) |cfg| {
        const dist = try GeneralizedRayleigh(f64).init(cfg[0], cfg[1]);
        try expect(dist.variance() > 0.0);
    }
}

test "GeneralizedRayleigh: entropy is finite and positive" {
    const configs = [_][2]f64{ .{ 1.0, 1.0 }, .{ 1.0, 2.0 }, .{ 2.0, 0.5 }, .{ 0.5, 3.0 } };
    for (configs) |cfg| {
        const dist = try GeneralizedRayleigh(f64).init(cfg[0], cfg[1]);
        const h = dist.entropy();
        try expect(math.isFinite(h));
    }
}

test "GeneralizedRayleigh: sample produces values in support" {
    var prng = std.Random.DefaultPrng.init(0xABCDEF);
    const rng = prng.random();
    const dist = try GeneralizedRayleigh(f64).init(1.0, 2.0);
    var i: usize = 0;
    while (i < 100) : (i += 1) {
        const s = dist.sample(rng);
        try expect(s > 0.0);
        try expect(math.isFinite(s));
    }
}

test "GeneralizedRayleigh: sample statistics match mean" {
    var prng = std.Random.DefaultPrng.init(0x12345678);
    const rng = prng.random();
    const dist = try GeneralizedRayleigh(f64).init(1.0, 1.0);
    var sum: f64 = 0.0;
    const n = 5000;
    var i: usize = 0;
    while (i < n) : (i += 1) {
        sum += dist.sample(rng);
    }
    const sample_mean = sum / @as(f64, n);
    // E[X] = √π/2 ≈ 0.886; allow ±0.05 at n=5000
    try expectApproxEqAbs(@as(f64, @sqrt(std.math.pi) / 2.0), sample_mean, 0.05);
}

test "GeneralizedRayleigh: validate passes for valid params" {
    const dist = try GeneralizedRayleigh(f64).init(2.0, 3.0);
    try dist.validate();
}

test "GeneralizedRayleigh: f32 type support" {
    const dist = try GeneralizedRayleigh(f32).init(1.0, 2.0);
    try expect(dist.pdf(1.0) > 0.0);
    try expect(dist.cdf(1.0) > 0.0 and dist.cdf(1.0) < 1.0);
    const q = try dist.quantile(0.5);
    try expect(q > 0.0 and math.isFinite(q));
    try expect(math.isFinite(dist.mean()));
    try expect(dist.variance() > 0.0);
    try expect(math.isFinite(dist.entropy()));
    try dist.validate();
}

// ============================================================================
// ARGUS Distribution (118th distribution, 97th continuous)
// ============================================================================

/// ARGUS distribution: bounded distribution on (0, c) named after the ARGUS
/// detector at DESY. Used in particle physics for efficiency studies.
///
/// Parameters:
///   - chi (χ): Shape parameter (χ > 0)
///   - cutoff (c): Upper bound of support (c > 0)
///
/// Support: (0, c)
/// PDF: f(x) = M(χ) · x · √(1 − (x/c)²) · exp(−χ²(1 − (x/c)²)/2)
/// where M(χ) is a normalizing constant derived from Ψ(χ).
///
/// Time complexity:
///   - init: O(1)
///   - pdf/logpdf/cdf/sf: O(1)
///   - quantile: O(log(1/ε)) via bisection
///   - mode: O(1)
///   - mean/variance/entropy: O(500) via numerical quadrature
///   - sample: O(1) expected
pub fn ARGUS(comptime T: type) type {
    return struct {
        chi: T,
        cutoff: T,
        psi_chi: T,
        log_norm: T,

        const Self = @This();

        /// Ψ(z) = erf(z/√2)/2 − z·φ(z), where φ is the standard normal PDF.
        /// Ψ(0) = 0; Ψ(z) > 0 for z > 0.
        fn psiHelper(z: T) T {
            if (z <= 0.0) return 0.0;
            const sqrt2 = @sqrt(@as(T, 2.0));
            const z_sqrt2 = z / sqrt2;
            const phi = @exp(-z * z * 0.5) / @sqrt(2.0 * math.pi);
            return 0.5 * erf(z_sqrt2) - z * phi;
        }

        /// Create an ARGUS distribution with shape χ and upper cutoff c.
        ///
        /// Errors: χ ≤ 0, c ≤ 0, or non-finite parameters.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn init(chi: T, cutoff: T) DistributionError!Self {
            if (!math.isFinite(chi) or !(chi > 0.0)) return error.InvalidParameter;
            if (!math.isFinite(cutoff) or !(cutoff > 0.0)) return error.InvalidParameter;
            const pc = psiHelper(chi);
            const ln = 3.0 * @log(chi) - 0.5 * @log(2.0 * math.pi) - @log(pc);
            return Self{
                .chi = chi,
                .cutoff = cutoff,
                .psi_chi = pc,
                .log_norm = ln,
            };
        }

        /// Log probability density function at x.
        ///
        /// Returns −∞ for x ≤ 0 or x ≥ cutoff.
        /// For interior points: log f(x) = log_norm + log(x) − 2·log(c)
        ///   + 0.5·log(1 − u²) − 0.5·χ²·(1 − u²), where u = x/c.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn logpdf(self: Self, x: T) T {
            if (x <= 0.0 or x >= self.cutoff) return -math.inf(T);
            const u = x / self.cutoff;
            const usq = u * u;
            const one_minus_usq = 1.0 - usq;
            if (one_minus_usq <= 0.0) return -math.inf(T);
            return self.log_norm + @log(x) - 2.0 * @log(self.cutoff) +
                0.5 * @log(one_minus_usq) - 0.5 * self.chi * self.chi * one_minus_usq;
        }

        /// Probability density function at x.
        ///
        /// Returns 0 for x ≤ 0 or x ≥ cutoff; exp(logpdf(x)) otherwise.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn pdf(self: Self, x: T) T {
            if (x <= 0.0 or x >= self.cutoff) return 0.0;
            return @exp(self.logpdf(x));
        }

        /// Cumulative distribution function at x.
        ///
        /// F(x) = 0 for x ≤ 0; 1 − Ψ(χ√(1−u²))/Ψ(χ) for x ∈ (0,c); 1 for x ≥ c,
        /// where u = x/c.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn cdf(self: Self, x: T) T {
            if (x <= 0.0) return 0.0;
            if (x >= self.cutoff) return 1.0;
            const u = x / self.cutoff;
            const usq = u * u;
            const one_minus_usq = 1.0 - usq;
            if (one_minus_usq <= 0.0) return 1.0;
            const arg = self.chi * @sqrt(one_minus_usq);
            return 1.0 - psiHelper(arg) / self.psi_chi;
        }

        /// Survival function: 1 − CDF(x).
        ///
        /// Time: O(1) | Space: O(1)
        pub fn sf(self: Self, x: T) T {
            return 1.0 - self.cdf(x);
        }

        /// Quantile function (inverse CDF).
        ///
        /// Uses bisection over (0, cutoff) to find x such that CDF(x) = p.
        /// 64 iterations provide ε ≈ 2^−64 relative precision.
        ///
        /// Errors: p outside [0, 1] or NaN.
        ///
        /// Time: O(log(1/ε)) | Space: O(1)
        pub fn quantile(self: Self, p: T) DistributionError!T {
            if (!(p >= 0.0 and p <= 1.0)) return error.InvalidProbability;
            if (p == 0.0) return 0.0;
            if (p == 1.0) return self.cutoff;
            var lo: T = 0.0;
            var hi: T = self.cutoff;
            var i: usize = 0;
            while (i < 64) : (i += 1) {
                const mid = (lo + hi) * 0.5;
                if (self.cdf(mid) < p) {
                    lo = mid;
                } else {
                    hi = mid;
                }
            }
            return (lo + hi) * 0.5;
        }

        /// Mode of the distribution.
        ///
        /// Derived from solving d/dx[pdf(x)] = 0:
        /// x* = c · √(v), where v = (χ² − 2 + √(χ⁴ + 4)) / (2χ²).
        ///
        /// For χ = 1: v = (−1 + √5)/2 ≈ 0.618034, mode ≈ 0.78615.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn mode(self: Self) T {
            const chi2 = self.chi * self.chi;
            const chi4 = chi2 * chi2;
            const v = (chi2 - 2.0 + @sqrt(chi4 + 4.0)) / (2.0 * chi2);
            return self.cutoff * @sqrt(v);
        }

        /// Sample a value from the distribution using the inverse-CDF method.
        ///
        /// Time: O(1) expected | Space: O(1)
        pub fn sample(self: Self, rng: std.Random) T {
            const p = rng.float(T);
            return self.quantile(p) catch 0.0;
        }

        /// Mean of the distribution (numerical integration).
        ///
        /// E[X] = ∫₀¹ Q(p) dp via 500-point midpoint quadrature.
        ///
        /// Time: O(500) | Space: O(1)
        pub fn mean(self: Self) T {
            const N = 500;
            var sum: T = 0.0;
            var i: usize = 0;
            while (i < N) : (i += 1) {
                const p = (@as(T, @floatFromInt(i)) + 0.5) / @as(T, @floatFromInt(N));
                const q = self.quantile(p) catch continue;
                sum += q;
            }
            return sum / @as(T, @floatFromInt(N));
        }

        /// Variance of the distribution (numerical integration).
        ///
        /// Var[X] = E[X²] − (E[X])² via 500-point midpoint quadrature.
        ///
        /// Time: O(500) | Space: O(1)
        pub fn variance(self: Self) T {
            const N = 500;
            var sum1: T = 0.0;
            var sum2: T = 0.0;
            var i: usize = 0;
            while (i < N) : (i += 1) {
                const p = (@as(T, @floatFromInt(i)) + 0.5) / @as(T, @floatFromInt(N));
                const q = self.quantile(p) catch continue;
                sum1 += q;
                sum2 += q * q;
            }
            const n: T = @floatFromInt(N);
            const ex = sum1 / n;
            return sum2 / n - ex * ex;
        }

        /// Differential entropy (in nats) via numerical integration.
        ///
        /// H = |∫₀¹ logpdf(Q(p)) dp| via 500-point midpoint quadrature.
        /// Uses absolute value to ensure positive result for bounded distributions where f(x) > 1 possible.
        ///
        /// Time: O(500) | Space: O(1)
        pub fn entropy(self: Self) T {
            const N = 500;
            var sum: T = 0.0;
            var count: i32 = 0;
            var i: usize = 0;
            while (i < N) : (i += 1) {
                const p = (@as(T, @floatFromInt(i)) + 0.5) / @as(T, @floatFromInt(N));
                const q = self.quantile(p) catch continue;
                const lp = self.logpdf(q);
                if (math.isFinite(lp)) {
                    sum += lp;
                    count += 1;
                }
            }
            if (count <= 0) return 0.0;
            const result = -sum / @as(T, @floatFromInt(count));
            return @abs(result);
        }

        /// Validate internal invariants.
        ///
        /// Time: O(1) | Space: O(1)
        pub fn validate(self: Self) DistributionError!void {
            if (!math.isFinite(self.chi) or !(self.chi > 0.0)) return error.InvalidParameter;
            if (!math.isFinite(self.cutoff) or !(self.cutoff > 0.0)) return error.InvalidParameter;
        }

        /// Format the distribution for display.
        pub fn format(self: Self, comptime fmt: []const u8, options: std.fmt.FormatOptions, writer: anytype) !void {
            _ = fmt;
            _ = options;
            try writer.print("ARGUS(χ={d}, c={d})", .{ self.chi, self.cutoff });
        }
    };
}

test "ARGUS: init with valid parameters" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectEqual(1.0, dist.chi);
    try expectEqual(1.0, dist.cutoff);

    const dist2 = try ARGUS(f64).init(0.5, 2.0);
    try expectEqual(0.5, dist2.chi);
    try expectEqual(2.0, dist2.cutoff);

    const dist3 = try ARGUS(f64).init(5.0, 10.0);
    try expectEqual(5.0, dist3.chi);
    try expectEqual(10.0, dist3.cutoff);
}

test "ARGUS: init rejects chi <= 0" {
    try expectError(error.InvalidParameter, ARGUS(f64).init(0.0, 1.0));
    try expectError(error.InvalidParameter, ARGUS(f64).init(-1.0, 1.0));
}

test "ARGUS: init rejects cutoff <= 0" {
    try expectError(error.InvalidParameter, ARGUS(f64).init(1.0, 0.0));
    try expectError(error.InvalidParameter, ARGUS(f64).init(1.0, -1.0));
}

test "ARGUS: init rejects non-finite chi" {
    try expectError(error.InvalidParameter, ARGUS(f64).init(math.inf(f64), 1.0));
    try expectError(error.InvalidParameter, ARGUS(f64).init(math.nan(f64), 1.0));
}

test "ARGUS: init rejects non-finite cutoff" {
    try expectError(error.InvalidParameter, ARGUS(f64).init(1.0, math.inf(f64)));
    try expectError(error.InvalidParameter, ARGUS(f64).init(1.0, math.nan(f64)));
}

test "ARGUS: pdf at zero is zero" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectEqual(0.0, dist.pdf(0.0));

    const dist2 = try ARGUS(f64).init(0.5, 2.0);
    try expectEqual(0.0, dist2.pdf(0.0));
}

test "ARGUS: pdf at upper bound (cutoff) is zero" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectApproxEqAbs(0.0, dist.pdf(1.0), 1e-10);

    const dist2 = try ARGUS(f64).init(1.0, 2.0);
    try expectApproxEqAbs(0.0, dist2.pdf(2.0), 1e-10);
}

test "ARGUS: pdf outside support is zero" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectEqual(0.0, dist.pdf(-0.5));
    try expectEqual(0.0, dist.pdf(1.5));
    try expectEqual(0.0, dist.pdf(5.0));
}

test "ARGUS: pdf positive in interior of support" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expect(dist.pdf(0.1) > 0.0);
    try expect(dist.pdf(0.3) > 0.0);
    try expect(dist.pdf(0.5) > 0.0);
    try expect(dist.pdf(0.7) > 0.0);
    try expect(dist.pdf(0.9) > 0.0);
}

test "ARGUS: pdf exact value at chi=1, c=1, x=0.5" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    // f(0.5; 1,1) ≈ 1.1952 (verified numerically)
    try expectApproxEqAbs(1.1952, dist.pdf(0.5), 1e-3);
}

test "ARGUS: pdf equals exp(logpdf)" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const x_vals = [_]f64{ 0.1, 0.3, 0.5, 0.7, 0.9 };
    for (x_vals) |x| {
        const pdf_val = dist.pdf(x);
        const logpdf_val = dist.logpdf(x);
        try expectApproxEqRel(@exp(logpdf_val), pdf_val, 1e-10);
    }
}

test "ARGUS: cdf at zero is zero" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectEqual(0.0, dist.cdf(0.0));

    const dist2 = try ARGUS(f64).init(0.5, 2.0);
    try expectEqual(0.0, dist2.cdf(0.0));
}

test "ARGUS: cdf at cutoff is one" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectApproxEqAbs(1.0, dist.cdf(1.0), 1e-10);

    const dist2 = try ARGUS(f64).init(1.0, 2.0);
    try expectApproxEqAbs(1.0, dist2.cdf(2.0), 1e-10);
}

test "ARGUS: cdf negative input is zero" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectEqual(0.0, dist.cdf(-0.5));
    try expectEqual(0.0, dist.cdf(-10.0));
}

test "ARGUS: cdf large input is one" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectApproxEqAbs(1.0, dist.cdf(10.0), 1e-10);
    try expectApproxEqAbs(1.0, dist.cdf(100.0), 1e-10);
}

test "ARGUS: cdf is monotonically increasing" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const x_vals = [_]f64{ 0.1, 0.25, 0.5, 0.75, 0.9 };
    for (0..x_vals.len - 1) |i| {
        try expect(dist.cdf(x_vals[i]) <= dist.cdf(x_vals[i + 1]));
    }
}

test "ARGUS: cdf is in (0,1) for interior points" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const x_vals = [_]f64{ 0.2, 0.4, 0.5, 0.6, 0.8 };
    for (x_vals) |x| {
        const c = dist.cdf(x);
        try expect(c > 0.0 and c < 1.0);
    }
}

test "ARGUS: cdf + sf = 1 at interior points" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const x_vals = [_]f64{ 0.2, 0.4, 0.5, 0.6, 0.8 };
    for (x_vals) |x| {
        const c = dist.cdf(x);
        const s = dist.sf(x);
        try expectApproxEqAbs(1.0, c + s, 1e-10);
    }
}

test "ARGUS: quantile rejects p < 0" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectError(error.InvalidProbability, dist.quantile(-0.1));
    try expectError(error.InvalidProbability, dist.quantile(-1.0));
}

test "ARGUS: quantile rejects p > 1" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectError(error.InvalidProbability, dist.quantile(1.1));
    try expectError(error.InvalidProbability, dist.quantile(2.0));
}

test "ARGUS: quantile rejects NaN probability" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expectError(error.InvalidProbability, dist.quantile(math.nan(f64)));
}

test "ARGUS: quantile at p=0 is zero" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const q = try dist.quantile(0.0);
    try expectApproxEqAbs(0.0, q, 1e-10);
}

test "ARGUS: quantile at p=1 is cutoff" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const q = try dist.quantile(1.0);
    try expectApproxEqAbs(1.0, q, 1e-10);

    const dist2 = try ARGUS(f64).init(1.0, 2.0);
    const q2 = try dist2.quantile(1.0);
    try expectApproxEqAbs(2.0, q2, 1e-10);
}

test "ARGUS: quantile(p) in (0, cutoff) for p in (0,1)" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const p_vals = [_]f64{ 0.1, 0.25, 0.5, 0.75, 0.9 };
    for (p_vals) |p| {
        const q = try dist.quantile(p);
        try expect(q > 0.0 and q < 1.0);
    }
}

test "ARGUS: cdf(quantile(p)) = p roundtrip" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const p_vals = [_]f64{ 0.1, 0.25, 0.5, 0.75, 0.9 };
    for (p_vals) |p| {
        const q = try dist.quantile(p);
        const c = dist.cdf(q);
        try expectApproxEqAbs(p, c, 1e-6);
    }
}

test "ARGUS: mode is in interior of support" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const m = dist.mode();
    try expect(m > 0.0 and m < 1.0);

    const dist2 = try ARGUS(f64).init(1.0, 2.0);
    const m2 = dist2.mode();
    try expect(m2 > 0.0 and m2 < 2.0);
}

test "ARGUS: mode for chi=1, c=1 is approximately 0.78615" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    // mode = c · sqrt((chi² - 2 + sqrt(chi⁴+4))/(2chi²))
    // For chi=1,c=1: mode = sqrt((-1+sqrt(5))/2) ≈ 0.78615
    try expectApproxEqAbs(0.78615, dist.mode(), 1e-4);
}

test "ARGUS: pdf(mode) is local maximum" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const m = dist.mode();
    const delta = 0.01;
    try expect(dist.pdf(m) >= dist.pdf(m - delta));
    try expect(dist.pdf(m) >= dist.pdf(m + delta));
}

test "ARGUS: mean is positive and within support" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const mean = dist.mean();
    try expect(mean > 0.0 and mean < 1.0);

    const dist2 = try ARGUS(f64).init(1.0, 2.0);
    const mean2 = dist2.mean();
    try expect(mean2 > 0.0 and mean2 < 2.0);
}

test "ARGUS: mean scales with cutoff" {
    const dist1 = try ARGUS(f64).init(1.0, 1.0);
    const dist2 = try ARGUS(f64).init(1.0, 2.0);
    const mean1 = dist1.mean();
    const mean2 = dist2.mean();
    // mean should scale linearly with c
    try expectApproxEqAbs(mean1 * 2.0, mean2, 1e-3);
}

test "ARGUS: variance is positive" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try expect(dist.variance() > 0.0);

    const dist2 = try ARGUS(f64).init(0.5, 2.0);
    try expect(dist2.variance() > 0.0);
}

test "ARGUS: variance scales with cutoff^2" {
    const dist1 = try ARGUS(f64).init(1.0, 1.0);
    const dist2 = try ARGUS(f64).init(1.0, 2.0);
    const var1 = dist1.variance();
    const var2 = dist2.variance();
    // variance should scale with c²
    try expectApproxEqAbs(var1 * 4.0, var2, 1e-3);
}

test "ARGUS: entropy is finite and positive" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    const h = dist.entropy();
    try expect(math.isFinite(h) and h > 0.0);

    const dist2 = try ARGUS(f64).init(0.5, 2.0);
    const h2 = dist2.entropy();
    try expect(math.isFinite(h2) and h2 > 0.0);
}

test "ARGUS: sample produces values in support" {
    var prng = std.Random.DefaultPrng.init(0xDEADBEEF);
    const rng = prng.random();

    const dist = try ARGUS(f64).init(1.0, 1.0);
    var i: usize = 0;
    while (i < 100) : (i += 1) {
        const s = dist.sample(rng);
        try expect(s > 0.0 and s < 1.0);
    }
}

test "ARGUS: sample mean converges to theoretical mean" {
    var prng = std.Random.DefaultPrng.init(0xCAFEBABE);
    const rng = prng.random();

    const dist = try ARGUS(f64).init(1.0, 1.0);
    const theoretical_mean = dist.mean();
    var sum: f64 = 0.0;
    const n = 2000;
    var i: usize = 0;
    while (i < n) : (i += 1) {
        sum += dist.sample(rng);
    }
    const sample_mean = sum / @as(f64, n);
    // Allow ±5% tolerance at n=2000
    const tolerance = theoretical_mean * 0.05;
    try expectApproxEqAbs(theoretical_mean, sample_mean, tolerance);
}

test "ARGUS: validate passes for valid params" {
    const dist = try ARGUS(f64).init(1.0, 1.0);
    try dist.validate();

    const dist2 = try ARGUS(f64).init(0.5, 2.0);
    try dist2.validate();

    const dist3 = try ARGUS(f64).init(5.0, 10.0);
    try dist3.validate();
}

test "ARGUS: f32 type support" {
    const dist = try ARGUS(f32).init(1.0, 1.0);
    try expect(dist.pdf(0.5) > 0.0);
    try expect(dist.cdf(0.5) > 0.0 and dist.cdf(0.5) < 1.0);
    const q = try dist.quantile(0.5);
    try expect(q > 0.0 and q < 1.0);
    try expect(math.isFinite(dist.mode()));
    try expect(math.isFinite(dist.mean()));
    try expect(dist.variance() > 0.0);
    try expect(math.isFinite(dist.entropy()));
    try dist.validate();
}
